INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(1, 1, 1, 'Fast Swimmer', 0, 0, NULL, 'Improved Action; Improved action \"swim\" For you, swimming is just an action, not a stunt', '@@ACTION: Improved action \"swim\"\n\n@@SECTION:\nFor you, swimming is just an action, not a stunt. (Other characters are sent Reeling after a \"swim\" stunt.)\n\n@@FLAVOUR:\nYou can travel over swampy terrain faster than those who don\'t have this Gift. (See \"Hiking\", page 148.)', 5, 51, '', 16, 'fast-swimmer', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(2, 1, 2, 'Prehensile Trunk', 0, 0, NULL, 'PASSIVE: You have an extra off-hand, a trunk in the middle of your face.', '@@FLAVOUR:\nYou have the trunk of an elephant.\n\n@@PASSIVE: Extra off-hand\n\n@@FLAVOUR:\nYou have an extra off-hand, a trunk in the middle of your face. You can use this off-hand for one-handed weapons or even a shield.\n\n@@SECTION:\nIf you try to use a \"good hand\" in your off-hand, you suffer a d12 penalty. The Gift of Ambidexterity removes this penalty.\n\n@@SECTION: You also gain a \"Trunk\" Brawling Attack as an off-hand move. Like other natural attacks, your attack dice are Body & Brawling, and the effect is Damage +1, Grapple.', 4, 438, '', 15, 'prehensile-trunk', '2026-03-22 10:39:00', '2026-03-29 08:47:53'),
(3, 1, 3, 'Team Player', 0, 0, NULL, 'Action; Action \"assist\" When you successfully assist someone else in a task, you grant a bonus d12', '@@ACTION: Action \"assist\"\n\n@@SECTION:\nWhen you successfully assist someone else in a task, you grant a bonus d12. (Characters who successfully assist another character, and who do not have this Gift, grant only a d8 bonus. See the Basic Rules chapter for more details.)\n\n@@SECTION: Team Player only provides the benefit when you are the assistant, not when you are the task master.', 5, 60, 'When you successfully assist someone else in a task', 22, 'team-player', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(4, 1, 4, 'Extra Two Hands', 0, 0, NULL, 'Passive; Gain 2 extra off-hands; extra hands may equip only Good hand/Off-hand weapons (no 2-hand); multiple shields allowed but Cover bonuses don’t stack (use best)', '@@FLAVOUR:\nYou have a strange insect-like or arachnoid body.\n\n@@PASSIVE: Two extra off-hands\n\n@@FLAVOUR:\nYou have two extra arms, with two extra off-hands. (You still only have one hand that\'s your good hand.)\n\n@@SECTION: Your Extra Two Hands are smaller than regular hands. You can only equip \"Good hand\" or \"off-hand\" weapons in them. (And not \"2 hand\" weapons.) While you may carry multiple shields, Cover bonuses don\'t stack, you just use the best Cover bonus.\n\n@@FLAVOUR:\nThe gift of Ambidexterity turns all your off-hands into good hands, so yes, it\'s a very good Gift for you to have!\n\n@@SECTION: You might want to consider Quick Draw for the ability to ready up to four weapons at once, too.', 4, 438, '', 15, 'extra-two-hands', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(5, 1, 5, 'Venomous Bite', 0, 0, 2, 'Passive; Exhaust; If your Bite scores a \"Hurt\" result on a target, you may choose to exhaust this Gift. If you do, the target also becomes Sick.', '@@REFRESH: X (Respite)\n\n@@TRIGGER: Bite attack scores a \"Hurt\" Result\n\n@@ACTION:\nIf your Bite scores a \"Hurt\" result on a target, you may choose to exhaust this Gift. If you do, the target also becomes Sick.', 5, 69, 'Bite attack scores a \"Hurt\" Result', 15, 'venomous-bite', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(6, 1, 6, 'Ophidian', 0, 0, NULL, 'Passive; Body: snake (serpentine)\nNo hands—prehensile tail counts as your Good hand.\nMay use Wrestle without hands (coil around a single target).\n+2 Stride, −2 Dash.\nExtra action each turn: Stand Up.', '@@FLAVOUR:\nYou have the body of a snake.\n\n@@PASSIVE: No hands, only Prehensile Tail\n\n@@FLAVOUR:\nYou have only one hand - a prehensile tail. You may use this tail as a good hand.\n\n@@FLAVOUR:\nYou can use the \"Wrestle\" attack without any hands, by coiling your body around a single target.\n\n@@SECTION: +2 Stride, -2 Dash\nAdd two to your Stride, but subtract two from your Dash.\n\n@@ACTION: Extra action \"stand up\"\n\n@@FLAVOUR:\nYou can take an extra action on your turn: the \"stand up\" action. Yes, you can be knocked down, flipped, rolled over, etc, but at least you get up much faster.', 4, 438, '', 15, 'ophidian', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(7, 1, 7, 'True Leader', 0, 0, NULL, 'Action; \"rally with a new boon: grant Focus to target\" You may claim a new boon when rallying: You may grant Focus to an ally', '@@ACTION: Action \"rally with a new boon: grant Focus to target\"\n\n@@SECTION: You may claim a new boon when rallying: You may grant Focus to an ally.\n\n@@SECTION: Your ally must be able to receive Focus. Allies that are Reeling, Confused, Enraged, or Afraid cannot become Focused.\n\n@@SECTION: Notes - You use Will & Leadership dice to Rally. See the Combat Rules chapter for more details.', 5, 82, '', 61, 'true-leader', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(8, 1, 8, 'Wings', 0, 0, NULL, 'Passive; Extra Wings: +1 to Flying Stride You have an extra pair of wings that sprout from your shoulder-blades, instead of the winged arms that most species have', '@@FLAVOUR:\nYou have separate wings that sprout from your back.\n\n@@SECTION: Extra Wings: +1 to Flying Stride\n\n@@FLAVOUR:\nYou have an extra pair of wings that sprout from your shoulder-blades, instead of the winged arms that most species have. These wings give you much more control when you fly.\n\n@@FLAVOUR:\nYou can use two-handed weapons while flying. (Characters without the Gift of Wings can only use one-handed weapons while flying.)\n\n@@SECTION: Add 1 to your Flying Stride', 4, 438, '', 15, 'wings', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(9, 1, 9, 'Counter-Tactics', 0, 0, NULL, 'Passive; May include your Tactics dice in your defense against attacks that include Tactics dice.', '@@FLAVOUR: Attacker using Tactics? Defend using Tactics, Too\n\n@@TRIGGER: When someone includes Tactics dice in an Attack made against you\n\n@@REACTION:\nYou may include your own Tactics dice with your defense against that attack.\n\n@@NOTE:\nNormally, Tactics dice are only used for Attacks, and only against flanked opponents.', 5, 72, 'When an attacker includes Tactics dice in an attack against you.', 62, 'counter-tactics', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(10, 1, 10, 'Spines', 0, 0, NULL, 'Passive; Use Spines as a Brawling Weapon Note: From The gift \"quills\" as spines was not listed', '@@PASSIVE: Use Spines as a Brawling Weapon\n\n@@SECTION: Note: From The gift \"quills\" as spines was not listed separately in source book.\n\n@@SECTION: Your body is covered in modified hairs that are long, stiff, sharp, and end in barbs. People grappling you are in danger of hurting themselves.', 3, 745, '', 15, 'spines', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(11, 1, 11, 'Electroreceptors', 0, 0, NULL, 'Passive; In water, sense targets at Short range.', '@@PASSIVE: In water, sense targets at Short range\n\n@@FLAVOUR:\nYou have sophisticated organs in your body that can detect the muscular activity of other creatures, through water (and not air). You and yours usually call this \"the water sense\".\n\n@@SECTION:\nWhen you are in water, you suffer no concealment penalties against any targets within short range of you. You can swim freely, even blind, using this passive sense to help you.', 1, 918, 'When you are in water', 15, 'electroreceptors', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(12, 1, 12, 'Venomous Kick', 0, 0, 2, 'Passive; Exhaust; If your Kick scores a \"Hurt\" result on a target, you may choose to exhaust this Gift the target also becomes Sick.', '@@REFRESH: X (Respite)\n\n@@TRIGGER: Kick attack scores a \"Hurt\" Result\n\n@@SECTION:\nIf your Kick scores a \"Hurt\" result on a target, you may choose to exhaust this Gift. If you do, the target also becomes Sick.\n\n@@SECTION: (A Sick character falls down any time they become Reeling, and they cannot heal from being Injured until they have first healed the Sick.)', 1, 923, 'Kick attack scores a \"Hurt\" Result', 15, 'venomous-kick', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(13, 1, 13, 'Keen Eyes', 0, 0, NULL, 'Passive; When using Observation to see something, you may negate the highest-showing difficulty die that opposes you', '@@PASSIVE: Better Seeing\nYou have better eyesight. When using Observation to see something, you may negate the highest-showing difficulty die that opposes you.', 5, 51, 'When using Observation to see something', 16, 'keen-eyes', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(14, 1, 14, 'Cleric\'s Trappings [Left-Hand]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Extravagant book: your own copy of \"The Testaments of Helloise\", as transcribed by the Church of Penitence\none White Robe\none Acacia Wand\none weapon from the following list:\nan Electrum Rod (for the Left-Hand Path)\none Talisman: a Fluroite Octohedron\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 60, '', 25, 'clerics-trappings-left-hand', '2026-03-22 10:39:00', '2026-03-29 09:13:30'),
(15, 1, 15, 'Literacy', 0, 1, NULL, 'Passive; You can read!', '@@FLAVOUR:\nYou can read!\n\n@@SECTION: You can read and write. The Game Host may call for rolls of Mind and Academics to understand particularly difficult texts. (Characters without this Gift can\'t read or write at all!)\n\n@@LIMIT: Manifold\n\n@@NOTE: Learning a new alphabet requires a new Literacy gift.', 5, 76, '', 63, 'literacy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(16, 1, 16, 'White Magic Apprentice', 0, 0, 1, 'Action; Rally + Divine Aid; Roll Will + Leadership; choose one boon: remove Hurt; Dying→Fatigued; remove On Fire; Marionette→Reeling; Controlled→Immobilized; Immobilized/Slowed→Reeling; (GH may allow other cures).\nLong action (5 min); Lead group in healing prayer; remove Hurt from all participating allies.\nAction; Exhaust; Ready Holy weapon (Repudiation, Rebuke); counts as Magic Attack; persists until cast (Attack), dropped (free), or end of Scene (~5 min). [Battle]', '@@REQUIRES: Literacy\nCleric\'s Trappings (Any)\n\n@@ACTION: Action \"rally and apply divine aid\"\nWhenever you take the \"rally other\" action, you may call upon the Shining Light of All-Creation to bless the target. Roll your Will & Leadership, as always, and note the successes. You now have some new boons you may claim:\nRemove the \"Hurt\" condition from the target.\nReplace the \"Dying\" condition with the \"Fatigued\" condition.\nRemove the \"On Fire\" Condition\nReplace the \"Marionette\" condition with the \"Reeling\" condition.\nReplace the \"Controlled\" condition with the \"Immobilized\" condition.\nReplace the \"Immobilized\" or \"Slowed\" condition with the \"Reeling\" condition.\n\n@@NOTE: At the discretion of the Game Host, applying divine aid may be able to cure the target of other afflictions.\n\n@@ACTION: Long action (five minutes) \"Lead group in healing prayer\"\nAfter any battle has ended, you may gather all your allies around you and lead them in inspirational prayer. All allies who participate in your prayer have their \"Hurt\" conditions removed.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Holy weapon\"\nExhaust this Gift, then use the ready action to draw forth a Holy weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nHoly weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nRepudiation\nRebuke', 5, 87, 'Whenever you take the \"rally other\" action', 12, 'white-magic-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(17, 1, 17, 'Carousing', 0, 0, NULL, 'Passive; Bonus d12 When Drinking ', '@@PASSIVE: Bonus d12 When Drinking\n\n@@FLAVOUR: You are a social drinker.\n\n@@SECTION: When making rolls in bars, taverns, parties, and anywhere where alcohol spirits flow freely, you may claim a bonus d12.\nThis bonus applies, but is not limited to, gossiping with other drinkers, negotiating with drunk people, deceiving someone to believe that you\'re drunker than you really are, and winning drinking contests.', 5, 57, 'When making rolls in bars, taverns, parties, and anywhere where alcohol spirits flow freely', 22, 'carousing', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(18, 1, 18, 'Seduction', 0, 0, NULL, 'Passive; Bonus d12 with the Art of Romance', '@@PASSIVE: Bonus d12 with the Art of Romance\nWhen inquiring about someone\'s notions of love, gossiping to find a suitable partner, negotiating a romantic rendezvous, or deceiving someone who has romantic feelings for you, you may claim a bonus d12.', 5, 59, '', 22, 'seduction', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(19, 1, 19, 'Streetwise', 0, 0, NULL, 'Passive; Bonus d12 with the Criminal Element ', '@@PASSIVE: Bonus d12 with the Criminal Element\nYou have a keen insight into the underworld. When gossiping with other streetwise folks, when negotiating for criminal services, when inquiring about past or future crimes, or when deceiving others about your shady activities, you may claim a bonus d12', 5, 80, '', 24, 'streetwise', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(20, 1, 20, 'Bodyguard', 0, 0, 1, 'Passive; Exhaust; You may use any valid defense (counter, dodge, etc.) against this attack', '@@REQUIRES: Danger Sense\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: ally is attacked\n\n@@SECTION: When an ally is attacked, declare you will use the Bodyguard Gift. That ally must be no further away from you than your Stride.\nExhaust this Gift, then swap places with that ally. You are now defending in place of your ally, just as if you were the declared target in the first place. Any special attacks, modifiers, etc. that were declared against the original target are now in play against you. You may use any valid defense (counter, dodge, etc.) against this attack.\n@@NOTE: Your ally must agree to swapping places with you. If they refuse, for any reason, do not Exhaust this Gift and don\'t swap places.\nIf the attack claimed both you and your ally as targets (say, for example, because it was a Group attack), then the attack against your ally is negated, but you are still attacked. You must still swap places with your ally, but you only get attacked once. (Don\'t play out two attacks against yourself!)', 5, 73, 'ally is attacked', 5, 'bodyguard', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(21, 1, 21, 'Resolve', 0, 0, NULL, 'PASSIVE: You Include Your  Will Dice with Your Soak Dice. ', '@@PASSIVE: Include Will Dice with Soak Dice\nYou may claim your Will Dice as bonus Soak Dice. (Characters without this Gift use only their Body Dice as Soak Dice.)', 5, 78, '', 19, 'resolve', '2026-03-22 10:39:00', '2026-03-29 08:23:39'),
(22, 1, 22, 'Massive Fool', 0, 0, 1, 'Passive; Exhaust; Stunt \"Taunt multiple targets\" Exhaust this Gift, then declare a \"Taunt\" Stunt - against a Group of targets (instead of just one)', '@@FLAVOUR: No mere simpleton, your foolishness can enrage a crowd.\n\n@@STUNT: \"Taunt multiple targets\"\n\n@@SECTION: Exhaust this Gift, then declare a \"Taunt\" Stunt - against a Group of targets (instead of just one).\n\n@@NOTE:\nThe best result you can score on multiple targets is Enraged. Even if you score three successes, using the Stand-Out Fool ability to taunt multiple targets does not cause anyone to become Berserk.', 2, 356, '', 10, 'massive-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(23, 1, 23, 'Disguise', 0, 0, NULL, 'Passive; When deceiving others to think you\'re someone else, or when you stealthily blend in with a crowd, you may claim a bonus d12', '@@PASSIVE: Specialty Bonus for Imposters\nWhen deceiving others to think you\'re someone else, or when you stealthily blend in with a crowd, you may claim a bonus d12.', 5, 57, 'When deceiving others to think you\'re someone else, or when you stealthily blend in with a crowd', 22, 'disguise', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(24, 1, 24, 'Forgery', 1, 0, NULL, 'Passive; When using a skill to make a copy of an item that is present, you may claim a bonus die, limited by your highest skill die.', '@@REQUIRES: Streetwise\n\n@@PASSIVE: Bonus d12 for Imitations\n\n@@ACTION: You can falsify the origins of objects. For example, you can make a work of art look like it was painted by someone else, or you can make a bogus legal document look legitimate. You can make a modern item look antique by making fake distress marks. You can make cheap paint look like real gold, etc.\n\n@@SECTION: You must make the item normally - this Gift does not provide you with the skills. Once the item is made, other folks will have a d12 penalty to any rolls made to see through your forgery, in addition to any rolls against your skill.\n\n@@SECTION: Also, it takes a crook to know a crook. You may claim a bonus d12 to identify someone else\'s work as a forgery.\n@@SECTION: When using a skill to make a copy of an item that is present, you may claim a bonus d12, limited by your highest skill die. For example, if forging a document requires Mind & Academics, and your dice are d8, d6 ... then your limit on Forgery is d8, so you may only claim a bonus d8.\n\n@@LIMIT: Multiple\n\n@@NOTE: You may take this Gift multiple times. Each time, your opponents have an extra d12 penalty to see through your work, you may claim an extra d12 to recognize forged handiwork, and you may claim another (limited) bonus d12 to your forgery rolls.', 5, 80, 'When using a skill to make a copy of an item that is present', 6, 'forgery', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(25, 1, 25, 'Dilettante\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \na pistol\na rapier\na main gauche\nan Expensive outfit\na genuine letter of recommendation\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 61, '', 25, 'dilettantes-trappings', '2026-03-22 10:39:00', '2026-03-29 09:13:47'),
(26, 1, 26, 'Nobility', 1, 0, 4, 'Passive; When gossiping with other nobles, when negotiating special favors appropriate to the upper class, or when asserting your noble presence, you may claim a bonus d12.', '@@FLAVOUR: A noble bloodline or patent of nobility, traceable to a Great House or Minor House.\n\n@@PASSIVE: Bonus d12 with Noble Matters\n\n@@SECTION: You are a noble. When gossiping with other nobles, when negotiating special favors appropriate to the upper class, or when asserting your noble presence, you may claim a bonus d12.\n\n@@SECTION: You have the rights and privileges of the noble class. You are entitled to \"high justice\", and different laws will apply to you, most favorably.\n\n@@TRAPPINGS: You begin the game with a signet ring, a pewter or gold ring that you wear with the seal of your noble house on it. You may press the ring into wax to put your noble seal on official documents.\n\n@@REFRESH: X (Influence)\n\n@@FLAVOUR:\nYou may invoke your noble status for special favors ... even after failing a roll! Refer to the Influence rules for more details.\n\n@@LIMIT: Multiple\n@@NOTES: You may buy this Gift multiple times, either to represent multiple titles of nobility, or to represent greater rank or authority in noble circles. You may still only claim one bonus d12, but you will gain more exhaustions.', 5, 59, 'When gossiping with other nobles, when negotiating special favors appropriate to the upper class, or when asserting your noble presence', 22, 'nobility', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(27, 1, 27, 'Veteran', 0, 0, NULL, 'ACTION: When Aiming, you may claim a bonus d12 with your attack (instead of the typical d8); \nACTION: When Guarding, you may claim a bonus d12 with all defenses (instead of the typical d8).', '@@ACTION: Action \"aim improved to d12\"\nWhen Aiming, you may claim a bonus d12 with your attack (instead of the typical d8).\n\n@@ACTION: Action \"guard improved to d12\"\nWhen Guarding, you may claim a bonus d12 with all defenses (instead of the typical d8).', 5, 83, 'When Aiming | When Guarding', 26, 'veteran', '2026-03-22 10:39:00', '2026-03-29 08:25:39'),
(28, 1, 28, 'Elementalist\'s Trappings [Star]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS:\none Extravagant book: your own copy of \"On Elementalism\" by the College of Dunwasser\none Robe that matches your choice of school:\nStarred (for Star)\none Wand of your choice of the following:\nMyrtle (for Star)\none Rod of your choice of the following:\nDioptra (for Star)\none Talisman of your choice of the following:\nAstrolabe (for Star)\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 61, '', 25, 'elementalists-trappings-star', '2026-03-22 10:39:00', '2026-03-29 09:05:27'),
(29, 1, 29, 'Elemental Apprentice', 0, 0, 1, 'Action; Exhaust this Gift, then use the ready action to draw forth an Elemental weapon', '@@REQUIRES: Literacy\n\n@@REQUIRES: Elementalist\'s Trappings (Any)\n\n@@STUNT: \"reason with elemental\"\nYou may speak with elementals, the manifestations of universal energy, by taking the \"Reason\" action.\nYou cannot force an elemental to manifest, but you can talk to one that is still dormant. If you roll well with your Gossip or Negotiation skills, the elemental might deign to speak with you. (Elementals are notoriously emotional.)\nWhile people without this Gift may talk to elementals, their words are not understood, and they receive no intelligible reply.\n\n@@STUNT: \"minor elemental effect\"\nYour knowledge of petty elemental magicks allows you to perform minor little feats of wizardry to manipulate the physical world. You can call forth a misty fog, spark a candle or a gun, lift ¼ stone or less of unattended physical materials and move them around within Near range, freeze or boil one liter worth of liquid, or any other petty feat of magic involving the physical world. The Game Host is the final arbiter of what is petty elemental magic and what isn\'t.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Elemental weapon\"\nExhaust this Gift, then use the ready action to draw forth an Elemental weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nElemental weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nCreate Air\nCreate Earth\nCreate Water\nIgnite Fire\nMove Air\nMove Earth\nMove Fire\nMove Water', 5, 84, 'If you roll well with your Gossip or Negotiation skills', 12, 'elemental-apprentice', '2026-03-22 10:39:00', '2026-03-25 05:19:34'),
(30, 1, 30, 'Cartography', 0, 0, NULL, 'Passive; Read Maps and Make Maps. You may claim a bonus d12.', '@@REQUIRES: Literacy\n\n@@FLAVOUR: Read Maps and Make Maps\n\n@@PASSIVE: For all rolls involving whether a map is accurate or not, how to read a map, and how to plot a course using a map, you may claim a bonus d12.', 5, 76, '', 23, 'cartography', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(31, 1, 31, 'Research', 0, 0, NULL, 'Passive; Bonus d12 to Look Things Up', '@@REQUIRES: Literacy\n\n@@PASSIVE: Bonus d12 to Look Things Up\n\n@@SECTION: When you have access to a large library, university, or other repository of knowledge, you may claim a bonus d12 with rolls to research academic or supernatural matters.\n\n@@NOTES: Also, slow research is second-nature to you. When performing long-term research by rote, your successes count full value. (Other characters who do research by rote only get half value.)', 5, 76, 'When you have access to a large library, university, or other repository of knowledge | When performing long-term research by rote, your successes count full value', 23, 'research', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(32, 1, 32, 'Etiquette', 0, 0, NULL, 'Passive; When making rolls at formal functions, parties, or social events, you may claim a bonus d12', '@@PASSIVE: Specialty Bonus for Minding Your Manners\nYou are suitably finished. When making rolls at formal functions, parties, or social events, you may claim a bonus d12.\nThis bonus applies, but is not limited to, rolls that involve knowing which fork to use, how to address lords and ladies, and the proper gifts and apologies to make when sucking up to aristocrats.', 5, 57, 'When making rolls at formal functions, parties, or social events', 22, 'etiquette', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(33, 1, 33, 'Haggling', 0, 0, NULL, 'Passive; Bonus d12 for Haggling.', '@@SECTION: 10% Discount on Most Items\nWhen buying Average or Expensive items, you pay only 90% of the listed cost.\nWhenever you buy Cheap items in bulk, you get a discount. Buy 9 of the same Cheap item, and the 10th one is free.\n30% for Used Goods\nWhen you sell Average or Expensive items to a Minor Character, you may claim 30% of the value of the item as standard (instead of 20%).\nYour Quincunxes are worth 5Ð, not 3Ð\nWhen you use the infamous quincunx coins to buy or sell items, you may claim full value (5 denarii) instead of the partial value that non-Hagglers get (3 denarii).\n@@PASSIVE: Bonus d12 for Haggling\nWhenever you negotiate prices on Extravagant items, inquire about fair deals, or deceive someone about an item\'s monetary worth, you may claim a bonus d12.', 5, 57, 'When buying Average or Expensive items | Whenever you buy Cheap items in bulk | When you sell Average or Expensive items to a Minor Character', 22, 'haggling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(34, 1, 34, 'Bravery', 0, 0, 1, 'ACTION: You can negate the Afraid condition on your character.', '@@REQUIRES: Veteran\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: being Afraid\n@@SECTION: Any time your character is Afraid, declare you will Exhaust this Gift. Then, negate the Afraid condition on your character.\nThe Gift of Bravery has no effect on the Terrified condition.', 5, 83, 'being Afraid', 5, 'bravery', '2026-03-22 10:39:00', '2026-03-29 08:26:43'),
(35, 1, 35, 'Dead Reckoning', 0, 0, NULL, 'Passive; Bonus d12 for Land Navigation', '@@PASSIVE: Bonus d12 for Land Navigation\nYou have a keen sense to tell how far you have moved in a certain amount of time, and in what direction. You may claim a bonus d12 on all rolls to tell how far you\'ve traveled and to tell what direction you\'ve traveled.', 5, 54, '', 14, 'dead-reckoning', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(36, 1, 36, 'Geography', 0, 0, NULL, 'Passive; Bonus d12 to Know Places and People.', '@@PASSIVE: Bonus d12 to Know Places and People\nWhen making rolls to identify major roads; cities, nations, and populations, you may claim an extra d12.\nGeography helps with general knowledge - for the specifics of a particular town or landscape, you\'ll want the Gift of Local Area Knowledge.', 5, 54, 'When making rolls to identify major roads; cities, nations, and populations', 14, 'geography', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(37, 1, 37, 'Fast-Talk', 0, 0, NULL, 'Passive; Bonus d12 for Fast Negotiations ', '@@PASSIVE: Bonus d12 for Fast Negotiations\nYou may claim a bonus d12 when using Negotiation to get someone to do something, as long as that something can be done in this Scene (that is, in less than 5 minutes). This bonus includes, but is not limited to, when using the \"Reason\" action in combat.', 5, 57, '', 22, 'fast-talk', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(38, 1, 38, 'Cleric\'s Trappings [Right-Hand]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS:\none Extravagant book: your own copy of \"The Testaments of Helloise\", as transcribed by the Church of Penitence\none White Robe\none Acacia Wand\none weapon from the following list:\na Calendar Sword (for the Right-Hand Path)\none Talisman: a Fluroite Octohedron\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 60, '', 25, 'clerics-trappings-right-hand', '2026-03-22 10:39:00', '2026-03-29 09:12:33'),
(39, 1, 39, 'Cognoscente\'s Trappings [Green]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Extravagant book: your own copy of an anonymous volume, bound with a purple cover and strung with a green bookmark, on the subject of Green & Purple Magic\none Robe: Green\none Olive Wand\none Quicksilver Rod\none Talisman: a Tourmaline Headband\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 61, '', 25, 'cognoscentes-trappings-green', '2026-03-22 10:39:00', '2026-03-29 09:13:35'),
(40, 1, 40, 'Green & Purple Apprentice', 0, 0, 1, 'Action; Action \"ready Psychic weapon\"\n        Action \"rally by thought-sending\"', '@@REQUIRES: Literacy\n\n@@REQUIRES: Cognoscente\'s Trappings (Any)\n\n@@STUNT: \"reason with shade\"\nYou may speak with shades, the ghosts of personality, by taking the \"Reason\" action. You cannot force a shade to manifest, but you can talk to one that is still dormant. If you roll well with your Gossip or Negotiation skills, the shade might deign to speak with you. (Shades are notoriously emotional.)\n\n@@SECTION: While people without this Gift may talk to shades, their words are not understood, and they receive no intelligible reply.\n\n@@ACTION: Action \"rally by thought-sending\"\nBy taking the \"rally\" action, you may send your thoughts to a single target within Medium range of you, provided you have line of sight. The target hears your voice in their head, as if you were speaking aloud in a voice only they can hear. (Those schooled in the Supernatural may make a simple roll to figure this out; other people may just assume they can\'t see the speaker, which can lead to embarrassing situations if they respond by speaking out loud.)\nOutside of combat situations, the Thought-Sending effect can be used simply to send instructions. Inside of combat, you may use your Will & Leadership to rally a single target, up to Medium range, with no Range penalties.\nThe Cognoscenti use their thought-sending to have conversations with each other, or with their servants, in public places, without fear of anyone listening in.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Psychic weapon\"\nExhaust this Gift, then use the ready action to draw forth a Psychic weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as afree action), or until the end of the Scene (five minutes).\nPsychic weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nAtaxia\nEyebite\nPerplexing', 5, 85, 'If you roll well with your Gossip or Negotiation skills', 12, 'green-purple-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(41, 1, 41, 'Cognoscente\'s Trappings [Purple]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Extravagant book: your own copy of an anonymous volume, bound with a purple cover and strung with a green bookmark, on the subject of Green & Purple Magic\none Robe: Purple\none Olive Wand\none Quicksilver Rod\none Talisman: a Tourmaline Headband\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 61, '', 25, 'cognoscentes-trappings-purple', '2026-03-22 10:39:00', '2026-03-29 09:13:40'),
(42, 1, 42, 'Thuamaturge\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Extravagant book: your own copy of \"Thamauturgoria\", by Kyndranigar the Shadow Magus\none Gray Robe\none Hazel Wand\none Cypress Rod\none Talisman: a Lodestone Charm\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 63, 'Casting an Unholy Spell', 25, 'thuamaturges-trappings', '2026-03-22 10:39:00', '2026-03-29 09:23:19'),
(43, 1, 43, 'Thaumaturge Apprentice', 0, 0, 1, 'Action; Action \"ready Theurgic weapon\" \nAction \"guard with supernatural shield\"', '@@REQUIRES: Literacy\n\n@@REQUIRES: Thaumaturge\'s Trappings\n\n@@TRIGGER: when guarding Reaction \"supernatural light\"\n@@ACTION: Whenever you are guarding, you may call forth a supernatural light. Everything Near you (within 4 paces) is illuminated as per daylight, although no one can clearly see where the light is coming from.\nThis light is supernatural, and it does not travel further than 4 paces from you. Supernatural light totally negates supernatural darkness in its area of effect.\n\n@@ACTION: Action \"guard with supernatural shield\"\n@@TRIGGER: When you take the \"Guard\" action, you may call forth a supernatural shield.\nYou and any allies Near you (within 4 paces) gain good Cover (bonus d8 to Parry and Dodge). Allies within Short Range (12 paces) gain minor Cover (bonus d4 with Parry and Dodge).\nYou must be able to see an ally to grant them the supernatural Cover. The cover only lasts as long as you Guard.\nThe supernatural shield is invisible, but still protects the wizard from harm. Thaumaturges often use this spell as a magic umbrella, to keep the rain off their heads.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Theurgic weapon\"\nExhaust this Gift, then use the ready action to draw forth a Theurgic weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\n@@SECTION: Theurgic weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nMisfortune\nSilence', 5, 86, 'when guarding Reaction \"supernatural light\"', 12, 'thaumaturge-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(44, 1, 44, 'Cosmopolitan', 0, 0, NULL, 'Passive; Negate Culture Penalties You may use your Culture Skills and Gifts with any culture, not just your own', '@@PASSIVE: Negate Culture Penalties\nYou may use your Culture Skills and Gifts with any culture, not just your own.', 5, 57, '', 22, 'cosmopolitan', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(45, 1, 45, 'Elementalist\'s Trappings [Yellow]', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS:\none Extravagant book: your own copy of \"On Elementalism\" by the College of Dunwasser\none Robe: Yellow\none Wand: Oak\none Rod: Alumen\none Talisman: Sapphire Charm\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 61, '', 25, 'elementalists-trappings-yellow', '2026-03-22 10:39:00', '2026-03-29 09:05:33'),
(46, 1, 46, 'First Aid', 0, 0, NULL, 'Passive; Also, you may claim a bonus d12 with a first aid attempt', '@@ACTION: New action \"improved first aid\"\nFor you, first aid is no longer a stunt - it\'s a standard action. You are not automatically sent Reeling after performing First aid.\nAlso, you may claim a bonus d12 with a first aid attempt', 5, 54, '', 14, 'first-aid', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(47, 1, 47, 'Artist: [Choice]', 1, 0, NULL, 'Passive; Bonus d12 for Making Art ', '@@PASSIVE: Bonus d12 for Making Art\nYou can create works of art. When you take this Gift, choose a type of art. When making rolls to gossip about this art, or to craft new works of art, you may claim a bonus d12.\nSuggestions for Art Specialties:\nCharcoal Art\nLimning (cutting silhouettes out of paper)\nPainting\nSculpting', 5, 53, 'When you take this Gift, choose a type of art | When making rolls to gossip about this art, or to craft new works of art', 14, 'artist-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(48, 1, 48, 'Doctor', 0, 0, NULL, 'Passive; You can treat the Injured and Sick. ', '@@REQUIRES: Literacy\n\n@@S:ection: Recuperation\nYou can treat the Injured and Sick. Take one hour and use your medical supplies to treat a patient, by rolling your Mind & Academics vs. 3. For each success you score, the patient earns 1 point towards healing an Injured or Sick quota.\nIf the patient is both Injured and Sick, you must split your points between the two quotas, however you like.', 5, 76, 'If the patient is both Injured and Sick', NULL, 'doctor', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(49, 1, 49, 'Low Profile', 0, 0, NULL, 'Passive; Bonus d12 to Blend In With Crowds', '@@PASSIVE: Bonus d12 to Blend In With Crowds\nWhen rolling to deceive others that you\'re an unimportant bystander or to stealthily blend in with a crowd, you may claim a bonus d12.', 5, 59, 'When rolling to deceive others that you\'re an unimportant bystander or to stealthily blend in with a crowd', 22, 'low-profile', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(50, 1, 50, 'Heraldry', 0, 0, NULL, 'Passive; Bonus d12 to Know Nobles and Flags', '@@PASSIVE: Bonus d12 to Know Nobles and Flags\nWhen rolling to spot or to identify battle standards and flags, to know the family history and lineage of noble bloodlines, and to know the past and current standings of clans and dynasties, you may claim a bonus d12.', 5, 54, '', 14, 'heraldry', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(51, 1, 51, 'Rider\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS:  \neither a destrier or a palfrey (your choice)\nharness and saddle\na saddle-holster with shortsword\ntwo saddlebags\na animal\'s grooming kit\na blanket\nspurs\na riding crop\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session.', 5, 62, 'If you are parted from your items, ask the Game Host for a plot twist to return or to replace them', 25, 'riders-trappings', '2026-03-22 10:39:00', '2026-03-29 09:20:27'),
(52, 1, 52, 'Honor', 0, 0, 5, 'Passive; Exhaust; You cannot refresh this Gift until you have redressed the wrong that caused you dishonor Conditional Bonus to Defend Your Honor Swear, on your honor, that you…', '@@REFRESH: X (Special)\n\n@@PASSIVE: If you ever act dishonorably, exhaust this Gift. You cannot refresh this Gift until you have redressed the wrong that caused you dishonor\nConditional Bonus to Defend Your Honor\nSwear, on your honor, that you will perform some task. Whenever anyone dishonorably tries to prevent you from performing your task, you may claim a bonus d12. You may continue to claim the bonus d12 until you have performed the task or until this Gift becomes exhausted.\nDishonorable acts include attacking you without formally challenging you first. You are free to refuse any challenge from an unworthy, dishonorable foe.', 5, 57, 'If you ever act dishonorably', 22, 'honor', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(53, 1, 53, 'Animal Handling', 0, 0, NULL, 'Action; When making rolls to diagnose problems with an animal, you may claim a bonus d12', '@@ACTION: Action \"rally animal\"\n\n@@FLAVOUR:\nYou may attempt to rally animals. (People without this gift may not rally animals.)\nYour roll is your Body Trait. If you physically grab the animal, or if you are riding it, you may include your Riding Dice. If the animal is yoked to a vehicle that you control, you may use your Vehicles Dice.\nWhen making rolls to diagnose problems with an animal, you may claim a bonus d12.', 5, 53, 'When making rolls to diagnose problems with an animal | If you physically grab the animal, or if you are riding it | If the animal is yoked to a vehicle that you control', 14, 'animal-handling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(54, 1, 54, 'Teamster', 0, 0, NULL, 'Passive; Bonus d12 for Animal-Powered Vehicles When operating a vehicle that is powered by one or more animals, you may claim a bonus d12', '@@PASSIVE: Bonus d12 for Animal-Powered Vehicles\nWhen operating a vehicle that is powered by one or more animals, you may claim a bonus d12.', 5, 56, 'When operating a vehicle that is powered by one or more animals', 14, 'teamster', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(55, 1, 55, 'Craft Speciality: [Choice]', 0, 1, NULL, 'Passive; Whenever you roll your Craft dice with your specialty, you may claim an extra d12', '@@PASSIVE: Bonus to a Specialty Craft\nWhen you take this Gift, choose an appropriate specialty. Whenever you roll your Craft dice with your specialty, you may claim an extra d12.\n\n@@LIMIT: Manifold\n@@NOTES: You may take this Gift multiple times, choosing a new specialty each time.', 5, 54, 'Whenever you roll your Craft dice with your specialty', 14, 'craft-speciality-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(56, 1, 56, 'Diplomacy', 0, 0, NULL, 'Passive; Bonus d12 for Long Negotiations You may claim a bonus d12 for any use of Negotiation conducted over five minutes (one Scene) or longer', '@@PASSIVE: Bonus d12 for Long Negotiations\nYou may claim a bonus d12 for any use of Negotiation conducted over five minutes (one Scene) or longer.', 5, 57, '', 22, 'diplomacy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(57, 1, 57, 'Mathematics', 0, 0, NULL, 'Passive: Bonus d12 to Work with Numbers', '@@REQUIRES: Literacy\n\n@@SECTION: Bonus d12 to Work with Numbers\nWhen rolling to count inventory, to draft an engineering plan, or anything else that involves algebra and complex numbers, you may claim a bonus d12.', 5, 76, 'When rolling to count inventory, to draft an engineering plan, or anything else that involves algebra and complex numbers', 23, 'mathematics', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(58, 1, 58, 'Administration', 0, 0, NULL, 'PASSIVE: When making rolls for administrative duties, you may claim a bonus d12.', '@@PASSIVE: Bonus d12 to manage affairs\n\nWhen making rolls for administrative duties, you may claim a bonus d12. This bonus applies, but is not limited to, rolls that involve balancing books, meting out paychecks, and complying with various laws.', 5, 76, 'When making rolls for administrative duties', 6, 'administration', '2026-03-22 10:39:00', '2026-03-29 08:14:39'),
(59, 1, 59, 'Brawling Fighter', 0, 0, NULL, 'Passive; Parry with Body & Brawling Dice', '@@PASSIVE: Parry with Body & Brawling Dice\nYou can use your Body & Brawling dice to Parry against attacks! (Characters without this Gift can\'t Parry with Brawling attacks.)\nBrawling Attacks Threaten at Close Range; Counter with Brawling Attack\nYour body is a lethal weapon. If you\'re not disadvantaged or otherwise out of it, you constantly threaten other foes within Close Range of you, just with your bare hands or your natural weapons.\nBecause your Brawling weapons now threaten at Close Range, you may now Counter with Brawling', 5, 50, 'If you\'re not disadvantaged or otherwise out of it', 5, 'brawling-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(60, 1, 60, 'Sailing', 0, 0, NULL, 'Passive; Bonus d12 for sailing craft ', '@@PASSIVE: Bonus d12 for sailing craft\nWhen making rolls to identify a sailing craft\'s type, to operate a sailing craft, or basically for any roll involving a boat with sails, you may claim a bonus d12', 5, 56, 'When making rolls to identify a sailing craft\'s type, to operate a sailing craft, or basically for any roll involving a boat with sails', 14, 'sailing', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(61, 1, 61, 'Astrology', 0, 0, NULL, 'Passive: When making rolls to navigate by star-light, to determine horoscopes, or anything else related to astrology, you may claim a bonus d12', '@@REQUIRES: Literacy\n\n@@FLAVOUR: Know The Mysteries Of The Stars\n\n@@SECTION: When making rolls to navigate by star-light, to determine horoscopes, or anything else related to astrology, you may claim a bonus d12', 5, 76, 'When making rolls to navigate by star-light, to determine horoscopes, or anything else related to astrology', 23, 'astrology', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(62, 1, 62, 'Junk Expert', 0, 0, 5, 'Action; You tend to pick up things of value and then have them ready when you need them. You must be carrying your bundle, a sack of unspecified junk that weighs at least 1 stone.', '@@REFRESH: X (special)\n\n@@ACTION: Action \"draw item from junk bundle\"\nYou tend to pick up things of value and then have them ready when you need them. You must be carrying your bundle, a sack of unspecified junk that weighs at least 1 stone.\nAs an Action, you may draw a Cheap item of your choice from your bundle, that weighs no more than ¼ stone. (The Game Host should veto any inappropriate choices ... but improvised weapons are always a possibility).\nAfter drawing the item, roll your Mind & Searching vs. 3. If you succeed, you may use this Gift\'s ability again on another turn. If you tie or worse, exhaust this Gift. You may refresh this Gift only after spending 1 hour searching through a pile of junk.', 5, 54, 'After drawing the item, roll your Mind & Searching vs. 3. ', 14, 'junk-expert', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(63, 1, 63, 'Legerdemain', 0, 0, NULL, 'Improved Action; New action \"attack: pick pocket\" You can attempt to pick someone\'s pocket of a random item', '@@ACTION: Improved Action \"draw item: sleight of hand\"\nFor you, stealing an object is not a stunt, but a simple \"draw\" action.\n\n@@ACTION: Improved Action \"draw item: concealed weapon\"\nFor you, drawing a concealed weapon is no longer a stunt, but a simple \"draw weapon\" action.\n\n@@ACTION: New action \"attack: pick pocket\"\nYou can attempt to pick someone\'s pocket of a random item. Treat an attempt to pick someone\'s pocket as an attack. (It\'s really best to pick the pocket of someone who\'s disadvantaged!) At Close Range, roll your Speed & Deceit vs. the target\'s Mind & Observation. If the target is aware of you, they may attempt to Counter. If the target is actively in combat, whether they know you\'re there or not, they may elect to Dodge.\nUnlike a regular attack, you cannot claim a combat advantage bonus ... in fact, if you don\'t have combat advantage, your attack is limited to d8s or smaller.\nIf you Succeed, you get a random item from the person\'s pockets, purse, satchel, or what have you, provided that it\'s a small item easily purloined. In addition, your target is not sent Reeling - they probably don\'t even know you got something.', 5, 51, '', 16, 'legerdemain', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(64, 1, 64, 'Shadowing', 0, 0, NULL, 'Passive; Bonus d12 for Following People You know how to follow people without being seen ... and that knowledge works both ways, so you know how to avoid being…', '@@PASSIVE: Bonus d12 for Following People\nYou know how to follow people without being seen ... and that knowledge works both ways, so you know how to avoid being followed, yourself.\nWhen you are stealthily avoiding being followed, when observing if you\'re being followed, or when gossiping with folks to find out if someone\'s been around lately, you may claim a bonus d12.\n\n@@SECTION: Note\nShadowing is described in the Spot Rules chapter.', 5, 59, '', 22, 'shadowing', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(65, 1, 65, 'Ordainment', 1, 0, 4, 'Passive; You may still only claim one bonus d12, but you will gain more exhaustions', '@@REQUIRES: An endorsement from a religious organization.\n\n@@SECTION: Bonus d12 with Religious Matters\n\n@@SECTION: You are an ordained priest or priestess. People treat you with respect. You can regularly depend on people\'s charity.\nWhen you speak on academic matters of religion, when you gossip about religious matters, when you negotiate for favors for your church, or when you assert your holy presence, you may claim a bonus d12.\n\n@@REFRESH: X (Influence)\n\n@@FLAVOUR:\nYou may invoke your churchly status for special favors ... even after failing a roll! Refer to the Influence rules for more details.\n\n@@LIMIT: Multiple\n@@NOTE: You may buy this Gift multiple times, either to represent greater rank or authority in priestly circles. You may still only claim one bonus d12, but you will gain more exhaustions.', 5, 59, '', 22, 'ordainment', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(66, 1, 66, 'Knockout Strike', 0, 0, 1, 'Action; Exhaust; \"brawling or melee attack: knockout strike\" Before making a brawling attack or a melee attack, declare you will exhaust this Gift', '@@REQUIRES: Veteran\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"brawling or melee attack: knockout strike\"\nBefore making a brawling attack or a melee attack, declare you will exhaust this Gift. The damage from your attack becomes Weak. If you score a Hurt result against your target, the target also becomes Asleep. If you score an Afraid result against your target, your target also becomes Unconscious.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"melee attack: knockout strike with truncheon\"\nAs \"knockout strike\", above, only if your melee weapon has the Truncheon descriptor, you may claim a bonus d8 with your attack.', 5, 83, 'If you score a Hurt result against your target | If you score an Afraid result against your target, your target also becomes Unconscious', 26, 'knockout-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(67, 1, 67, 'Spy\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \na pistol\na stiletto\none Cheap outfit\ntwo Average outfits\none Expensive outfit\nthree forged letters of recommendation.\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 62, '', 25, 'spys-trappings', '2026-03-22 10:39:00', '2026-03-29 09:21:12'),
(68, 1, 68, 'Oratory', 0, 0, NULL, 'Passive; Bonus d12 with Public Speaking ', '@@PASSIVE: Bonus d12 with Public Speaking\nWhen giving a public speech about an academic topic, a call to action worthy of a great leader, a winning debate point in a negotiation, or just announcing your presence to a crowd, you may claim a bonus d12', 5, 59, 'When giving a public speech about an academic topic', 22, 'oratory', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(69, 1, 69, 'Legal Authority: [Choice]', 0, 0, 4, 'Passive; Exhaust; You may exhaust this Gift to push influence over other folks ... even after failing a roll!', '@@REQUIRES: Authorization from a recognized legal authority.\n\n@@FLAVOUR: You are the law\n\n@@SECTION: You are an authorized legal agent of some greater authority. You may be a town guard, a policeman, or even the mayor. You have certain entitlements, such as carrying a concealed weapon or arresting people who break the law. Your Legal Authority is limited in scope - usually to only a single Landscape or branch of government.\nYou can claim a bonus d12 when Gossiping with other folks with Legal Authority.\n\n@@REFRESH: X (Influence)\n\n@@PASSIVE: You may exhaust this Gift to push influence over other folks ... even after failing a roll! Influence rules for more details.', 5, 58, '', 22, 'legal-authority-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(70, 1, 70, 'Bribery', 0, 0, NULL, 'Passive; Bonus d12 to bribe others ', '@@PASSIVE: Bonus d12 to bribe others\n@@ACTION: You can claim a bonus d12 when using Gossip or Inquiry to find out what would be a good bribe for someone.\n@@ACTION: You can claim a bonus d12 when trying to Negotiate, if you offer the other party a good or service that they want. If you still Fail the contest, the other party would be less insulted than they would have been if you didn\'t have this Gift.\n@@NOTE: (Characters without the Gift of Bribery can still attempt to bribe others - and they can still get a bonus for really good bribes - but they don\'t get your automatic Bonus d12 and they risk offending the other party.)', 5, 57, '', 22, 'bribery', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(71, 1, 71, 'Gambling', 0, 0, NULL, 'Passive; Bonus d12 with Games of Chance When playing a game of chance, negotiating a wager, deceiving others with a bluff in a card game, inquiring from others about…', '@@PASSIVE: Bonus d12 with Games of Chance\nWhen playing a game of chance, negotiating a wager, deceiving others with a bluff in a card game, inquiring from others about their own bluffs, you may claim a bonus d12.', 5, 54, '', 14, 'gambling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(72, 1, 72, 'Medicine', 0, 0, NULL, 'Passive; Bonus d12 to Heal People When rolling to use academic knowledge to help a patient recover from injury or sickness, to inquire about a patient\'s history, or to…', '@@PASSIVE: Bonus d12 to Heal People\nWhen rolling to use academic knowledge to help a patient recover from injury or sickness, to inquire about a patient\'s history, or to identify a cause of death, you may claim a bonus d12.', 5, 55, '', 14, 'medicine', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(73, 1, 73, 'Venomous Sting', 0, 0, 2, 'Passive; Exhaust; If your Sting scores a \"Hurt\" result on a target, you may choose to exhaust this Gift', '@@REFRESH: X (Respite)\n\n@@TRIGGER: Sting attack scores a \"Hurt\" Result\n\n@@SECTION:\nIf your Sting scores a \"Hurt\" result on a target, you may choose to exhaust this Gift. If you do, the target also becomes Sick.\n\n@@NOTE:\nthis comes from Venomous Bite. Had the gift of Venom in the book but no such gift exists', 4, 438, 'Sting attack scores a \"Hurt\" Result', 15, 'venomous-sting', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(74, 1, 74, 'Quick Fool', 0, 0, 1, 'Passive; Exhaust; When you use the Dodge defense against an Enraged or Berserk attacker, exhaust this Gift', '@@FLAVOUR:\nYou have to be quick, when folks are this mad at you.\n\n@@TRIGGER: Dodging an Enraged/Berserk attacker\n\n@@SECTION:\nWhen you use the Dodge defense against an Enraged or Berserk attacker, exhaust this Gift. You may not use the ability against attackers who are neither Enraged nor Berserk.\n\n@@SECTION: Take note of your highest Dodge die. You may move up to this distance, away from your attacker, in a straight line. For example, if your Dodge dice came up 7, 6, 4, then you may move up to 7 paces away from the attacker.', 2, 356, 'Dodging an Enraged/Berserk attacker', 10, 'quick-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(75, 1, 75, 'Fighting Fool', 0, 0, NULL, 'Passive; You rush in where others fear to tread. 2d8 Bonus to attack the Enraged or Berserk ', '@@FLAVOUR: You rush in where others fear to tread.\n\n@@SECTION: 2d8 Bonus to attack the Enraged or Berserk\n\n@@ACTION:\nIf you declare an attack against an Enraged or Berserk combatant, you may claim a bonus 2d8 with your attack', 2, 355, 'If you declare an attack against an Enraged or Berserk combatant', 10, 'fighting-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(76, 1, 76, 'Comic Relief', 0, 0, 1, 'Action; Exhaust; This Gift only allows you to Rally when you are Afraid or Terrified - not with other bad conditions', '@@FLAVOUR: Somehow, your wisecracks are just the right thing to say to relieve the tension and to urge our heroes to action.\n\n@@ACTION: Action \"rally (even when Afraid or Terrified)\"\n\n@@SECTION: Exhaust this Gift, then take a Rally action, even if you are Afraid.\n\n@@SECTION: This Gift only allows you to Rally when you are Afraid or Terrified - not with other bad conditions.', 2, 355, '', 10, 'comic-relief', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(77, 1, 77, 'Coward', 0, 0, 2, 'Passive; When Afraid, You Move Faster and Dodge Better Whenever you are Afraid or Terrified, add 1 to your Stride, add 3 to your Dash, and 9 to your Run', '@@FLAVOUR: When Afraid, You Move Faster and Dodge Better\n\n@@ACTION: Whenever you are Afraid or Terrified, add 1 to your Stride, add 3 to your Dash, and 9 to your Run. (Since Run is based on Dash, this will result in +12 to Run.)\nAlso, you may claim a bonus d12 to your Dodge defense (but not to other defenses).\n\n@@REFRESH: X (Respite)\n\n@@SECTION: As a Reaction, you may become Afraid for the rest of this Scene (about 5 minutes).', 5, 50, 'When Afraid', 16, 'coward', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(78, 1, 78, 'Increased Trait: Will', 1, 0, NULL, 'PASSIVE: Increase Your Will Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\n\n@@LIMIT: Multiple\n@@NOTE: You may take this Gift multiple times, increasing a Trait even further, up to d12.\n\n@@LIMIT: Manifold\n@@NOTE: You may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-will', '2026-03-22 10:39:00', '2026-03-29 08:22:46'),
(79, 1, 79, 'Natural Armor', 0, 0, NULL, 'Passive; Add Species Die to Soak Dice Your thick hide protects you from damage', '@@PASSIVE: Add Species Die to Soak Dice\nYour thick hide protects you from damage. You may include your Species die with your Soak dice.', 5, 68, '', 15, 'natural-armor', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(80, 1, 80, 'Frenzy', 0, 0, 2, 'Reaction; For one scene; (Enraged fighters may shake off being sent unconscious or afraid, but they must take the Attack action every round.) If you are suffering from any conditions…', '@@REFRESH: X (Respite)\n\n@@FLASVOUR: \"Become Enraged\"\n@@REACTION: As a Reaction, you can become Enraged for one scene. (Enraged fighters may shake off being sent unconscious or afraid, but they must take the Attack action every round.)\nIf you are suffering from any conditions that would prevent you from becoming Enraged (such as Afraid or Unconscious), remove those conditions and become Enraged anyway.', 5, 51, '', 16, 'frenzy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(81, 1, 81, 'Strength', 0, 0, NULL, 'PASSIVE: With all Natural Attacks, Melee Attacks, and Thrown Attacks, you may include an extra d8. ', '@@PASSIVE: Carry More and Hit Harder\nWith all Natural Attacks, Melee Attacks, and Thrown Attacks, you may include an extra d8. (There is no benefit for Counter-Attacks or Parries.)\nYou can carry more weight. (See \"Encumbrance\", page 90.)', 5, 81, '', 5, 'strength', '2026-03-22 10:39:00', '2026-03-29 08:28:45'),
(82, 1, 82, 'Flight', 0, 0, 1, 'Passive; Exhaust; (That\'s a Maximized Body for a score of 4 ... a Maximized d12, d8, d6 for a score of 12 ... a Flying Dash of 4 ... and a bonus 12, all added together.) If you…', '@@REFRESH: X (Battle)\n\n@@ACTION: Extra Action \"fly at [altitude of choice]\"\nYou have winged arms that allow you to fly, in an awkward fashion.\nIn game terms, you have an extra action per turn: the \"fly\" action. (Normally, characters can only take two actions per turn - you can take three, if and only if one of those actions is a \"fly\" action.)\nSince you must flap your arms to fly, you can only use one-handed weapons and tools.\nIf your turn ends, and you haven\'t landed, then you will fall - see below.\n\n@@SECTION: While flying, you have the Full-Tilt status.\nAt the beginning of any turn when you are flying, then you will drift your Body dice in an appropriate direction. (For example, if your Body is d8, then you will drift d8 paces.)\nThe Full-Tilt will be in the last direction that you moved. In strange cases, the Game Host should choose an appropriate direction. No matter what, you will drift while flying; there is no hovering in a single spot.\nWhile flying, you may not Retreat. (You may still be pushed or moved by other sources.)\nChoosing an Altitude: Close, Reach, or Near\n\n@@S:ECTION To keep the game simple, the rules only keep track of a flier\'s altitude by Range Bands.\nWhen declaring that you will fly, choose an altitude level: Close, Reach, or Near. You may switch freely between these levels. For example, if you started your round at Close, you may rise to Reach or Near. If you started at Reach, you may rise to Near or drop to Close, etc.\nA flyer that is Close to the ground is only 1 pace up - they are weaving between ground-level obstacles. A flyer that is within Reach of the ground is 2 paces up, flying over the heads of other combatants. A flyer that is Near to the ground is 4 paces up, very much clear of the ground but still close enough to see what\'s going on - Near ground is the preferred altitude for most flyers.\n@@SECTION: Attackers on the ground must be within both distances to attack you. For example, if a flying combatant is 1 pace away on the horizontal battle map, but their altitude is Reach (2 paces), then you may threaten the combatant only with attacks that have a range of \"Reach\".\nRanged attacks use the worst of the two ranges. For example, if you\'re at Close range horizontally, but you\'re at Near range vertically, then you\'re at Near Range for purposes of ranged attacks.\n\n@@PASSIVE: Exhaust \"Flight\", then one action to Fly, then one action to Refresh Flight\nFlight is a Battle Gift. You must Exhaust it to fly. Since you must use the \"fly\" action to stay in the air, you will have to be able to Exhaust Flight to fly ... and if it\'s Exhausted, you will have to spend one of your actions to Refresh Flight.\nSo to keep it simple: first Exhaust your Flight, then declare your bonus \"fly\" action, then declare your \"refresh flight\" action. Your third action is yours to be whatever you want.\nIf you were sent Reeling: first Recover from Reeling, then declare your bonus \"fly\" action, then declare your \"refresh flight\" action.\nWant to be able to do more while you\'re in the air?\nThe gift of Flying Fighter, described in the Atavism chapter, lets you take an extra \"Refresh Flight\" action, bringing you up to four actions a turn: one \"fly\", one \"refresh flight\", and then two actions of your choice.\nThe rule of \"never the same action twice in the turn\" still applies. If you\'re Refreshing Flight, you\'re not refreshing other things. If you have other Battle Gifts that you need to Refresh, you will have to land, so that you can stop Refreshing Flight.\nUse your Flying Stride, Flying Dash, Flying Sprint, and Flying Run to move horizontally\nTo move horizontally, you may use the standard \"stride\", \"dash\", and \"sprint\" actions. You may also use the \"run\" stunt to move a great distance.\nYour Flying Stride distance is the same as your Stride, plus 3. Since most characters have a Stride of 1, then your Flying Stride is 4.\nYour Flying Dash distance is the same as your regular Dash. For example, if your character has a Dash of 4, then your Flying Dash is also 4. If your Dash drops to zero (say, because of encumbrance), then your Flying Dash is also zero.\nYour Flying Sprint dice are your Speed dice and your Weather Sense dice. For example, if your Speed is d8, and your Weather Sense are d12 and d6, then your Flying Sprint dice are d12, d8, d6. Just like a Sprint, you may choose to voluntarily lower your dice any time you use them. For example, instead of rolling d12, d8, d6, you could roll d8, d8, d6, or d4, d4, d4.\nYour Flying Run is your Maximized Body die, plus your Maximized Flying Sprint, plus your Flying Dash, plus 12. Following the above examples, a Body d4, Speed d8, Weather Sense d12, d6 character would have a Flying Run of 32. (That\'s a Maximized Body for a score of 4 ... a Maximized d12, d8, d6 for a score of 12 ... a Flying Dash of 4 ... and a bonus 12, all added together.) If you take a Flying Run stunt, at the end you will be sent Reeling, just like any other Run.\n\n@@ACTION: New action\n\"Rise to Short Altitude\"\nAs an action, if you are already flying at Close, Reach, or Near height, you may gain altitude, to Short height.\nFor game purposes, you are 12 paces off the ground.\nYou may only take one rise action per turn.\n\n@@ACTION: New action\n\"Rise from Short to Medium Altitude\"\nAs an action, if you are already flying, you may gain altitude. You may rise from Short height to Medium height. (You may not rise from Medium height from any altitude lower than Short.)\nYou may rise from Close, Reach, or Near altitude to Short altitude.\nYou may only take one rise action per turn.\n@@STUNT: New stunt\n\"Ascend from Medium to Long Altitude\"\nAs an action, if you are already flying, you may gain altitude. You may rise from Medium height to Long height. (You may not rise from Long height from any altitude lower than Medium.) After the move, you are sent Reeling, as per any stunt.\nNote that this stunt is not a rise action. You can use a \"rise\" action to move from Short to Medium height, then the \"ascend\" stunt to move to Long height.\nA flyer can\'t fly any higher than Long altitude unless they have the Gift of High Altitude Flyer, page 319.\n\n@@TRIGGER: you end your turn without having taken the \"fly\" action | you suffer falling damage\n\n@@ACTION: New action\n\"Dive from Short or Medium altitude\"\nAs an action, you may dive. You may drop from Medium or Short altitude to Close, Near, Reach, or Short altitude.\nWhen you dive, you may also move your Flying Stride in any horizontal direction.\n@@STUNT: New stunt\n\"Power Dive from Long altitude\"\nAs an action, you may power-dive from Long altitude. You may drop to Close, Near, Reach, Short, or Medium altitude.\nWhen you power-dive, you may also move your Flying Dash in any horizontal direction.\nYou may fly over obstacles\nWhile flying, you may clear any ground obstacles that are shorter than your altitude. For example, if you are within Reach of the the ground, you may fly over obstacles 1-pace tall or shorter. If you are Near to the ground, you may fly over any 3-pace-tall walls, or over other combatants. If you fly Close to the ground, you may ignore bad footing, but you will run into any other obstacles.\nLanding\nIf, after taking any action, you end your turn within Reach distance of the ground, you may declare that you have landed. If you end your turn near something you might hang on to, like a ledge or tree branch, you may declare that you will land on that. The Game Host may call for a roll of your Body & Climbing vs. 3 to cling to alight on unusual landing spots, like flag polls or branches. (Some fliers have Prehensile Feet, which makes this kind of landing easier.) Very unusual landing spots, such as greased poles, might be even more difficult. Naturally, a landing spot must be able to support your weight, too.\nOnce you have landed, you have no risk of falling, and you are now treated like any other non-flying combatant.\nNervous about landing? Try a Flying Dash to the landing spot, then declaring you will land. If you fail the roll, take \"Fly\" as your second action and you can stay in the air. (Then take \"Refresh Flight\" as your third action.)\n\n@@TRIGGER: you end your turn without having taken the \"fly\" action\n\"Fall\"\nAt the end of your turn, if for whatever reason you did not take the fly action, you will fall. Falling is discussed in the \"Spot Rules\" chapter.\nIf you are within Long distance of the ground, you will suffer 50 paces of falling damage. If you were at Medium range, you will suffer 18 paces of falling damage. If you were at Short range, you will suffer 6 paces of falling damage. If you were at any other range, you will suffer 3 paces of falling damage.\n\n@@TRIGGER: you suffer falling damage\nYour wings will slow your falling speed. When you take falling damage, for any reason, you may claim your Weather Sense dice as Soak dice', 5, 66, 'you end your turn without having taken the \"fly\" action | you suffer falling damage', 15, 'flight', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(83, 1, 83, 'Prehensile Feet', 0, 0, NULL, 'PASSIVE: Your feet have thumbs, and can grip things.', '@@PASSIVE: Grab Things With Your Feet\nYour feet have thumbs, and can grip things. They act as two extra off-hands (that cannot use 2-handed weapons). However, since you have to stand on them, they\'re not the best for weapon use unless you have the Gift of Acrobat and you can stand on your hands.\n\n@@TRIGGER: failed Climbing Roll  You may claim an extra d12 to escape from any After Failing a Climbing roll (or worse), you can grapple. make a separate, desperate attempt to grab with your Prehensile Feet. Roll all your Climbing Dice again - the second result stands. If the roll is successful, you are Knocked Down until you can right yourself.\n\n@@SECTION: Note\nThe Gift of Ambidexterity allows you to use all Prehensile appendages as if they were your main hand.', 5, 68, 'failed Climbing Roll You may claim an extra d12 to escape from any After Failing a Climbing roll (or worse), you can grapple.', 15, 'prehensile-feet', '2026-03-22 10:39:00', '2026-03-29 08:46:59'),
(84, 1, 84, 'Echolocation', 0, 0, NULL, 'Reaction; Among other things, echolocation negates concealment up to Medium range (allowing you to Counter-Attack or to Dodge with no penalty)', '@@REACTION: \"echolocate\"\nAs a reaction, declare that you will use echolocation to emit ultra-sonic sounds that allow you to navigate in complete darkness. Among other things, echolocation negates concealment up to Medium range (allowing you to Counter-Attack or to Dodge with no penalty). You cannot use echolocation if you cannot hear.\nOther combatants with the Gifts of either Keen Ears or Echolocation will hear your echolocation, if they\'re within Long Range of you. You will have (at best) partial concealment from folks who can hear you.\nFor Observation purposes, echolocation is a \"Listen\" sense.\nEcholocation is a very precise sense; it can determine very fine outlines of targets, in three dimensions, very similar to vision. Unlike sight, echolocation cannot see shades or colors; it can, however, distinguish textures accurately. While it is unsuitable for reading printed or handwritten text, it can be used to read inscriptions, carvings, and letters in raised relief.\nYou may speak all the aspects of the Language of the Night Speech. (However, understanding that language is a separate Gift).', 5, 66, '', 15, 'echolocation', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(85, 1, 85, 'Increased Trait: Body', 1, 0, NULL, 'PASSIVE: Increase Your Body Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\n\n@@LIMIT: Multiple\n@@NOTE: You may take this Gift multiple times, increasing a Trait even further, up to d12.\n\n@@LIMIT: Manifold\n@@NOTE: You may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-body', '2026-03-22 10:39:00', '2026-03-29 08:22:00'),
(86, 1, 86, 'Charging Strike', 0, 0, NULL, 'Action; Next, play out a brawling attack or a melee attack against your target', '@@ACTION: Action \"attack: charging strike\"\nYou have a special move - the charging strike.\nFirst, declare a foe no further than 12 paces away from you.\nThen, roll your Sprint die and move that many paces in a straight line, towards your foe. If you fail to reach your foe, stop there and your attack ends. Otherwise, stop when you reach your target.\nNext, play out a brawling attack or a melee attack against your target.', 5, 50, 'If you fail to reach your foe, stop there and your attack ends', 16, 'charging-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(87, 1, 87, 'Vengeful Fighter', 0, 0, NULL, 'Passive; Counter Attack when Hurt, Injured, or Sick Whenever you are Hurt, Injured, or Sick, you may claim a bonus d12 with all of your Counter-Attacks', '@@PASSIVE: Counter Attack when Hurt, Injured, or Sick\nWhenever you are Hurt, Injured, or Sick, you may claim a bonus d12 with all of your Counter-Attacks. There is no bonus to your Parries, Dodges, or other defenses.', 5, 56, 'Whenever you are Hurt, Injured, or Sick', 14, 'vengeful-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(88, 1, 88, 'Acrobat', 0, 0, NULL, 'PASSIVE: Treat Falling Damage is Weak; ACTION: Make an acrobatic dash; ACTION: Take am extra action  to Stand up; ACTION: You may Retreat While Knocked Down.', '@@ACTION: Action \"acrobatic dash\"\nYou may split your dash up into two smaller dashes. First, dash 1 pace or more in one direction, then move your Stride in any direction, then move 1 pace or more in another direction. Your total movement cannot exceed your Dash plus Stride.\n\nCharacters without the Gift of Acrobat must Dash in a single line. They may only Stride at the beginning or at the end, not in the middle.\n\n@@ACTION: Extra action \"Stand up\"\nOn your turn, you may take an extra action: \"Stand up\".\n\n@@Actions: Retreating While Knocked Down\nYou can Retreat while Knocked Down, by rolling along the ground. \n\nKnocked-Down combatants cannot normally Retreat.\n\n@@PASSIVE: Falling Damage is Weak\nIf you are not helpless or otherwise unable to react, then when you fall you always land on your feet. \n\nTreat Falling Damage as Weak.', 5, 50, '', 16, 'acrobat', '2026-03-22 10:39:00', '2026-03-29 08:14:44'),
(89, 1, 89, 'Increased Trait: Speed', 1, 0, NULL, 'PASSIVE: Increase Your Speed Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\n\n@@LIMIT: Multiple\n@@NOTE: You may take this Gift multiple times, increasing a Trait even further, up to d12.\n\n@@LIMIT: Manifold\n@@NOTE: You may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-speed', '2026-03-22 10:39:00', '2026-03-29 08:22:38'),
(90, 1, 90, 'Night Vision', 0, 0, NULL, 'Passive; See Better in Darkness You can see better in the dark', '@@PASSIVE: See Better in Darkness\nYou can see better in the dark. For spotting and attack purposes, treat poor lighting as fair lighting. Night Vision does not compensate for total darkness (like in a cave) or for being blind.\nYou can travel at night twice as fast as those who don\'t have this Gift. (See \"Hiking\" in the Spot Rules chapter.)', 5, 52, '', 16, 'night-vision', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(91, 1, 91, 'Fast Mover', 0, 0, NULL, 'Passive; Improved Stride, Dash, and Run Your movement increases: Add 1 to your Stride', '@@PASSIVE: Improved Stride, Dash, and Run\nYour movement increases:\nAdd 1 to your Stride. Add 2 to your Dash. Add 6 to your Run. (Note: since Run is based on Dash, your total Run distance will increase by 8.) If you have the Gift of Flight, this Gift improves your Flight movement, too', 5, 74, '', 5, 'fast-mover', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(92, 1, 92, 'Keen Ears', 0, 0, NULL, 'Passive; When using Observation to hear something, you may negate the highest-showing difficulty die that opposes you', '@@PASSIVE: Better Hearing\nYou have better hearing. When using Observation to hear something, you may negate the highest-showing difficulty die that opposes you.\nYou can hear into the ultrasonic range. You can hear some sounds other folks without Keen Ears simply cannot.', 5, 51, 'When using Observation to hear something', 16, 'keen-ears', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(93, 1, 93, 'Howling', 0, 0, NULL, 'Action; Howling is a loud noise, but it lets you claim a Bonus d12 to resist being scared', '@@SECTION: Sound your Barbaric Yawp Over the World\nYou can vocalize a variety of ululations, noises, and growls. You may speak all the aspects of the Language of Baer Sgairnach. (However, understanding that language is a separate Gift).\n\n@@ACTION: Action \"stunt: scare\"\nWhen attempting to scare a target, you may also howl. Howling is a loud noise, but it lets you claim a Bonus d12 on your scare attempt.\n\n@@TRIGGER: you defend against a scare\nWhen someone attempts to scare you, you may howl as a reaction. Howling is a loud noise, but it lets you claim a Bonus d12 to resist being scared.', 5, 65, 'you defend against a scare', 15, 'howling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(94, 1, 94, 'Survival', 0, 0, NULL, 'Passive; Bonus d12 to Live Off the Land When foraging for food or shelter, you may claim a bonus d12', '@@PASSIVE: Bonus d12 to Live Off the Land\nWhen foraging for food or shelter, you may claim a bonus d12.', 5, 60, 'When foraging for food or shelter', 22, 'survival', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(95, 1, 95, 'Keen Nose', 0, 0, NULL, 'Passive; When foraging for food in the wilderness, you may claim an extra d12.\nPassive; When tracking a quarry who you can identify by scent, you may claim an extra d12.', '@@PASSIVE: Better Smelling\nYou have a better sense of smell. When using Observation to smell something, you may negate the highest-showing difficulty die that opposes you.\nWhen tracking a quarry who you can identify by scent, you may claim an extra d12. (See \"Tracking\" in the Spot Rules.)\nWhen foraging for food in the wilderness, you may claim an extra d12.', 5, 51, '', 16, 'keen-nose', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(96, 1, 96, 'Tracking', 0, 0, NULL, 'Passive; Bonus d12 to Follow Trails', '@@PASSIVE: Bonus d12 to Follow Trails\nWhen searching for tracks or when stealthily covering up your own tracks, you may claim a bonus d12.\nSee the Spot Rules for more details on tracking', 5, 56, 'When searching for tracks or when stealthily covering up your own tracks', 14, 'tracking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(97, 1, 97, 'Hiking', 0, 0, NULL, 'Passive; Bonus d12 for long-distance travel You can walk to the ends of the earth', '@@PASSIVE: Bonus d12 for long-distance travel\nYou can walk to the ends of the earth. When making rolls for enduring long-distance travel on foot, you may claim a bonus d12.', 5, 51, '', 16, 'hiking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(98, 1, 98, 'Danger Sense', 0, 0, NULL, 'Passive; Start of battle: \"Rolling Initiative\" You may claim a bonus d12 with all Initiative rolls. Bonus d12 for Danger You are constantly watchful for attackers', '@@TRIGGER: Start of battle: \"Rolling Initiative\"\n\n@@ACTION: You may claim a bonus d12 with all Initiative rolls. Bonus d12 for Danger\n\n@@FLAVOUR: You are constantly watchful for attackers. You may claim a bonus d12 on all rolls to detect danger, including but not limited to observe hidden enemies, to search for deadly traps, and to gossip with locals about which places in town are more dangerous', 5, 73, '', 5, 'danger-sense', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(99, 1, 99, 'Sure-Footed', 0, 0, NULL, 'Passive; Ignore Bad Footing and Terrible Sprints You can run over bad footing with no loss to Dash or Stride', '@@PASSIVE: Ignore Bad Footing and Terrible Sprints\nYou can run over bad footing with no loss to Dash or Stride.\nWhen rolling your Sprint dice, you have favor; you may re-roll one 1.\nYou can travel over rough terrain faster than those who don\'t have this Gift. (See \"Hiking\" in the Spot Rules.)', 5, 53, '', 16, 'sure-footed', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(100, 1, 100, 'Increased Trait: Mind', 1, 0, NULL, 'PASSIVE: Increase Your Mind Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\n\n@@LIMIT: Multiple\n@@NOTE: You may take this Gift multiple times, increasing a Trait even further, up to d12.\n\n@@LIMIT: Manifold\n@@NOTE: You may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-mind', '2026-03-22 10:39:00', '2026-03-29 08:22:22'),
(101, 1, 101, 'Prehensile Tail', 0, 0, NULL, 'PASSIVE: Your tail is particularly strong and dextrous. You can use it as an extra off-hand.', '@@PASSIVE: Grab Things With Your Tail\nYour tail is particularly strong and dextrous. You can use it as an extra off-hand.\nAfter Failing a Climbing roll (or worse), you can make a separate, desparate attempt to grab with your Prehensile Tail. Roll all your Climbing Dice again - the second result stands. If the roll is successful, you are Knocked Down until you can right yourself.\nThe Gift of Ambidexterity allows you to use all Prehensile appendages as if they were your main hand.', 5, 69, '', 15, 'prehensile-tail', '2026-03-22 10:39:00', '2026-03-29 08:47:28'),
(102, 1, 102, 'Contortionist', 0, 0, NULL, 'Action; Retreating without moving You may still Retreat without moving one pace, by contorting your body to move out of the way of the attack', '@@ACTION: Action \"squeeze through tight spaces\"\nYou can fit into spaces other people of your size cannot - the general rule is that if you get your head through the opening, you can get the rest of you through too, given enough time. For really tight spaces, the Game Host may call for rolls of your Speed & Mind Traits vs. your own Body Trait.\n\n@@SECTION: Retreating without moving\nYou may still Retreat without moving one pace, by contorting your body to move out of the way of the attack.\nThe contortionist ability allows you to claim a successful Retreat when Knocked Down, when dodging against Ranged Weapons without Cover, and when grappled.\n\n@@ACTION: Action \"attack: brawling attack to break free\"\nWhen using the Brawling Attack \"Break Free\", you may claim a bonus d12.', 5, 50, '', 16, 'contortionist', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(103, 1, 103, 'Deep Diving', 0, 0, 2, 'Passive; When you are sent Reeling because you cannot breathe, negate that Reeling', '@@PASSIVE: Swimming Dice Resist Suffocation\nInclude your Swimming dice with your Body dice when rolling to see if you suffer suffocation.\nHold Breath 10x as Long\nYou hold your breath for ten times longer than characters without this Gift.\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: when suffocation sends you Reeling\nWhen you are sent Reeling because you cannot breathe, negate that Reeling.', 5, 66, 'when suffocation sends you Reeling', 15, 'deep-diving', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(104, 1, 104, 'Quills', 0, 0, NULL, 'Passive; You may claim an extra d12 to escape from any grapple', '@@PASSIVE: Use Quills as a Brawling Weapon\nYour body is covered in modified hairs that are long, stiff, sharp, and end in barbs. People grappling you are in danger of hurting themselves.\nYou may claim an extra d12 to escape from any grapple.', 5, 69, '', 15, 'quills', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(105, 1, 105, 'Fast Jumper', 0, 0, NULL, 'Improved Action; Improved action \"jump\" For you, jumping is just an action, not a stunt', '@@ACTION: Improved action \"jump\"\nFor you, jumping is just an action, not a stunt. (Other characters are sent Reeling after a \"jump\" stunt.)', 5, 51, '', 16, 'fast-jumper', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(106, 1, 106, 'Ambidexterity', 0, 0, NULL, 'Action; (Characters without this gift suffer a d12 penalty when they attempt to use an off hand as a good hand.) Action: \"draw two weapons\" When you declare a \"draw…', '@@SECTION: All Hands are now Good Hands\nYou may fight with either hand at no penalty. If a weapon lists that it requires a \"Good Hand\", you may use any hand - left or right - at no penalty. (Characters without this gift suffer a d12 penalty when they attempt to use an off hand as a good hand.)\n\n@@ACTION: Action \"draw two weapons\"\nWhen you declare a \"draw weapon\" action, you may draw two one-handed weapons at once. (Characters without this Gift must draw multiple weapons one at a time.)\n\n@@REACTION: bonus d12 to Parry, when using two weapons\nIf you have two weapons ready, you may use both to parry the same attack. Use the parrying dice of the better weapon, and you may claim a bonus d12.', 5, 71, '', 5, 'ambidexterity', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(107, 1, 107, 'Fast Climber', 0, 0, NULL, 'Improved Action; (Other characters are sent Reeling after a \"climb\" stunt.) You can travel over mountainous terrain faster than those who don\'t have this Gift', '@@ACTION: Improved action \"climb\"\nFor you, climbing is just an action, not a stunt. (Other characters are sent Reeling after a \"climb\" stunt.)\nYou can travel over mountainous terrain faster than those who don\'t have this Gift. (See \"Hiking\" in the Spot Rules chapter.)', 5, 50, '', 16, 'fast-climber', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(108, 1, 108, 'Taoist Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \n點 one Mo Kun (鄚錕) Wand, a small stick made with drawn wire\n點 one Tin Rod (the X-ı zhàng, 錫杖), a metal staff with a ring on one end, that holds five more rings that jangle noisily\n點 one Talisman: the Taijitu (数珠), a circle divided in half with contrasting fields.\n點 One robe of the following types: \n    Huáng (黃), yellow for Earth Magic\n    Hóng (紅), red for Fire Magic\n    Baí (白), white for Metal Magic \n    Lán (藍), blue for Water Magic\n    Qian (芊), green for Wood Magic\n    Z-ı (緇), black for all Tàoist Magic\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 4, 514, '', 25, 'taoist-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(109, 1, 109, 'Spray', 0, 0, 2, 'Action; Action \"Stunt: Spray Attack\" You can lift your tail, turn your rear toward your enemy, and release stinging acidic spray in a line behind you', '@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Stunt: Spray Attack\"\nYou can lift your tail, turn your rear toward your enemy, and release stinging acidic spray in a line behind you.\nSpray is a special attack with Medium Range. It uses your Body, Speed & Species vs. your target\'s Speed & Dodge. (Cover Dice applies normally.)\nIf you hit, the base effect is Blinded 3, Stench, and Sweep Short.\nCharacters affected by Stench cannot use Keen Nose and have a penalty d12 to avoid detection. The Stench must be washed off, using special cleaners (not just water).\nThe Spray attack is a stunt, so afterwards, you are sent Reeling.', 5, 69, '', 15, 'spray', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(110, 1, 110, 'Performance: [Choice]', 0, 1, NULL, 'Passive; Bonus d12 for Entertaining the Masses Whenever you assert your presence on stage with your performance of choice, or to know the academic particulars of your…', '@@PASSIVE: Bonus d12 for Entertaining the Masses\nWhenever you assert your presence on stage with your performance of choice, or to know the academic particulars of your craft, you may claim a bonus d12. You may also claim the bonus d12 when you \"deceive\" others in how well you\'ve immersed yourself in your acting role.\nManifold\nYou may take this gift multiple times. Each time, you may choose a different type of performance.\nSample Choices for Performance\nActor; Clown; Dancer; Drummer; Flautist; Guitarist; Keyboardist; Juggler; Raconteur; Singer;\nTrumpeter; Xylophonist', 5, 59, '', 22, 'performance-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(111, 1, 111, 'Springing Strike', 0, 0, NULL, 'Action; First, declare a brawling attack or a melee attack against a target', '@@ACTION: Action \"melee attack (springing strike)\"\nYou have a special attack - the Springing Strike.\nFirst, declare a brawling attack or a melee attack against a target. If you tie or lose the attack, play out the effects as normal - the springing strike has no additional effects\nIf you win the attack, play out the effects as normal, and then immediately roll your Sprint Dice. You must move that many paces, directly away from your target, in a straight line.\n\n@@NOTE:\nSince you may voluntarily lower your Speed, you may declare you will roll a smaller die. For example, if your Sprint die is d8, you may declare that your springing strike will use a d6 or a d4.\nUnlike a true sprint, you must move exactly that many paces away from your melee attack\'s target - you can\'t modify the distance with your Stride.\nYes, you may press the attack and then spring away', 5, 53, '', 16, 'springing-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(112, 1, 112, 'Foolery', 0, 0, 1, 'Passive; Exhaust; You may taunt even if this Gift is exhausted', '@@PASSIVE: You\'ve often been called a fool ... but when you have this Gift, yo certifably are one!\n\n@@SECTION: New stunt \"Taunt\"\n\n@@SECTION: As a stunt, you may Taunt another target. Your character insults the target, or performs rude gestures, or generally does something to the target to make them angry with you. You may taunt even if this Gift is exhausted.\n\n@@SECTION: Taunting does not require you to have your mental faculties. You can Taunt even when Confused or Enraged.\n\n@@SECTION: Roll your own Mind, Will, and Presence dice. The target rolls their Will, Inquiry, and your Body Dice. (That\'s right - bigger people have less effective taunts, because the target is more likely to be scared than taunted.)\n\n@@FLAVOUR:\nThe target must be able to hear you. You can\'t be Silenced, the target can\'t be Asleep or Unconscious, etc.\n\n@@SECTION: Range penalties apply, but use the Cover and Concealment on yourself, not the target. (Taunting works better if you\'re out in the open.)\n\n@@SECTION: \"Scare, Trick, or Taunt Stunt\" Negate Reeling\n\n@@TRIGGER: Whenever you take the \"Scare\", \"Trick\", or your special \"Taunt\" stunt, you may Exhaust this Gift. You are not sent Reeling by the stunt.\n\n@@FLAVOUR:\nThe Stunt still ends your turn, as usual, but at least you\'re not Reeling.', 2, 354, '\"Scare, Trick, or Taunt Stunt\" Negate Reeling', 10, 'foolery', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(113, 1, 113, 'Fool\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@FLAVOUR: Sure, anyone who dresses like you looks ridiculous, but a real fool will properly accossorize.\n\n@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \nAn Expensive motley outfit in bright colors.\nAn Expensive hideous mask, with either a contorted grin or a horrible frown.\nAn Expensive floppy three-pointed hat, with jingling bells on each point.\nAn Average-cost, Rare marotte, a small stick with a head carved on it.\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 2, 355, '', 25, 'fools-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(114, 1, 114, 'Healing', 0, 0, 5, 'Passive; Requires Literacy Cleric\'s Trappings (any) White Magic Apprentice After successfully rallying one of your allies, you may invoke the spell of Healing', '@@PASSIVE: Sometimes, the inspirational rally of the cleric\'s word isn\'t enough.\nRequires\nLiteracy\nCleric\'s Trappings (any)\nWhite Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@TRIGGER: successful rally\nAfter successfully rallying one of your allies, you may invoke the spell of Healing.\nYour target be conscious and able to understand you. Confused or Enraged targets will not be able to consent. If your target does not consent, the Healing fails and your Gift is Exhausted.\nRoll the target\'s Will and your Academics dice. (Keep the target\'s and your dice separate.) Contest your roll against 2d8.\n1. If you score one Success, remove the Hurt status from the target.\n2. If you score two Successes, remove the Injured status from the target.\n3. If you score three Successes, remove the Sick status from the target.\nIf you Tie, nothing happens.\nIf you Fail, it matters who rolled what. If the target rolled the lowest, they become Asleep. If you rolled the lowest, you become Afraid. If you both tied for lowest, then you both suffer!\nThis Gift can only be refreshed by praying for 8 minutes during the Office of Tierce (9 am to noon).', 5, 306, 'successful rally', NULL, 'healing', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(115, 1, 115, 'Abjure Monster', 0, 0, NULL, 'PASSIVE: Add +1 Mark to your Supernatural Skill; ACTION: Cast the spell \"Abjure Monster\".', '@@PASSIVE: Add +1 Mark to Supernatural\nAdd 1 Mark to your Supernatural Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@ACTION: Special action \"abjure monster\"\nTap this gift, and then roll your Will, Supernatural, and bonus d12 from Mystic: Tawas.\nEach 4 or better that you roll is one success.\n\nYou can then choose one and only one result from the table below, one that you have enough successes to obtain.\n(If you scored 2 successes, you can choose any 2-, 1-, or none-success result, and not any result of 3 or higher.)\n\nIf you choose a result that\'s too weak (say, you choose to immobilize Typicals when your foes are Elites), then you wasted your magical effort.\nWhat if you don\'t know the strength of the monsters that you are trying to abjure? Part of being an effective Antiñgero is to do some research before you encounter the monsters face to face. Choose wisely.\n\nRemember that many lesser undead may be in the company of enablers. Greater undead (such as powerful aswangs) may be able to rally their minions or negotiate with them to remove the bad statuses. And any necromancer can make undead become Berserk, though when they add Berserk to an Afraid, Terrified, or Immobilized undead, the Berserk is instantly cancelled and those bad statuses are removed. You should deal with bosses before you abjure the minions.\n\n@@TABLE: Banish the Supernatural\nWill, Supernatural, Mystic\'s d12 ≥4 | Choose one result\nNo successes | No effect, but your gift of \"Banish Monster\" can be recharged with a \"recharge\" action.\n1 success or more | One Typical supernatural creature (no trait higher than d6) that is Near you (within 4m) becomes Terrified. You can recharge this gift with a \"recharge\" action.\n2 successes or more | All Typical supernatural creatures (no trait higher than d6) that are Near you (within 4m) become Afraid and Immobilized; all Typical supernatural creatures within Short range (12m) become Afraid. You can recharge this gift at the start of the next scene.\n3 successes or more | One Elite supernatural creature (no trait higher than d8) that is Near you (within 4m) becomes Afraid. You can recharge this gift with a \"recharge\" action. Or, you can choose that all Typical supernatural creatures (no trait higher than d6) become Terrified. You can recharge this gift at your next respite.\n4 successes or more | All Elite supernatural creatures (no trait higher than d8) that are Near you (within 4m) become Afraid and Immobilized; all Elite supernatural creatures within Short range (12m) become Afraid. You can recharge this gift at the start of the next scene.\n5 successes or more | One supernatural creature (of any strength) that is Near you (within 4m) becomes Afraid and Immobilized. You can recharge this gift at your next respite. Or, you can choose that all Elite supernatural creatures (no trait higher than d8) become Terrified. You can recharge this gift at your next respite.\n6 successes or more | One supernatural creature (of any strength) that is Near you (within 4m) becomes Terrified. You can recharge this gift at the start of the next chapter.', 1, 915, '', 12, 'abjure-monster', '2026-03-22 10:39:00', '2026-03-29 08:14:59');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(116, 1, 116, 'Absolution', 0, 0, 5, 'ACTION: Cast the spell \"Absolution\"  to remove a status from a living target.', '@@FLAVOUR:\nThe Almoners of the priesthood use this spell to remove the suffering of the sick, the mad, and the ensorcelled.\n\n@@STUNT: \"Absolution\"\n\nUse this spell to remove a status from a living target. This spell is very useful for targets who have botched their resistance rolls and are permanently afflicted.\n\nRoll the target\'s Will and your Supernatural dice. (Keep the target\'s and your dice separate.) Compare your roll as a contest against 3d12.\n\nIf you Succeed, the affliction is removed.\n\nIf you Tie, the affliction is removed, but you also suffer for Failure, as below.\n\nIf you Fail, something bad happens to you, the target, or both. If the target\'s dice rolled lowest, then their condition either gets worse (for example, Afraid might turn into Terrified, or Slowed might turn into Immobilized), or they suffer a new affliction. If your dice rolled the lowest, then you suffer, either what the target has, or something else.\n\nThis Gift can only be refreshed by praying for 8 minutes during the Office of Prime (6 am to 9 am).', 5, 303, '', 12, 'absolution', '2026-03-22 10:39:00', '2026-03-29 08:09:00'),
(117, 1, 117, 'Aegir', 0, 0, 2, 'ACTION: Cast the spell Aegir and Draw forth and ready a \"Aegir\" weapon.', '@@FLAVOUR: In the rocky north, the waves smack into the coast shooting water with violent force. This spell does the same thing, only the water flies from your hand and strikes a foe.\n\n@@ACTION: Action \"ready Aegir\"\nExhaust this Gift, then use the ready action to draw forth a \"Aegir\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 295, '', 12, 'aegir', '2026-03-22 10:39:00', '2026-03-29 08:16:09'),
(118, 1, 118, 'Aiming on The Draw', 0, 0, NULL, 'Take an \"Aim\" action with the weapon you just reloaded or readied', '@@ACTION: Combo \"ready ranged weapon and aim\", Combo \"reload ranged weapon and aim\"\n\nYou have two new combination actions. When readying a ranged weapon, or when reloading a ranged weapon, you may also take an \"Aim\" action with the weapon you just reloaded or readied.\n\nAiming-on-the-draw only works with Ranged Weapons, and not with any other kind of weapon.', 5, 79, '', 3, 'aiming-on-the-draw', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(119, 1, 119, 'Air Clout', 1, 0, 3, 'PASSIVE: Add 1 Mark to your Weather Sense Skill; ACTION: Claim a bonus 2d8 when casting a spell of the Air nature.', '@@FLAVOUR: The greatest wizards can increase the power of a spell, even after it has been cast.\n\n\n@@PASSIVE: Add +1 Mark to Weather Sense\nAdd 1 Mark to your Weather Sense Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@ACTION: Casting a Air Spell\nExhaust this Gift after casting a spell of the Air nature to claim a bonus 2d8 with your casting dice.\n\n@@LIMIT: Multiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 287, 'Casting a Air Spell', 12, 'air-clout', '2026-03-22 10:39:00', '2026-03-29 08:19:13'),
(120, 1, 120, 'Air Mnemonic', 0, 0, 3, 'Passive; Add +1 Mark to Weather Sense Add 1 Mark to your Weather Sense Skill', '@@FLAVOUR:\nYour meditative training allows you to call upon reserves of power.\n\n@@REQUIRES: Any two Gifts which have both the \"Air\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@TRAPPINGS: Any magical Talisman from any Trappings Gift\n\n@@PASSIVE: Add +1 Mark to Weather Sense\nAdd 1 Mark to your Weather Sense Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh all Air Battle Gifts and Air Respite Gifts\"\nOn your turn, as an extra action, you may put your off-hand upon your magical talisman, and in a loud voice, you declare your command over all Air. By doing so, you immediately refresh all exhausted gifts that have both the \"Air\" descriptor and either the \"Battle\" or the \"Respite\" descriptor. Other Gifts are not refreshed.\nIf you do not have a magical talisman to brandish forth, you cannot use this ability', 5, 287, '', 12, 'air-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(121, 1, 121, 'Akhal-Teke Wrangler', 0, 0, NULL, 'Passive; Spend a lot of time on dry land often invest in this Gift; It now has a Mind Trait of d4 and may be designated as the beneficiary of the Improved Ally Gift', '@@PASSIVE: This is the stuff of which epic poems are made.  This variant of the Ally Gift (Ironclaw p. 70) introduces a special kind of companion. Octopodes who spend a lot of time on dry land often invest in this Gift.\n\n@@SECTION: Steed\nYour character has an Akhal-Teke as a full-fledged minor character. It now has a Mind Trait of d4 and may be designated as the beneficiary of the Improved Ally Gift. It can\'t speak, but it can communicate with you (and only you) in some idiosyncratic way.\n\n@@SECTION: You and the Game Host should negotiate who is responsible for your mount\'s actions. We assume that you, the player, will decide what the mount does in combat, but you may prefer to have the Game Host or another player decide what it does so that you don\'t feel like you\'re talking to yourself.', 3, 746, '', 22, 'akhal-teke-wrangler', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(122, 1, 122, 'Akimbo Fighter', 0, 0, NULL, 'Passive; Akimbo Fighter grants the following benefits while fighting with two weapons.', '@@REQUIRES: Ambidexterity\n\n@@REQUIRES: Akimbo Attack, Counter, Parry with Favor\n\n@@REQUIRES: When you fight with two weapons, you may claim favor. Your attacks, counters, and parries may re-roll one die that comes up 1.\n\n@@REQUIRES: Akimbo Threatens when Reeling\n\n@@REQUIRES: When you are Reeling, and if you are fighting with two weapons, you may still threaten.\n\n@@REQUIRES: Any attackers may claim the bonus d8 to hit you, but you may still Counter.\n\n@@REQUIRES: Akimbo Breaks Ties on Parries\n\n@@REQUIRES: If you Parry, while using two weapons, any ties break in your favor. You may only claim the tie-breaking bonus on Parries, not on Counters or other defenses, and only when you Parry using two weapons.', 5, 71, '', 5, 'akimbo-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(123, 1, 123, 'Alchemy', 0, 0, 2, 'TRAPPINGS: Start with special list of equipment.', '@@SECTION: Belongings\nYou begin the game with:\nOne alchemy kit\n6 bottles of Aqua Fortis\n6 bottles of Aqua Vitae\n12 bottles of medicine (quack)\n6 bottles of medicine (good)\n\n@@REFRESH: X (Respite)\n\n@@SECTION: You may craft alchemy items faster\n\n@@SECTION: First, you must spend 12 denarii on \"essential salts\", the materials known only to you. Ask the Game Host if you\'re able to buy these expensive materials in the location that you\'re at. (At the discretion of the game host, you may be able to spend days foraging for these in the appropriate places, rolling Mind & Searching vs. 3. ... but these materials are rare and obviously valuable, so they\'re not usually found lying around on un-owned land.)\n\n@@SECTION: Then, tap this gift, spend an hour with your kit, and roll your Mind, Academics, Craft vs. 3. (If you have Chemistry, that\'s another d12).\n\n@@FLAVOUR:\nFor each success you score, you may choose one:\n1 bottle of Aqua Fortis\n1 bottle of Aqua Vitae\n2 bottles of Quack Medicine and 1 bottle of Good Medicine.\n\n@@SECTION:\nIf you have multiple successes, you can mix and match. (For example, you could use 5 successes to make 2 bottles of Aqua Vitae, 1 bottle of Aqua Fortis, 4 bottles of Quack Medicine and 2 bottles of Good Medicine.)', 3, 747, '', NULL, 'alchemy', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(124, 1, 124, 'All Fours', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Fast Mover\n\n@@REQUIRES: Faster Ground Movement\n\n@@REQUIRES: You can run on your hands and feet. Your hands must be completely empty.\n\n@@REQUIRES: While running on all fours, your Stride increases by 1, your Dash increases by 2, and your Run increases by 6. (Since Run is based on Dash, this means your Run increases by 8.) Yes, these bonuses are cumulative with the ones from Fast Mover.', 5, 317, '', 2, 'all-fours', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(125, 1, 125, 'All-out Attack', 0, 0, 1, 'Passive; Exhaust; After playing out one successful attack, you may Exhaust this Gift to launch a second strike', '@@REQUIRES: Counter-Tactics\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: any successful attack Action: \"stunt - second strike\"\nAfter playing out one successful attack, you may Exhaust this Gift to launch a second strike.\nA second strike may only be a simple Brawling Attack or a simple Melee Attack. Other attacks are not permitted - no Ranged Attacks, Magic Attacks, bizarre attacks provided by strange Gifts, etc.\nJust like any stunt, after playing out the second strike, you are sent Reeling and your turn ends.\nAll-Out Attack\'s second strike is an action, so you will have to have an action left this turn, to do it', 5, 72, 'any successful attack Action: \"stunt - second strike\"', 5, 'all-out-attack', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(126, 1, 126, 'Ally: [Choice]', 0, 0, NULL, 'Passive; Or maybe your ally is a childhood friend who tags along on your adventures', '@@PASSIVE: Ally: Name, Career, Species\nYou have a trusted ally, another character in the game who has your best interests in mind. Your ally could be a brother, sister, cousin, or other relative. Or maybe your ally is a childhood friend who tags along on your adventures. In some cases, an ally could be a trusted servant, or maybe a bonded villain who owes you a debt of honor.\nAn ally is a Minor Character. Your ally has d6s in all Traits. Naturally, your ally has a Species and Career, and all the appropriate Gifts that go with them. Allies also start with a Gift of a Langage that you understand. Allies have no extra Marks in Skills, and they just have the seven Gifts they start the game with. (No Local Knowledge for Allies!)\nAllies do not earn Experience - if you want your Ally to get better, you have to take the Gift of \"Improved Ally\".\nLike most Minor Characters, your ally is normally controlled by the Game Host. However, in some cases, the Host may let you control the ally. (For example, if the party gets split into two groups, your main character may go with one group, and your ally may go with the other. If the ally\'s party runs into trouble, the Host may let you declare what the ally does.)\nAn ally always has your character\'s best interests in mind. They will not betray your main character, unless they are somehow tricked into doing so, or unless they are convinced that a minor betrayal will somehow spare them from a worse fate.', 5, 70, '', 17, 'ally-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(127, 1, 127, 'Animal Magnetism', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Bonus d12 Among Your Own Species\n\n@@REQUIRES: Whenever you use Gossip, Inquiry, Leadership, Negotiation, or Presence to interact with someone of your own Species, you may claim a bonus d12.', 5, 317, '', 2, 'animal-magnetism', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(128, 1, 128, 'Animation', 0, 0, 1, 'Passive', '@@REQUIRES: Literacy\n\n@@REQUIRES: Necromancer\'s Trappings\n\n@@REQUIRES: Apprentice Necromancy\n\n@@PASSIVE: X (Battle) Action \"Rally a corpse into a Marionette\"\nDeclare any dead body within 9 paces of you. The body must not have been Overkilled.\nRoll your Will, Leadership, & 2d6 vs. 3d6. If you are successful, the corpse becomes a Hurt, Injured Marionette under your control. If the body is still fresh, treat it as a Typical Zombie; if the body is nothing but bones, treat it as a Typical Skeleton. (You may also use your ability to unleash undead to turn the animated corpse into a Berserk monsters - in which case, you no longer control it.)\nAfter five minutes, the body returns to lifelessness.', 5, 313, '', 12, 'animation', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(129, 1, 129, 'Anonymous', 0, 0, 5, 'Passive; Exhaust; You cannot tell anyone any name to use for you without exhausting this Gift', '@@FLAVOUR:\nYou have forsaken your own name, to prevent others from using it to claim power over you.\n\n@@REQUIRES: Permission from the Game Host No Influence Gifts.\n\n@@FLAVOUR: Character Development\n\n@@SECTIONS: You have no name. If you are just starting the game, write \"Anonymous\" in the blank on your character sheet. If you had a name, you renounce it - replace it with \"Anonymous\".\n\n@@SECTION: Because you have no name, and no standing in society, you cannot have any Influence Gifts.\n\n@@SECTION: +1 Mark in Supernatural\n\n@@SECTION: You may claim +1 Mark in Supernatural Skill.\n\n@@REFRESH: X (Special)\n\n@@TRIGGER: saying your own name\nIf you tell someone your name, exhaust this Gift. You cannot tell anyone any name to use for you without exhausting this Gift. Other people may assign you a name, such as \"The Nameless One\" or \"Rump-\nFed Mooncalf\", and it\'s okay if you agree to respond to the name. But if you ever speak a name for yourself, exhaust this Gift.\nThis Gift refreshes after you spend 24 hours without any contact whatsoever with any persons who heard you speak your name, and after any names you wrote down for yourself have been erased or destroyed.\nWhen unexhausted, benefits to defense\nWhile this Gift is unexhausted, you may claim the following benefits:\nYou may claim a bonus d12 to defend against any Magic attack.\nYou are never the \"lowest roller\". If you are hit by any attack that has something special happen to the lowest roller, and you happened to be lowest roller, the effect does not happen to you. The \"lowest-roller\" effect happens to the second-lowest roller, or someone who tied with you, etc. (If there isn\'t any candidate for lowest- roller - maybe you were the only in the scope, maybe you\'re the only one who failed to resist, etc. - then the \"lowest roller\" effect is completely negated.) If you failed to resist the effect, you still suffer normally ... just not as bad as the lowest-roller would.', 5, 84, 'saying your own name', 12, 'anonymous', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(130, 1, 130, 'Antiñgero Apprentice', 0, 0, 1, 'Reaction; You and any allies Near you (within 4 paces) gain good Cover (bonus d8 to Parry and Dodge)', '@@TRIGGER: when guarding\n\n@@REACTION: \"supernatural light\"\n\n@@REACTION: Whenever you have the Guarding status, you may call forth a su pernatural light. Everything Near you (within 4 paces) is illuminated as per daylight, although no one can clearly see where the light is coming from.\n\n@@SECTION: This light is supernatural, and it does not travel further than 4 paces from you. Supernatural light totally negates supernatural darkness in its area of effect.\n\n@@ACTION: Action \"guard with tagaliwas\"\n\n@@SECTION:\nWhen you take the \"Guard\" action, you may call forth a supernatural shield, known as the tagaliwas.\n\n@@SECTION: You and any allies Near you (within 4 paces) gain good Cover (bonus d8 to Parry and Dodge). Allies within Short Range (12 paces) gain minor cover (bonus d4 with Parry and Dodge).\n\n@@SECTION: You must be able to see an ally to grant them the supernatural Cover. The cover only lasts as long as you Guard.\n\n@@FLAVOUR:\nThe tagaliwas is invisible, but still protects the wizard from harm. Antiñgeros often use this spell as a magic umbrella, to keep the rain off their heads.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready magic weapon\"\n\n@@FLAVOUR:\nYour Gift allows you to ready the following magical weapons:\nGendam\nTenung', 1, 916, 'when guarding', 12, 'antigero-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(131, 1, 131, 'Antiñgero Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Pedalaman Robe\none Teak Rod\none Alum Wand\none Talisman: the Agimat,\na necklace made of a pure elemental metal.\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 1, 916, '', 25, 'antigero-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(132, 1, 132, 'Apprentice Necromancy', 0, 0, 1, 'Passive; Exhaust; Until the end of the Scene; Stunt \"unleash undead\" As a stunt, you may declare a Group of Undead targets, then roll your Will & Deceit, as a Group attack', '@@REQUIRES: Literacy\n\n@@REQUIRES: Necromancer\'s Trappings\n\n@@STUNT: \"Scare\"\n\n@@PASSIVE: Whenever you declare a \"Scare\" stunt, you may invoke black magic to assist you with unearthly moans, horrible smells, or other unholy effects. You must claim a bonus 3d6 with your roll.\nIf you use this unholy magic to successfully scare a Dying target... the target instantly becomes Dead. The target need not be conscious to suffer your magic.\n\n@@STUNT: \"unleash undead\"\nAs a stunt, you may declare a Group of Undead targets, then roll your Will & Deceit, as a Group attack. All Undead targets in the Group become Berserk.\nBerserk Undead are no longer under anyone\'s control - yours or anyone else\'s.\n\n@@PASSIVE: X (Battle) Action \"ready Unholy weapon\"\nExhaust this Gift, then use the ready action to draw forth an Unholy weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nUnholy weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nHorror\nIllness\nTorment', 5, 312, '', 12, 'apprentice-necromancy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(133, 1, 133, 'Armored Fighter', 0, 0, NULL, 'Passive', '@@REQUIRES: Resolve\n\n@@PASSIVE: Increased Armor Dice\n\n@@SECTION: Your Armor Dice increase by one size. For example, if your Armor Dice were d10, d6, they are now d12, d8.\n\n@@SECTION: Your Soak Dice are unaffected', 5, 78, '', 5, 'armored-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(134, 1, 134, 'Artful Dodger', 0, 0, NULL, 'Passive; Add Body dice to Sprint distance After playing out a Sprint, for any reason, declare than Short, you may claim a d12 concealment bonus with your Dodge (and…', '@@REQUIRES: Fast Mover\n\n@@TRIGGER: you are attacked at Medium Range\nYou can move out of harm\'s way with blinding speed. When someone attacks you at any range greater than Short, you may claim a d12 concealment bonus with your Dodge (and only with your Dodge).', 5, 74, 'you are attacked at Medium Range', 5, 'artful-dodger', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(135, 1, 135, 'Artillerist', 0, 0, NULL, 'Passive; With artillery, claim Ranged Dice as bonus attack dice When you attack using an artillery weapon, you may include the Range penalty dice as bonus attack dice', '@@PASSIVE: With long experience, keen senses, and just a little intuition, you can calculate the trajectory of seige-scale powder weapons.\n\n@@SECTION: With artillery, claim Ranged Dice as bonus attack dice When you attack using an artillery weapon, you may include the Range penalty dice as bonus attack dice.\n\n@@SECTION: (The target still gets their Ranged Dice as bonus dodge dice, too. More dice all around!)\n\n@@SECTION: Artillery weapons are equipment that has the \"Artillery\" descriptor.', 3, 476, '', 14, 'artillerist', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(136, 1, 136, 'Austringer', 0, 0, 3, 'Passive; When your pet is Close to you, it grants you a bonus d8 to initiative and to Observation', '@@FLAVOUR:\nYou have a small flying reptile, called a sahin, as a pet and helper. It helps you to hunt or fish for food.\n\n@@FLAVOUR:\nYou have a cute little pet. Your pet is small enough to ride in your pocket, or in a special pouch. Your pet can also fly.\n\n@@SECTION:\nWhen your pet is Close to you, it grants you a bonus d8 to initiative and to Observation.\n\n@@FLAVOUR:\nYou can use a Control action to order your pet to take certain actions. Your pet can fetch items, pull levers, push buttons, or do other things a pet could do. (Without any hands or a sentient Mind, the pet is somewhat limited. The host may call for rolls of your Will & Tactics dice to order the pet to do things that are more complex.)\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: your pet suffers a Dying or Dead result If your pet suffers a Dying or Dead result, you may exhaust this gift to reduce that result to Sick and Unconscious. If your pet suffers an Overkill result, you may exhaust this gift to reduce that result to Dying & Sick.', 3, 746, 'your pet suffers a Dying or Dead result If your pet suffers a Dying or Dead result, you may exhaust this gift to reduce that result to Sick and Unconscious. If your pet suffers an Overkill result, you may exhaust this gift to reduce that result to Dying & Sick.', 22, 'austringer', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(137, 1, 137, 'Back in the Saddle', 0, 0, NULL, 'Passive; You still have to fight as if you\'re both Reeling, but maybe this edge case will help in case of spells that only hit people who are Reeling or something', '@@PASSIVE: Mount and Dismount with Ease\n\n@@SECTION:\nWhen you mount or dismount, you\'re not sent Reeling.\n\n@@SECTION: Doubling Up on Reeling\n\n@@SECTION:\nIf one of you or your mount is sent Reeling, the other isn\'t automatically. You still have to fight as if you\'re both Reeling, but maybe this edge case will help in case of spells that only hit people who are Reeling or something.', 3, 745, '', 16, 'back-in-the-saddle', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(138, 1, 138, 'Battering Charge', 0, 0, 1, 'Action; Anyone and everyone, friend or foe, within 1 pace of that path, must defend against your battering charge attack dice', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Charging Strike\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"brawling attack: battering charge\"\nYou have a special move - the battering charge attack.\nFirst, declare a line, no more than 12 paces long.\nThis will be the path of your battering charge. This line should go through, or within 1 pace of, other combatants that you want to use your battering charge against.\nRoll your Body, Speed, and Brawling Dice. These are your battering charge attack dice.\nFind the highest showing die. You immediately move exactly that many paces, along the path.\nAnyone and everyone, friend or foe, within 1 pace of that path, must defend against your battering charge attack dice. Anyone who fails to defend suffers Damage\n+2 and is Pushed 1 pace away from the line.\nIf you are prevented from travelling the full distance of your battering charge, for any reason, you stop where you are and immediately become Reeling and Hurt', 5, 317, '', 3, 'battering-charge', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(139, 1, 139, 'Benediction', 0, 0, 5, 'Passive; Exhaust; The prayer can be any phrase you want, but most Clerics choose an appropriate one, such as, \"Helloise, save me!\" If the target does not accurately repeat the…', '@@PASSIVE: Requires\nLiteracy\nCleric\'s Trappings (any) White Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Benediction\"\nChoose any Magical Gift that you know, that has a Refresh of either \"X (Battle)\" or \"X (Respite)\". Now choose a target within Medium Range, and have them recite a prayer with you. The prayer can be any phrase you want, but most Clerics choose an appropriate one, such as, \"Helloise, save me!\"\nIf the target does not accurately repeat the prayer back to you - that is, if they resist this spell - Exhaust this Gift, and your spell fails. Targets that cannot speak coherently, such as Confused targets, may not repeat the prayer.\nIf the target accepts your Benediction, exhaust this Gift. The target of your Benediction is instantly rallied - remove any Reeling or Afraid effects on the target.\nSometime in the future, the target may call upon the spell that you declared, as a stunt. The target must turn to the heavens and recite the prayer you just told them, word for word, and then allow the Benediction to draw upon their personal faith.\nThe game effect is as if the target was the caster of the spell you just declared. Use the target\'s dice for any rolls. Popular gifts for the Benediction include the White Magic Apprentice and Flesh Ward.\nRegardless of the Gift you use for your Benediction, the target gets one and only one use of the Magic Gift. Whether they succeed or not, the Benediction ends after they perform the stunt and recite the prayer.\nEven though this is a White Magic spell, you may use the Benediction with any \"X (Battle)\" or \"X (Respite)\" Gift, provided that Gift has the \"Magic\" descriptor.\nThis Gift can only be refreshed by praying for 8 minutes during the Office of Lauds (3 am to 6 am). Once this Gift is refreshed, any and all of your Benedictions expire.', 5, 305, '', 12, 'benediction', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(140, 1, 140, 'Blessed Way', 0, 0, NULL, 'Passive; Bonus d8 when working with animals When working with animals (natural creatures with no Mind Trait), you may claim a bonus d8 to all rolls', '@@FLAVOUR:\nYou can talk to the spirits.\n\n@@PASSIVE: Bonus d8 when working with animals\nWhen working with animals (natural creatures with no Mind Trait), you may claim a bonus d8 to all rolls.\n\n@@PASSIVE: Bonus d8 when working with live plants\nWhen identifying, growing, or nurturing live plants, you may claim a bonus d8 to all rolls. It is considered good practice to ask permission before cutting or reaping a live plant.\n\n@@PASSIVE: Bonus d8 to talk with supernatural creatures\nYour communion with the other worlds grants you the ability to talk to any supernatural creature: elemental, undead, shade, etc. When inquiring about their motives, negotiating their wants and desires, or imposing your presence upon them, you may claim a bonus d8.\n\n@@SECTION: However, not only is there no bonus to deceive a supernatural creature, you also have a d12 penalty. They know you.', 3, 748, '', 12, 'blessed-way', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(141, 1, 141, 'Bind Salamander', 0, 0, 5, 'Action; If the elemental is healthy, you may Refresh this Gift at your next cycle', '@@SECTION: Once you have asserted your dominion over an elemental, the creature is bound to serve you\n\n@@REQUIRES: Any two Gifts which have both the \"Fire\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Elementalist\'s Trappings: Red\n\n@@REQUIRES: Successfully finding a Salamander and winning a contest to bind it\n\n@@REQUIRES: Character Development\nWinning a contest of your Will & Leadership vs. the elemental\'s Will & Salamander Trait\nIn order to buy this Gift, you must first successfully confront a Salamander, strongly present your Obsidian Charm, and then roll a contest of your Will & Leadership die vs. the elemental\'s Will & Salamander Trait. If you are successful, the Salamander is bound to you, dormant inside your Talisman. If you tie the contest, or worse, you may not try again until you buy at least one more Mark in Presence Skill.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"Rally to call forth a Fire Elemental\"\nDeclare a Rally action, and then bring your Obsidian Charm forth. The dormant Salamander appears in any appropriate spot Near you.\nThe elemental is a character under the control of the Game Host. It acts after you take your turn in the sequence. You will have to use the Rally action to give it orders (although that action also counts as a Rally).\nIf the elemental is Near you, you may order it back into your charm, with a Rally action. If the elemental is healthy, you may Refresh this Gift at your next cycle. If the elemental is Hurt, Injured, Sick, etc., then you may not Refresh this Gift until the elemental has healed over time, at the normal rate. Dormancy is the best rest possible - it counts as a nice bed and a square meal.\nIf not rebound, then after eight hours of being released, and each full hour thereafter, roll your Will die. If you roll a 1, the Salamander becomes unbound. You will have to bind it again, by winning the contest, as above. (You may also have to track it down, for it will find someplace else to become dormant.)', 5, 292, '', 12, 'bind-salamander', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(142, 1, 142, 'Bind Shade', 0, 0, 5, 'Action; Exhaust; If you tie the contest, or worse, you may not try again with the same shade until the Shade has not seen you for more than 101 hours', '@@REQUIRES: Any two Gifts which have both the \"Psychic\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Cognoscenti Magic Magic Insider: Cognoscente\n\n@@REQUIRES: Successfully finding a Shade and winning a contest to bind it\n\n@@REQUIRES: Character Development\nWinning a contest of your Mind & Will vs. the shade\'s Mind, Will, & Shade Traits\nIn order to buy this Gift, you must first successfully confront a Shade, strongly present your Tourmaline Headband, and then roll a contest of your Mind & Will dice vs. the shade\'s Mind, Will, and Shade Traits. If you are successful, the Shade is bound to you, dormant inside your Headband.\nIf you tie the contest, or worse, you may not try again with the same shade until the Shade has not seen you for more than 101 hours.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"Rally to call forth a Shade\"\nDeclare a Rally action, while you are wearing your Tourmaline Headband, and then Exhaust this Gift. The dormant Shade appears in any appropriate spot Near you.\nThe Shade is a character under the control of the Game Host. It acts after you take your turn in the sequence. You will have to use the Rally action to give it orders (although that action also counts as a Rally).\nIf the Shade is Near you, you may order the Shade back into your headband, with a Rally action. If the Shade is healthy, you may Refresh this Gift at your next cycle. If the shade is Hurt, Injured, Sick, etc., then you may not Refresh this Gift until the Shade has healed over time, at the normal rate. Dormancy is the best rest possible - it counts as a nice bed and a square meal.\nIf not rebound, then after eight hours of being released, and each full hour thereafter, roll your Mind die. If you roll a 1, the Shade becomes unbound. You will have to bind it again, by winning the contest, as above. (You may also have to track it down, for it will find someplace else to become dormant.)', 5, 300, '', 12, 'bind-shade', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(143, 1, 143, 'Bind Sylph', 0, 0, 5, 'Action; If you tie the contest, or worse, you may not try again until you buy at least one more Mark in Weather Sense Skill', '@@SECTION: Once you have asserted your dominion over an elemental, the creature is bound to serve you.\n\n@@REQUIRES: Any two Gifts which have both the \"Air\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Elementalist\'s Trappings: Yellow\n\n@@REQUIRES: Successfully finding a Sylph and winning a contest to bind it\n\n@@REQUIRES: Character Development\nWinning a contest of your Speed & Leadership vs. the elemental\'s Speed & Sylph Trait\nIn order to buy this Gift, you must first successfully confront a Sylph, strongly present your Sapphire Charm, and then roll a contest of your Speed & Leadership die vs. the elemental\'s Speed & Sylph Trait. If you are successful, the Sylph is bound to you, dormant inside your Talisman.\nIf you tie the contest, or worse, you may not try again until you buy at least one more Mark in Weather Sense Skill.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"Rally to call forth an Air Elemental\"\nDeclare a Rally action, and then bring your Sapphire Charm forth. The dormant Sylph appears in any appropriate spot Near you.\nThe elemental is a character under the control of the Game Host. It acts after you take your turn in the sequence. You will have to use the Rally action to give it orders (although that action also counts as a Rally).\nIf the elemental is Near you, you may order it back into your headband, with a Rally action. If the elemental is healthy, you may Refresh this Gift at your next cycle. If the elemental is Hurt, Injured, Sick, etc., then you may not Refresh this Gift until the elemental has healed over time, at the normal rate. Dormancy is the best rest possible - it counts as a nice bed and a square meal.\nIf not rebound, then after eight hours of being released, and each full hour thereafter, roll your Speed die. If you roll a 1, the Sylph becomes unbound. You will have to bind it again, by winning the contest, as above. (You may also have to track it down, for it will find someplace else to become dormant.)\n\n@@SECTION: (You may also have to track it down, for it will find someplace else to become dormant.)', 5, 287, '', 12, 'bind-sylph', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(144, 1, 144, 'Bind Undine', 0, 0, 5, 'Action; If you tie the contest, or worse, you may not try again until you buy at least one more Mark in Swimming Skill', '@@SECTION: Once you have asserted your dominion over an elemental, the creature is bound to serve you.\n\n@@REQUIRES: Any two Gifts which have both the \"Water\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Elementalist\'s Trappings: Blue\n\n@@REQUIRES: Successfully finding an Undine and winning a contest to bind it\n\n@@REQUIRES: Character Development\nWinning a contest of your Mind & Leadership vs. the elemental\'s Mind & Undine Trait\nIn order to buy this Gift, you must first successfully confront a Undine, strongly present your Beryl Necklace, and then roll a contest of your Mind & Leadership die vs. the elemental\'s Mind & Undine Trait. If you are successful, the Undine is bound to you, dormant inside your Talisman.\nIf you tie the contest, or worse, you may not try again until you buy at least one more Mark in Swimming Skill.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"Rally to call forth a Water Elemental\" Declare a Rally action, and then bring your Beryl Necklace forth. The dormant Undine appears in any\nappropriate spot Near you.\nIf the elemental is Near you, you may order it back into your headband, with a Rally action. If the elemental is healthy, you may Refresh this Gift at your next cycle. If the elemental is Hurt, Injured, Sick, etc., then you may not Refresh this Gift until the elemental has healed over time, at the normal rate. Dormancy is the best rest possible - it counts as a nice bed and a square meal.\nThe elemental is a character under the control of the Game Host. It acts after you take your turn in the sequence. You will have to use the Rally action to give it orders (although that action also counts as a Rally).\nIf not rebound, then after eight hours of being released, and each full hour thereafter, roll your Mind die. If you roll a 1, the Undine becomes unbound. You will have to bind it again, by winning the contest, as above. (You may also have to track it down, for it will find someplace else to become dormant.)', 5, 295, '', 12, 'bind-undine', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(145, 1, 145, 'Blatant Fool', 0, 0, NULL, 'Passive; Anyone, near or far, can clearly make you out to be a fool', '@@PASSIVE: Anyone, near or far, can clearly make you out to be a fool.\n\n@@SECTION: No Range Penalties for Rally or Taunt\n\n@@SECTION: Your Rallies and Taunts no longer suffer penalties for Range. (Your Scare and Trick taunts still have range penalties.)', 2, 354, '', 10, 'blatant-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(146, 1, 146, 'Bind Gnome', 0, 0, 5, 'Action; If the elemental is healthy, you may Refresh this Gift at your next cycle', '@@SECTION: Once you have asserted your dominion over an elemental, the creature is bound to serve you.\n\n@@REQUIRES: Any two Gifts which have both the \"Earth\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Elementalist\'s Trappings: Amber\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Successfully finding a Gnome and winning a contest to bind it\n\n@@REQUIRES: Character Development\nWinning a contest of your Body & Leadership vs. the elemental\'s Body & Gnome Trait\nIn order to buy this Gift, you must first successfully confront a Gnome, strongly present your Hematite Necklace, and then roll a contest of your Body & Leadership die vs. the elemental\'s Body & Gnome Trait. If you are successful, the Gnome is bound to you, dormant inside your Talisman.\nIf you tie the contest, or worse, you may not try again until you buy at least one more Mark in Digging Skill.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"Rally to call forth an Earth Elemental\"\nDeclare a Rally action, and then bring your Hematite Necklace forth. The dormant Gnome appears in any appropriate spot Near you.\nThe elemental is a character under the control of the Game Host. It acts after you take your turn in the sequence. You will have to use the Rally action to give it orders (although that action also counts as a Rally).\nIf the elemental is Near you, you may order it back into your necklace, with a Rally action. If the elemental is healthy, you may Refresh this Gift at your next cycle. If the elemental is Hurt, Injured, Sick, etc., then you may not Refresh this Gift until the elemental has healed over time, at the normal rate. Dormancy is the best rest possible - it counts as a nice bed and a square meal.\nIf not rebound, then after eight hours of being released, and each full hour thereafter, roll your Body die. If you roll a 1, the Gnome becomes unbound. You will have to bind it again, by winning the contest, as above. (You may also have to track it down, for it will find someplace else to become dormant.)', 5, 289, '', 12, 'bind-gnome', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(147, 1, 147, 'Blind-Fighting', 0, 0, NULL, 'Passive', '@@REQUIRES: Danger Sense\n\n@@PASSIVE: Concealment penalties are only d8 at Near Range\n\n@@SECTION: When you make an attack at Near Range (4 paces), all concealment penalty dice are only d8s, not d12s.\n\n@@SECTION: Concealment doesn\'t stop you from threatening\n\n@@SECTION: Your uncanny sense of battle allows you to threaten folks with your weapons, even when you suffer concealment. (Yes, this means you can Counter when you\'re Reeling, since the Reeling penalty is a concealment penalty!) Your counter suffers a concealment penalty: d12 vs. totally-concealed attackers, d8 vs. partially- concealed attackers (such as when you\'re Reeling', 5, 73, '', 5, 'blind-fighting', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(148, 1, 148, 'Blindness', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Eyebite to Blindness\"\nTo use this ability, you must have a \"Eyebite\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Eyebite\" weapon becomes a \"Blindness\".', 5, 299, '', 12, 'blindness', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(149, 1, 149, 'Boomerang Arc', 0, 0, NULL, 'Passive; You can throw your boomerang against the wind in a path that crosses multiple targets', '@@FLAVOUR:\nYou can throw your boomerang against the wind in a path that crosses multiple targets. It only needs to hit one!\n\n@@SECTION: X: Action\n\n@@TRIGGER: before you throw a Boomerang\n\n@@SECTION: Tap this gift, then choose up to twelve targets.\n\n@@SECTION: All those targets must now defend against your boomerang attack ... but only the target that scores the lowest defense roll is hit.\n\n@@SECTION: All targets defend normally - so you may be exposing yourself to multiple counter-attacks!\n\n@@SECTION: Recharge this gift with a \"recharge\" action.', 1, 917, 'before you throw a Boomerang', 3, 'boomerang-arc', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(150, 1, 150, 'Boomerang Distance', 0, 0, NULL, 'Passive; For this attack, your maximum range is Long', '@@PASSIVE: Your boomerang soars on the wind, far and away.\n\n@@SECTION: X: Action\n\n@@TRIGGER: before you throw a Boomerang\n\n@@SECTION: Tap this gift, then throw your Boomerang. For this attack, your maximum range is Long.\n\n@@SECTION: Recharge this gift with a \"recharge\" action', 1, 917, 'before you throw a Boomerang', 3, 'boomerang-distance', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(151, 1, 151, 'Boomerang Return', 0, 0, NULL, 'Passive; You can throw your boomerang in a path that returns to you', '@@FLAVOUR:\nYou can throw your boomerang in a path that returns to you.\n\n@@SECTION: X: Action\n\n@@TRIGGER: when you miss with a thrown Boomerang\n\n@@SECTION:\nAfter you miss with a Boomerang throw, tap this gift. The Boomerang returns to your good hand, immediately ready for use.\n\n@@SECTION: Recharge this gift with a \"recharge\" action.\n\n@@FLAVOUR:\nYou can\'t use this if you hit the target. Your boomerang is over there, at the target\'s feet, embedded in their skull, etc.', 1, 917, 'when you miss with a thrown Boomerang', 3, 'boomerang-return', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(152, 1, 152, 'Cannon Sweep', 0, 0, NULL, 'Passive; A skilled cannoneer can fire for the best effect, bouncing the cannonball in the most surprising ways', '@@FLAVOUR:\nA skilled cannoneer can fire for the best effect, bouncing the cannonball in the most surprising ways.\n\n@@ACTION: Sweep with cannon fire\nWhen you hit a target with a cannon, you might be able to Sweep. The sweep distance varies on how far away the target is.\n\n@@SECTION: If the target is at Medium range or less, you can\'t sweep at all.\nIf the target is at Long range, you may Sweep Short.\nIf the target is at Very Long range or more, you may Sweep Medium.\n\n@@SECTION: Cannons are weapons that have the \"Cannon\" descriptor.', 3, 476, '', 14, 'cannon-sweep', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(153, 1, 153, 'Chain Lightning', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Grand masters can keep from laughing as they watch them dance in paroxysms of pain Action \"ready Chain Lightning\" Exhaust this Gift, then use the ready action…', '@@SECTION: Blasting a single fool with lightning? Child\'s play. A real master knows how to arc the bolt from one fool to the next. Grand masters can keep from laughing as they watch them dance in paroxysms of pain\n\n@@REQUIRES: Any two Gifts which have both the \"Air\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Chain Lightning\"\nExhaust this Gift, then use the ready action to draw forth a \"Chain Lightning\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 288, '', 12, 'chain-lightning', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(154, 1, 154, 'Claws of Iron', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better Brawling Fighter\n\n@@REQUIRES: Natural Weapon: Claws\n\n@@ACTION: Action \"brawling attack with claws\"\nYou may claim +1 Damage with all attacks made with Claws', 5, 318, '', 2, 'claws-of-iron', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(155, 1, 155, 'Clear-Headed', 0, 0, 1, 'Passive; Alternatively, you may reduce \"Controlled\" or \"Marionette\" to \"Immobilized.\"', '@@REFRESH: X (Battle)\n\n@@TRIGGER: when you are Berserk, Confused, or Enraged\nAs a reaction, negate Berserk, Confused, or Enraged on yourself.\nAlternatively, you may reduce \"Controlled\" or \"Marionette\" to \"Immobilized.\"', 5, 54, 'when you are Berserk, Confused, or Enraged', 14, 'clear-headed', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(156, 1, 156, 'Clouding of Minds', 0, 0, 2, 'Action; Exhaust; If you attack them, or do anything against them that provokes a resistance or defense, you immediately become visible again', '@@REQUIRES: Any two Gifts which have both the \"Green & Purple\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Clear-Headed\n\n@@REQUIRES: Green & Purple Apprentice Literacy\n\n@@REQUIRES: Insider with the Cognoscenti\n\n@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"guard and Cloud Minds\"\nDeclare a Guard action, then Exhaust this Gift. Roll your Mind & Deceit vs. the crowd\'s Mind & Observation. Anyone in the crowd who fails to defeat your roll can no longer perceive you. As long as you stay away from them, you have total concealment against their attacks.\nIf you attack them, or do anything against them that provokes a resistance or defense, you immediately become visible again. A target who can perceive you cannot be clouded again until they haven\'t seen you for 24 hours.\nYour thought-sending ability does not negate the clouding of minds. Cognoscenti often use thought- sending to communicate while invisible.\nSomeone who can perceive you can attempt to Rally someone who can\'t. If they score one success, then one boon they may claim is \"let my friend see the mind- clouding wizard\".', 5, 301, '', 12, 'clouding-of-minds', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(157, 1, 157, 'Clysmian Foul', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Water to Clysmian Foul\"\n\n@@SECTION: To use this ability, you must have a \"Create Water\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\n\n@@SECTION: Exhaust this Gift. Your \"Create Water\" weapon becomes a \"Clysmian Foul\", a gurgling ball of water and mud that you toss high in the air and then comes down as a pounding deluge upon your targets.', 3, 748, '', 12, 'clysmian-foul', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(158, 1, 158, 'Combat Edge', 0, 0, 3, 'Passive; Exhaust; If you tie on an attack or defense, exhaust this Gift', '@@REQUIRES: Mind d8 or better\n\n@@REQUIRES: +1 Mark in Tactics\n\n@@REQUIRES: You may claim +1 Mark in Tactics Skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: you tie on an Attack or Defense\nIf you tie on an attack or defense, exhaust this Gift.\nThat tie now breaks in your favor. (That is, your ties count as successes, and your opponent\'s ties don\'t count at all.)', 5, 63, 'you tie on an Attack or Defense', 21, 'combat-edge', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(159, 1, 159, 'Combat Save', 0, 0, 3, 'PASIVE:  If you suffer any results of Unconscious, Dying, or Dead when hit by an attack, negate all of those.', '@@REFRESH: X (Chapter)\n\n@@TRIGGER: failed attack or defense\nWhenever you fail any attack or defense, after you roll your Soak & Armor, if you suffer any results of Unconscious, Dying, or Dead, negate all of those results.\nAlternatively, you may reduce a result of Overkilled to Dying.', 5, 63, 'failed attack or defense', 21, 'combat-save', '2026-03-22 10:39:00', '2026-03-29 08:31:45'),
(160, 1, 160, 'Comet Fall', 0, 0, 3, 'Action; Exhaust; Exhaust this Gift', '@@TRAPPINGS: Elemental Apprentice Elementalist\'s Trappings: Star\n\n@@REQUIRES: Insider with the Dunwasser Academy Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: One Gift with both \"Air\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Earth\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Fire\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Water\" & \"Journeyman\" descriptors\n\n@@REQUIRES: Starlight\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Action \"aim and upgrade Stardust to Comet Fall\"\nTo use this ability, you must have a \"Stardust\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Stardust\" weapon becomes a \"Comet Fall\".', 5, 297, '', 12, 'comet-fall', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(161, 1, 161, 'Command the Rain', 0, 0, 5, 'Passive; You can raise or reduce the amount of precipitation by a hand\'s worth every four hours', '@@REQUIRES: Any two Gifts which have both the \"Water\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Special)\n\n@@FLAVOUR:\nYou can command the rain and snow. You can raise or reduce the amount of precipitation by a hand\'s worth every four hours. (That\'s about 1 inch or 2.5 cm every hour.) You can continue altering the weather as long as you remain conscious.\nWith concentration and rolls of Mind, Swimming, and Weather Sense, you can change the weather to hail, thunderstorms, etc., at the discretion of the Game Host', 5, 296, '', 12, 'command-the-rain', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(162, 1, 162, 'Command the Wind', 0, 0, 5, 'Passive; You can raise or reduce the amount of precipitation by four knot\'s worth of speed every hour', '@@FLAVOUR: Everyone talks about the weather, but it takes a master wizard to actually do something about it. Note: spells that control the weather are often banned by law.\n\n@@REQUIRES: Any two Gifts which have both the \"Air\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Special)\n\n@@SECTION: You can command the wind within the landscape that you are standing in. You can raise or reduce the amount of precipitation by four knot\'s worth of speed every hour. (That\'s about 4 mph or 7.4 km/h.) You can continue altering the weather as long as you remain conscious. When the wind gets above 24 knots, people will have trouble walking around; past 40 knots, and buildings will start to fall over.', 5, 288, '', 12, 'command-the-wind', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(163, 1, 163, 'Commanding Leader', 0, 0, NULL, 'Passive', '@@REQUIRES: True Leader\n\n@@ACTION: Action \"rally\"\nWhen you take the Rally action, your penalty Range dice are reduced. You suffer no range penalty dice up to Short Range; at Medium Range, you suffer d8; at Long Range, you suffer d12; and at Very-Long Range, you suffer 2d12.', 5, 82, '', 5, 'commanding-leader', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(164, 1, 164, 'Communion', 0, 0, 5, 'Passive; Exhaust; Requires Literacy Cleric\'s Trappings (any) White Magic Apprentice Stunt \"Communion\" Exhaust this Gift', '@@PASSIVE: Requires\nLiteracy\nCleric\'s Trappings (any) White Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Communion\"\nExhaust this Gift. Then roll your Mind & Will vs. a group\'s Will.\nIf none of your targets fail the roll, you become Afraid. The lowest-rolling failure has communion with you.\n(That target is obviously in the greatest need of your help.) Since it\'s tricky to figure out just who in the group is going to fail the roll, you are permitted to select a \"group of one\", to make sure that one person will have Communion.\nYou will know which of the group has the Communion spell cast upon them ... but only those trained in the Supernatural will be aware of the blessing that surrounds the target with an otherworldly aura of good fortune.\nAs a reaction, that target may cry out a message that is no more than 64 words. When they do, the following events happen:\nYou hear the message.\nYou are rallied. Remove any Reeling or Afraid conditions on yourself. If you are Asleep, you wake up.\nYou know the direction and the distance to the target, and you have synecdoche with them, until the end of the Office of Sext (3 pm).\nCommunion can be used to convey a simple message, such as \"I arrived safely at my destination.\" Or it can be a desperate call for help.\nThis gift can only be refreshed by praying for 8 minutes during the Office of Sext (noon to 3 pm). As soon as this gift is refreshed, the communion expires.', 5, 304, '', 12, 'communion', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(165, 1, 165, 'Compulsion', 1, 0, 5, 'Passive; For one scene; You may Refresh this Gift as a simple \"Refresh\" action, but if you do, the compulsion is negated', '@@REQUIRES: Any two Gifts which have both the \"Green & Purple\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Diplomacy\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REQUIRES: Insider with the Cognoscenti Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Magic attack: plant a compulsion\"\nRoll your Mind & Will vs. a group\'s Mind & Will.\nNote the lowest roller.\nThe lowest-rolling failure now has a compulsion. Choose one of the following statuses: Afraid, Berserk, Blinded, Confused, Enraged, Reeling, Slowed. Then, declare a sentence that would make this compulsion happen. When the target perceives that condition, the status takes effect, for one scene.\nYou may Refresh this Gift as a simple \"Refresh\" action, but if you do, the compulsion is negated. Unless you witness the compulsion activating, or hear about it from other sources, you\'ll never know if it happened or not.\nMultiple\nYou may buy this Gift multiple times. Each Gift gives you another Exhaustion. You may plant multiple compulsions in the same target, or compulsions in different targets. Keep a note of which Gift was exhausted for which compulsion, so you know which ones you can refresh.', 5, 301, '', 12, 'compulsioon', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(166, 1, 166, 'Consecration', 0, 0, 5, 'Passive; If they passed the first test, they must test again if they get to Short range - if they win the second time, it breaks the consecration and the spell ends; …', '@@REQUIRES: Literacy\n@@REQUIRES: Cleric\'s Trappings (any) White Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Consecration\"\nWhen you cast this spell, the spot where you are standing becomes consecrated. Make a note of your Will Dice.\nAny unholy creatures that approach within Medium range of this spot must test their Will & Undead dice vs. your dice. If they Tie or worse, they become Confused and Terrified until they flee to Long Range of the consecrated spot. If they passed the first test, they must test again if they get to Short range - if they win the second time, it breaks the consecration and the spell ends; otherwise, they must flee, as above.\nThis gift can only be refreshed by praying for 8 minutes during the Office of Compline (9 pm to midnight). As soon as this gift is refreshed, the consecration expires.\nThis spell has no effect during a total eclipse.', 5, 304, '', 12, 'consecration', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(167, 1, 167, 'Counter Shot', 0, 0, 1, 'Passive; Exhaust; Counter-Attack with Bow, Crossbow, Pistol, or Carbine Exhaust this Gift to Counter-Attack with a loaded bow, crossbow, pistol, or carbine, against Attacks…', '@@REQUIRES: Sharpshooter\n\n@@REFRESH: X (Battle)\n\n@@PASSIVE: Counter-Attack with Bow, Crossbow, Pistol, or Carbine\nExhaust this Gift to Counter-Attack with a loaded bow, crossbow, pistol, or carbine, against Attacks made against you from up to Near Range (4 paces). (Without this Gift, you cannot counter with these ranged weapons, at all.)\nThis Gift does not allow you to counter with fusils, muskets, slings, or other Ranged Weapons', 5, 79, '', 5, 'counter-shot', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(168, 1, 168, 'Curse', 0, 0, 2, 'Action; Exhaust; Since the curse is an Attack, then the target may choose to defend themselves with a Counter-Attack, instead of the dice listed above', '@@REQUIRES: Literacy\n\n@@REQUIRES: Necromancer\'s Trappings\n\n@@REQUIRES: Apprentice Necromancy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Aim to upgrade Illness to Curse\"\nTo use this ability, you must have an \"Illness\" Magic weapon at the ready, and you must take the \"Aim\" action at a target. Exhaust this Gift. Your \"Illness\" weapon becomes a \"Curse\".\nAs a Mystical, Magic Attack, you may curse a target. Normal Range penalties apply. Declare which curse you will use, and then roll your Will, Deceit, & 3d6 vs. the target\'s defense. The defense varies depending on what curse you are using.\nCurse  Game Effect  Target Defends with ...\nOpen Sores Hurt & Sick  Body, Will, Supernatural\nMilky Eyes Hurt & Blinded  Body, Mind, Observation\nHallucinations Hurt & Confused  Speed, Mind, Inquiry\nEnfeebled Hurt & Fatigued  Body, Speed, Endurance\nFrozen Limbs Hurt & Immobilized  Body, Speed, Will, Endurance\nIntense Nausea Hurt & Confused  Body, Speed, Mind, Supernatural\nAches and Pains Hurt & Slowed  Body, Speed, Endurance\nThe Game Host is encouraged to make up new kinds of curses to inflict, using these rules as guidelines.\nSince the curse is an Attack, then the target may choose to defend themselves with a Counter-Attack, instead of the dice listed above.', 5, 313, '', 12, 'curse', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(169, 1, 169, 'Death Watch', 0, 0, NULL, 'Passive; Bonus to Sense Undeath You can also sense undeath. Undead cannot claim concealment bonusesagainst you', '@@FLAVOUR: Where death goes, you follow.\n\n@@SECTION: You Know Death\nWhen someone or something within Medium range of your senses dies, you know it at the exact moment that it happens.\n\n@@SECTION: Bonus to Sense Undeath\n\n@@FLAVOUR:\nYou can also sense undeath. You can sense all lesser undead within Medium range of you, and you can sense all greater undead within Long range of you.\n\n@@SECTION: Undead cannot claim concealment bonuses against you.', 3, 750, '', 2, 'death-watch', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(170, 1, 170, 'Delay', 0, 0, 5, 'Passive; Exhaust; Stunt \"delay recovery\" Declare any one other Magic Gift you have', '@@REQUIRES: Literacy\n\n@@REQUIRES: Thaumaturge\'s Trappings\n\n@@REQUIRES: Thaumaturgy Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"delay recovery\"\nDeclare any one other Magic Gift you have. That gift must have the \"Magic\" descriptor, and either the \"Battle\" or the \"Respite\" descriptor. Exhaust this Gift.\nDuring battle, you may, as a free action, declare you will call upon your magical Delay to refresh the Magic Gift you had declared earlier. The Refresh happens instantly.\nYou may refresh this Gift at the next Respite. If you refresh this Gift, the delay that you had set earlier is gone.\nDelay only works on Magical Gifts that exclusively have \"X (Battle)\" or \"X (Respite)\" as their refresh options. It does not work on other Magic Gifts.', 5, 308, '', 12, 'delay', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(171, 1, 171, 'Dew-Walking', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Knack for Stealth\n\n@@PASSIVE: Maximize Dice to Resist Tracking\n\n@@SECTION: Whenever anyone tries to track you, your dice to resist them are Maximized.', 5, 318, '', 2, 'dew-walking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(172, 1, 172, 'Diehard', 0, 0, NULL, 'Passive', '@@REQUIRES: Toughness\n\n@@PASSIVE: Bonus d6 Soak when Hurt Bonus d6 Soak when Injured\n\n@@SECTION: Whenever you are Hurt, you may claim a bonus d6 with your Soak Dice. Whenever you are Injured, you may also claim a bonus d6 Soak Dice.\n\n@@SECTION: Yes, that means if you are both Hurt and Injured, you may claim a bonus 2d6.', 5, 63, '', 21, 'diehard', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(173, 1, 173, 'Disarming Save', 0, 0, 3, 'Passive; Exhaust; Whenever you fail a melee attack, counter-attack, or parry, after you roll your Soak & Armor, exhaust this Gift to negate all Unconscious, Dying, Dead, and…', '@@REQUIRES: Body d8 or better\n\n@@PASSIVE: +1 Mark in Melee Combat\n\nYou may claim +1 Mark in Melee Combat skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: while using a melee weapon, you fail a melee attack, counter-attack, or parry\n@@ACTION: Whenever you fail a melee attack, counter-attack, or parry, after you roll your Soak & Armor, exhaust this Gift to negate all Unconscious, Dying, Dead, and Overkilled results from the damage.\nAlso, you are disarmed. If you negated a result of Dying, your weapon flies in a random direction, 4 paces from you. If you negated a result of Dead, your weapon flies 12 paces away. If you negated a result of Overkilled, your weapon shatters into fragments.\nYou must be using a melee weapon for this Gift to work. If you dodge, or use Brawling Fighter to counter with a brawling weapon, then you cannot use Disarming Save.', 5, 63, 'while using a melee weapon, you fail a melee attack, counter-attack, or parry', 21, 'disarming-save', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(174, 1, 174, 'Disarming Strike', 0, 0, 1, 'Action; Exhaust; Action \"melee attack with fencing weapon\" When executing a Melee Attack with a fencing weapon, you may declare a disarming strike', '@@REQUIRES: Fencing\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"melee attack with fencing weapon\"\nWhen executing a Melee Attack with a fencing weapon, you may declare a disarming strike. First, exhaust this Gift. Then, play out the attack, as normal. If you missed your foe, nothing happens. If you hit your foe, you have disarmed them, as per below:\nIf your foe had a one-handed weapon, your foe is disarmed and you cause damage, as normal.\nIf your foe had a two-handed wea on, your foe is disarmed, but you cause Weak damage.', 5, 75, '', 5, 'disarming-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(175, 1, 175, 'Dramatic Disheveling', 0, 0, 3, 'Passive; Exhaust; Exhaust this Gift after you roll Soak & Armor dice, and a Damage effect still scores an Unconscious, Dying, Dead, or Overkilled result on you', '@@REQUIRES: Will d8 or better\n\n@@PASSIVE: +1 Mark in Presence\nYou may claim +1 Mark in Presence skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: just rolled Soak & Armor Dice\n@@ACTION: Exhaust this Gift after you roll Soak & Armor dice, and a Damage effect still scores an Unconscious, Dying, Dead, or Overkilled result on you.\nFirst, your best armor layer is instantly shredded. If you have no armor, then your clothes are shredded, leaving you a tattered mess.\nNext, negate all Unconscious, Dying, Dead, and Overkilled result just inflicted on you, from the damage you suffered.\nThird, negate any Afraid or Terrified effect currently on yourself (whether it\'s from this damage, or if it was already there.)', 5, 63, 'just rolled Soak & Armor Dice', 21, 'dramatic-disheveling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(176, 1, 176, 'Dukun Apprentice', 0, 0, 1, 'Action; Exhaust; Until the end of the scene; Action \"rally and apply anting aid\" Whenever you take the \"rally other\" action, you may call upon supernatural power to heal the target', '@@ACTION: Action \"rally and apply anting aid\"\n\n@@SECTION: Whenever you take the \"rally other\" action, you may call upon supernatural power to heal the target. Roll your Will & Leadership, as per a normal rally, and note the successes. For each success, you can claim one of the following boons:\n\n@@SECTION: Mundane Boons (anyone\'s rally could do this)\nRemove Afraid condition\nRemove Asleep\nRemove Unconscious\nRemove Reeling\nRemove Confused\nSupernatural Boons (only your magic can do this)\nRemove Hurt\nReplace Dying with Fatigued\nRemove \"On Fire\"\nReplace Marionette with Reeling\nReplace Immobilized with Reeling\nReplace Slowed with Reeling\nReplace Controlled with Immobilized\n\n@@SECTION:\nAt the discretion of the Game Host, applying supernatural aid may be able to cure the target of other afflictions.\n\n@@ACTION: Long action (five minutes)\n\n@@SECTION: \"Lead group in healing ceremony\"\n\n@@SECTION:\nAfter any battle has ended, you may gather all your allies around you and lead them in inspirational ceremony. All allies who participate in your prayer have their \"Hurt\" conditions removed.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready magic weapon\n\n@@SECTION: Exhaust this Gift, then use the Ready action to draw forth a spell. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the scene (five minutes).\n\n@@FLAVOUR:\nYour Gift allows you to ready the following magical weapons:\nSantet\nSirep', 1, 917, '', 12, 'dukun-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(177, 1, 177, 'Earth Clout', 1, 0, NULL, 'Passive; The greatest wizards can increase the power of a spell, even after it has been cast', '@@FLAVOUR:\nThe greatest wizards can increase the power of a spell, even after it has been cast.\n\n@@REQUIRES: Mystic: Elementalism\n\n@@PASSIVE: Add +1 Mark to Digging\nAdd 1 Mark to your Digging Skill.\n\n@@SECTION: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting a Earth Spell\n@@ACTION: Exhaust this Gift after casting a spell of the Earth nature to claim a bonus 2d8 with your casting dice.\n\n@@LIMIT: Multiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 290, 'Casting a Earth Spell', 12, 'earth-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(178, 1, 178, 'Earth Mnemonic', 0, 0, 3, 'Passive; Your meditative training allows you to call upon reserves of power Extra action: \"refresh all Earth Battle Gifts and Earth Respite Gifts\" On your turn, as an…', '@@FLAVOUR:\nYour meditative training allows you to call upon reserves of power\n\n@@REQUIRES: Any two Gifts which have both the \"Earth\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@TRAPPINGS: Any magical Talisman from any Trappings Gift\n\n@@PASSIVE: Add +1 Mark to Digging\nAdd 1 Mark to your Digging Skill.\n\n@@SECTION: If you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh all Earth Battle Gifts and Earth Respite Gifts\"\nOn your turn, as an extra action, you may put your off-hand upon your magical talisman, and in a loud voice, you declare your command over all Earth. By doing so, you immediately refresh all exhausted gifts that have both the \"Earth\" descriptor and either the \"Battle\" or the \"Respite\" descriptor. Other Gifts are not refreshed.\nIf you do not have a magical talisman to brandish forth, you cannot use this ability.', 5, 290, '', 12, 'earth-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(179, 1, 179, 'Eater of Dead', 0, 0, NULL, 'Passive; Cannibalism is taboo for most civilized persons; but corpses you taste don\'t come back', '@@PASSIVE: Cannibalism is taboo for most civilized persons; but corpses you taste don\'t come back.\n\n@@STUNT: \"Silencing Bite\"\n\n@@SECTION: You may take the Silencing Bite action, ritually eating part of a corpse to assist the associated spirit in shuffling off this mortal coil. If a corpse has received the Silencing Bite, it is considered consecrated and Overkilled.', 3, 750, '', 2, 'eater-of-dead', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(180, 1, 180, 'Eidolon', 0, 0, 2, 'Passive; (The bonus d12 is because you\'re effectively disguised as something else.) You can speak, and others will hear you', '@@REQUIRES: Literacy\n\n@@REQUIRES: Thaumaturge\'s Trappings\n\n@@REQUIRES: Thaumaturgy Apprentice\n\n@@REFRESH: X (Respite)\n\n@@STUNT: \"Manifest as an Eidolon\"\nThis spell allows you to project yourself as an eidolon, or magic representation of yourself, into an inanimate object. You must have a part of that object as a synedoche link. For example, to project an eidolon from a given tree, you could use a leaf from that tree. To project an eidolon at a campsite, you could use a rock from the campfire circle. You may not manifest an eidolon in a person or an animal.\nAn eidolon cannot move on its own from the spot from where it manifests. Others may move it, instead, provided it is not a tree or some other rooted object.\nThe eidolon resembles you, molde from the material that you are linked to. Following the examples above, your eidolon would take the form of an animate tree with your face in the wood grain, or the roaring flames of the campfire may take on the appearance of your grim visage. You cannot use your equipment, weapons, etc. - you are merely an artificial projection. You also may not cast spells.\nYou see, hear, and sense everything from where the eidolon is. (Eidolons are often used to look in on faraway places.) The eidolon doesn\'t grant you any senses you don\'t have, yourself, so if your eidolon manifests in a dark room, you won\'t be able to see anything.\nIf you don\'t want to be noticed, you\'ll have to roll your Mind, Stealth, and d12 vs. any vigilant onlooker\'s Mind, Observation, and Supernatural dice. (The bonus d12 is because you\'re effectively disguised as something else.)\nYou can speak, and others will hear you. Eidolons are frequently used to communicate with people far away.\nMeanwhile, your physical body remains at the original spot, clutching the material you are using for the link. While the spell is active, you are completely unaware of anything nearby. You are helpless against any attack.\nFrom within the eidolon, you automatically resist any spells that test your Body or Speed (that is, \"physical spells\"); spells resisted by other dice work on you normally.\nYou may dismiss the eidolon at any time, thus canceling the spell; you immediately are sent Reeling, but at least you\'re aware. The spell will also end if you are sent Reeling, Unconscious, or otherwise suffer an abnormal status such as Confusion, Fear, Silence, etc. Also, after five minutes, the spell will expire, and you will be sent Reeling.\nThe eidolon may be dispelled, or even destroyed. (The eidolon is just a physical object, after all.) If the eidolon suffers damage from an attack, you yourself are unharmed, but since any successful attack will send you Reeling, the spell will end.', 5, 308, '', 20, 'eidolon', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(181, 1, 181, 'Eidolon Stride', 0, 0, 3, 'Passive; You may use this spell at any point while you are manifesting an Eidolon', '@@REQUIRES: Literacy\n\n@@REQUIRES: Thaumaturge\'s Trappings\n\n@@REQUIRES: Thaumaturgy Apprentice\n\n@@REQUIRES: Mystic: Thaumaturgy\n\n@@REQUIRES: Locating\n\n@@REQUIRES: Eidolon\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: Using the Eidolon magic\nYou may use this spell at any point while you are manifesting an Eidolon. Your body disappears from the real world, and you are instantly teleported to where your eidolon is manifesting. You then must step 1 pace out of the eidolon, onto solid ground. Your Eidolon spell ends, and you are sent Reeling.', 5, 311, 'Using the Eidolon magic', 12, 'eidolon-stride', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(182, 1, 182, 'Sword Dancers Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \n點 A Martial Sword\n點 A Scholarly Sword\n點 Silk Armor\n點 A letter of recommendation, endorsing your skills as a Sword Dancer\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 4, 474, '', 25, 'sword-dancers-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(183, 1, 183, 'Eternal Breath', 0, 0, 2, 'Passive; Exhaust; Exhaust this Gift to hold your breath for the rest of this Scene (generally five minutes) without any ill effects', '@@REQUIRES: Species Trait of d8 or better Deep Diving\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: suffocation\nExhaust this Gift to hold your breath for the rest of this Scene (generally five minutes) without any ill effects. While holding your breath, you may not speak or perform other feats that require the use of breath', 5, 318, 'suffocation', 20, 'eternal-breath', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(184, 1, 184, 'Extra Career', 1, 0, NULL, 'Passive', '@@REQUIRES: The three starting Gifts of that Career\n\n@@PASSIVE: Extra Career Trait starting at d4\n\n@@SECTION: You have another Career! This Career begins at d4. Multiple Career Traits can be combined to provide lots more Skill dice.\n\n@@NOTE: You may use the \"Increased Trait\" Gift to buy up this Career Trait\n\n@@LIMIT: MULTIPLE', 5, 65, '', 8, 'extra-career', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(185, 1, 185, 'Extra Favourite Use With [Skill]', 0, 0, NULL, 'Passive; \"+1\" Skill Mark in [Skill of choice] Add one Mark to your Skill of choice', '@@PASSIVE: \"+1\" Skill Mark in [Skill of choice]\nAdd one Mark to your Skill of choice.\nAnother Favorite Use\nYou may choose an extra Favorite Use with your Skill of Choice. You still only get Favor once.\nCharacter Development\nIf you lose this Gift, you also lose the extra Mark you gained from this Gift.', 5, 54, '', 14, 'extra-favourite-use-with-skill', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(186, 1, 186, 'Familiar: Hantu Raya', 0, 0, NULL, 'Passive; Instead, it\'s good at pretending to be you, doing manual labor, and being really strong', '@@PASSIVE: Strange Monster Pretends To Be You\n\n@@SECTION: Through your accomplished knowledge of magic, you have bonded with a supernatural being, a hantu raya. This being looks exactly like you, but it isn\'t you. It doesn\'t have your Species gifts, your Career Gifts, or other special abilities. Instead, it\'s good at pretending to be you, doing manual labor, and being really strong. You can put the hantu raya to work for you, or you can use it as an alibi as you do something, somewhere else. It has a reasonable intelligence, but it\'s not very good conversation. It is obsessed with you and everything you do, to a degree that many would find unsettling.\n\n@@FLAVOUR:\nThe hantu raya is described in the Menagerie, page 983', 1, 918, '', 12, 'familiar-hantu-raya', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(187, 1, 187, 'Favor Bonus with: [Choice]', 1, 0, NULL, 'Passive', '@@REQUIRES: A Favorite Use with [Skill of Choice]\n\n@@PASSIVE: Bonus d12 when using Favor\nIf you roll one 1, before you invoke favor\'s re-roll, you may also claim a bonus d12.\n\n@@SECTION: Roll the bonus d12 first. Yes, if that d12 comes up \"1\", you may choose to use favor to re-roll that one.\n\n@@SECTION: Extra 12 When Using Favorite by Rote\n\n@@SECTION: If you use your Skill of Choice by rote, and you\'re performing your Favorite Use, you may claim a bonus\n\n@@SECTION: 12. This bonus 12 is just like a die that always comes up 12 (basically, a maximized d12).\n\n@@SECTION: This extra 12 will usually score a bonus success, which will then be will be added to the others, then halved, just like any rote', 5, 65, '', 8, 'favor-bonus-with-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(188, 1, 188, 'Fencing', 0, 0, NULL, 'Passive; Use Body, Melee Combat Dice, and Dodge Dice When you Parry (not Counter-Attack) with a fencing weapon, you may include your Dodge Skill dice', '@@FLAVOUR: Parry with Fencing Weapon? Use Body, Melee Combat Dice, and Dodge Dice\n\n@@PASSIVE: When you Parry (not Counter-Attack) with a fencing weapon, you may include your Dodge Skill dice. (That\'s just your Dodge dice, not your Speed too.) Your Dodge Dice are limited by Encumbrance', 5, 75, '', 5, 'fencing', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(189, 1, 189, 'Fencing Replay', 0, 0, 1, 'Passive; Exhaust; You may have rolled an attack, counter, or parry', '@@REQUIRES: Fencing\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: after rolling a fencing Attack, Counter, or Parry\nThis ability can be triggered after you roll your dice with a fencing weapon. You may have rolled an attack, counter, or parry. Your foe must have rolled already, as well. You must trigger this ability before any Damage or Soak is determined, however.\nYour blade clatters with your foe\'s, and you may exhaust this Gift to trigger a fencing replay.\nRe-roll your dice and your opponent\'s dice. The new result stands, for better or for worse', 5, 75, 'after rolling a fencing Attack, Counter, or Parry', 5, 'fencing-replay', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(190, 1, 190, 'Feral Swiftness', 0, 0, 2, 'Passive; Before you make a roll that uses Speed Dice, declare a bonus d12. This bonus d12 is just like more Speed Dice, and it may be limited by Encumbrance', '@@REQUIRES: Species Trait of d8 or better Fast Mover\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: any roll that uses Speed Dice\nBefore you make a roll that uses Speed Dice, declare a bonus d12. This bonus d12 is just like more Speed Dice, and it may be limited by Encumbrance.', 5, 318, 'any roll that uses Speed Dice', 20, 'feral-swiftness', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(191, 1, 191, 'Fire Ball', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Too bad the fire ball burns out too quickly to set any proper fires Action \"ready Fire Ball\" Exhaust this Gift, then use the ready action to draw forth a…', '@@FLAVOUR:\nThe spell most people think of, when they think of wizards. Sure, it\'s a bit cliché, but it\'s still very effective. Too bad the fire ball burns out too quickly to set any proper fires\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Fire Ball\"\nExhaust this Gift, then use the ready action to draw forth a \"Fire Ball\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 291, '', 12, 'fire-ball', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(192, 1, 192, 'Fire Clout', 1, 0, NULL, 'Passive', '@@REQUIRES: Mystic: Elementalism\n\n@@PASSIVE: Add +1 Mark to Presence\nAdd 1 Mark to your Presence Skill.\n\n@@SECTION: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting a Fire Spell\nExhaust this Gift after casting a spell of the Fire nature to claim a bonus 2d8 with your casting dice.\n@@@LIMIT: Multiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 293, 'Casting a Fire Spell', NULL, 'fire-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(193, 1, 193, 'Fire Mnemonic', 0, 0, 3, 'Passive; Add +1 Mark to Presence Add 1 Mark to your Presence Skill', '@@FLAVOUR:\nYour meditative training allows you to call upon reserves of power.\n\n@@REQUIRES: Any two Gifts which have both the \"Fire\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Any magical Talisman from any Trappings Gift\n\n@@PASSIVE: Add +1 Mark to Presence\nAdd 1 Mark to your Presence Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh all Fire Battle Gifts and Fire Respite Gifts\"\nOn your turn, as an extra action, you may put your off-hand upon your magical talisman, and in a loud voice, you declare your command over all fire. By doing so, you immediately refresh all exhausted gifts that have both the \"Fire\" descriptor and either the \"Battle\" or the \"Respite\" descriptor. Other Gifts are not refreshed.\nIf you do not have a magical talisman to brandish forth, you cannot use this ability', 5, 293, '', 12, 'fire-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(194, 1, 194, 'Flesh Ward', 0, 0, 1, 'Passive; Exhaust; The target gains a d12 bonus if they have Piety for the s\'Allumer religion', '@@R:equires: Literacy\n@@R:equires: Cleric\'s Trappings (any)\n@@R:equires: White Magic Apprentice\n\n@@REFRESH: X (Battle)\n\n@@T:RIGGER Trigger: Rally\n@@SECTION: After attempting to rallying one of your allies, you may invoke the Flesh Ward. You may not invoke the Flesh Ward on yourself.\nFirst, Exhaust this Gift. The target immediately gains 1 point of Flesh Ward.\nRoll the target\'s Will and your Academics dice vs. 3. The target gains a d12 bonus if they have Piety for the s\'Allumer religion. For each success scored, the target gains +1 points of Flesh Ward.\nEach time the target is hit by an attack that causes Damage, after the target rolls Soak & Armor, subtract the Flesh Ward from the remaining Damage. Then reduce the Flesh Ward by the amount of Damage it prevented. Once the Flesh Ward is reduced to zero, it expires and no longer provides protection.\nThe Flesh Ward ends if any of the conditions are met:\nThe ward is reduced to zero or less because of Damage (as above).\nEight minutes pass since you first cast the Flesh Ward.\nYou refresh the Flesh Ward Gift', 5, 304, '', 5, 'flesh-ward', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(195, 1, 195, 'Flight of the Prey', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Coward\n\n@@PASSIVE: More Bonuses for Cowardly Behavior\nYour bonuses for being cowardly are greatly improved! Whenever you are Afraid, you may claim a bonus 2d12 with all Parries and Dodges, you may add 1 to your Stride, 4 to your Dash, and 16 to your Run. (These better bonuses replace the ones from the \"Coward\" Gift.)', 5, 318, '', 2, 'flight-of-the-prey', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(196, 1, 196, 'Flying Fighter', 0, 0, NULL, 'Passive', '@@REQUIRES: Flight\n\n@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Speed must be greater than Body\n\n@@ACTION: Extra action \"refresh the Gift of Flight\"\nYou are a much better flyer. You may take an extra \"Refresh\" action every turn, but only to refresh the Gift of Flight.\nThe standard rule of \"never the same action twice in the same turn\" still applies. So if you use this Gift, you get an extra Refresh only for Flight, not for any other Battle Gifts.\nMay Retreat While Flying\nYour control of Flight is superior. When you are attacked while flying, you may Retreat, even though you are moving at Full-Tilt', 5, 319, '', 3, 'flying-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(197, 1, 197, 'Focused Fighter', 0, 0, NULL, 'Passive', '@@REQUIRES: Veteran\n\n@@REQUIRES: When Focused, bonus d12 to all defenses\n\n@@REQUIRES: Whenever you have Focus, you may claim a bonus d12 to all defenses: Counter-Attacks, Parries, Dodges, and any other defenses you may roll.', 5, 83, '', 5, 'focused-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(198, 1, 198, 'Fracturing Attack', 0, 0, NULL, 'Passive; +2 Damage, but your weapon loses 1 point of Damage bonus, permanently Weapons with fracturing edges, such as those made of stone or of teeth, can be even more…', '@@TRIGGER: You hit with a Fracture weapon, and before your target soaks the Damage\n\n@@PASSIVE: +2 Damage, but your weapon loses 1 point of Damage bonus, permanently\n\n@@SECTION: Weapons with fracturing edges, such as those made of stone or of teeth, can be even more effective if you\'re willing to take risks.\n\n@@SECTION:\nAfter you hit the target with a Fracture weapon, you can choose to make the attack a fracturing attack. Your attack causes +2 damage.\n\n@@SECTION:\nAfter resolving the attack, reduce your weapon\'s Damage bonus by 1 point. If this reduces your weapon\'s bonus to exactly zero, you can still use the weapon for future attacks. If the damage bonus drops below zero, the weapon shatters and is useless. Weapons that lose Damage from this fracturing attack are permanently reduced; they cannot be repaired and the damage loss is permanent. Consider getting a new weapon.\n\n@@SECTION: Fracture weapons are weapons that have the \"Fracture\" descriptor, such as the brux sword or the knapped pole', 1, 918, 'You hit with a Fracture weapon, and before your target soaks the Damage', 15, 'fracturing-attack', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(199, 1, 199, 'Freeze Arrow', 0, 0, 1, 'Action; Exhaust; If this cold bolt strikes a target, they shiver uncontrollably ... if they can still move at all', '@@FLAVOUR: By your will, you make a handful of elemental water become a barbed arrow of ice. If this cold bolt strikes a target, they shiver uncontrollably ... if they can still move at all.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Water to Freeze Arrow\"\nTo use this ability, you must have a \"Create Water\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Create Water\" weapon becomes a \"Freeze Arrow\".', 5, 294, '', 12, 'freeze-arrow', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(200, 1, 200, 'Fulguration', 0, 0, 1, 'Action; Exhaust; Literacy Cleric\'s Trappings (any) White Magic Apprentice Action \"ready Fulguration into wand, rod, or Calendar Sword\" Exhaust this Gift, then use the ready…', '@@REQUIRES: Literacy\n@@REQUIRES: Cleric\'s Trappings (any)\n@@REQUIRES: White Magic Apprentice\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Fulguration into wand, rod, or Calendar Sword\"\nExhaust this Gift, then use the ready action to draw forth a \"Fulguration\" weapon. The fulguration manifests as a white-hot lightning, glowing hotter than steel from the fire. The Fulguration is the essence of life energy, anathema to the unholy and the undead. The Fulguration is much too dangerous to be held in the hand.\nThe Fulguration may not be carried in the hand! You must ready the Fulguration into a rod, wand, or Calendar Sword.', 5, 306, '', 12, 'fulguration', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(201, 1, 201, 'Full-Tilt Movement', 0, 0, 1, 'Action; Most riding mounts may use Full-Tilt Movement, to give their riders a bonus to use tilting weapons', '@@FLAVOUR: Most riding mounts may use Full-Tilt Movement, to give their riders a bonus to use tilting weapons.\n\n@@REQUIRES: Species Trait of d8 or better\n@@REQUIRES: Fast Mover\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Dash or Sprint\"\nWhenever you are about to Dash or Sprint, you may declare that you will move at Full Tilt. You must declare the Full-Tilt before you move.\nYou immediately gain the Full-Tilt status. While moving at Full-Tilt, you may not Retreat.\nYour Stride temporarily increases by 3 paces. (This bonus to Stride stacks with the bonus from Fast Mover, which gives you a Stride of at least 5.)\nAs per the standard rules: before or after a Dash, you may move any distance up to your Stride. When you Sprint, you may increase or decrease the Sprint distance by your Stride.\nAfter Dashing or Sprinting, note the direction in which you last moved. (If you are using miniatures, use a Full-Tilt Marker.) At the beginning of your next turn, you must roll your Body Dice and move that far in a straight line.\n\n@@REFRESH: X (Battle)\n\n@@STUNT: \"Run\"\nWhenever you declare a \"Run\" stunt, you may declare you will move at Full-Tilt. You must declare the Full-Tilt before you run.\nYou immediately gain the Full-Tilt status. While moving at Full-Tilt, you may not Retreat.\nAt the end of your Run, you may move up to an extra 12 paces in a straight line. Note the direction you moved - place a Full-Tilt counter next to your figure, pointing in that direction. At the beginning of your next turn, you must roll your Body Dice and move that far in a straight line.', 5, 319, '', 3, 'full-tilt-movement', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(202, 1, 202, 'Gang of Irregulars', 0, 0, NULL, 'Passive', '@@REQUIRES: Ally\n\n@@SECTION: Gang of Irregular Allies\nIn addition to your ally, you have a gang of people who follow you around and help you out. In game terms, an irregular is a minor character you pick up in the course of play who may or may not be around, next chapter.\n\n@@SECTION: At the beginning of the play-session, you pick up one irregular. You may declare you will roll your Mind and Gossip dice vs. 3. Each success you score is one more irregular who shows up. (Gifts like Insider and Local Knowledge may increase this roll.) You Ally assists you with this roll.\n\n@@SECTION: The same irregulars may hang around from chapter to chapter, or they may come and go, as the Host sees fit. When a new chapter starts, the Game Host may change the line-up of the irregulars. The Host may also call for a new Gossip roll, and the count of irregulars will re-set to the new roll\'s result.\n\n@@SECTION: The irregulars have d6s in all Traits, and all Gifts from their Species and Careers. These minor characters are usually the same Species and Career as your Ally ... but they might not be. The Game Host may assign new names, Species, and Careers at random. The Game Host may also rule that the nature of your character attract certain kinds of irregulars. For example, if your character is Streetwise, your irregulars may be gypsies, tramps, and thieves. If your character is Ordained, your irregulars may be religious folk. If your character has Nobility, your irregulars might be ne\'er-do-well dilettantes, etc.\n\n@@SECTION: Irregulars may bolster your number in combat, or they may be sent on various errands. Irregulars will have expenses, and as long as they\'re hanging out with you, they assume you will cover them. If you don\'t, there\'s no hard feelings - but they will disappear until the next\n\n@@SECTION: The irregulars have your best interests in mind, but their morale is questionable. Injured or Afraid irregulars will flee a battlefield at the first opportunity, and they won\'t return before the next chapter.\n\n@@SECTION: Irregulars won\'t betray your main character - they will disappear or skip town, and they will only warn you of danger if it is zero trouble to do so. If you live a dangerous life, your irregulars may get threatened by your enemies; their refusal to sell you out may get them humiliated, beaten up, or even killed.\n\n@@SECTION: As an adventurer, it\'s known that you live a dangerous life, so irregulars know what they\'re getting into ... but if it becomes obvious that too many people who hook up with you come to a nasty end, the Host may raise the difficulty for mustering up future irregulars, or they may declare you must re-train this Gift.', 5, 70, '', 6, 'gang-of-irregulars', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(203, 1, 203, 'Giant', 0, 0, NULL, 'PASSIVE: You have an Extra 1 pace of Range in hand-to-hand; PASSIVE: You are so big and obvious that others may claim a bonus d12 to detect you with Observation.', '@@R:equires: Body Trait of d12\n\n@@SECTION: Extra Large\nYou are huge - more than 20 hands tall, and more than 12 stone in weight. You stick out in a crowd.\nClothes require custom tailoring. Your armor costs and weighs twice as much.\nYou can carry more weight. (See \"Encumbrance\", page 90.)\nYou are so big and obvious that others may claim a bonus d12 to detect you with Observation.\n@@SECTION: Extra 1 pace of Range in hand-to-hand\nWhen you attack others with Brawling or with Melee Combat, you may strike at up to one pace further. That is, your Close attacks will strike 1 or 2 paces away from you, and your Reach attacks will strike 2 or 3 paces away from you.\nThere is no extended threatening range, this bonus is only for your attacks.', 5, 51, '', 16, 'giant', '2026-03-22 10:39:00', '2026-03-29 08:21:15'),
(204, 1, 204, 'Taoist Apprentice', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Requires Tàoist Magic Trappings Literacy: Zho-ngwén Language: Zhonggese Action \"ready Tàoist weapon\" Exhaust this Gift, then use the ready action to draw…', '@@R:equires: Tàoist Magic Trappings\n@@R:equires: Literacy: Zho-ngwén\n@@R:equires: Language: Zhonggese\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Tàoist weapon\"\n\n@@SECTION: Exhaust this Gift, then use the ready action to draw forth a Tàoist spell as a Magic weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nTàoist weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\n點 Clod of Earth\n點 Spark of Fire\n點 Spray of Water\n點 Sliver of Metal\n點 Splinter of Wood\n\n@@REFRESH: X (Battle)\n\n@@SECTION: New stunt \"minor magic effect\"\nAs a stunt, you may perform a minor magical effect Near you (that is, within 4 paces). Minor effects have no real combat usage, but they can impress people around you. You can move a handful of earth, or spark a candle to life, call forth a drink of water, bend a minor amount of metal, sprout a small plant, etc.\n\n@@SECTION: Your control over matter allows you to manipulate things up to 4 paces away with no penalty for lack of tools. As a general rule, you will have to use Craft skill to repair things or to manipulate materials. You could also use this stunt to grant an assist bonus to someone\'s Craft, Digging, Endurance, Presence, or Swimming dice.', 4, 514, '', 50, 'taoist-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(205, 1, 205, 'Guard Breaker', 0, 0, 1, 'Action; Exhaust; Action \"brawling or melee attack: guard breaker\" When you use a Brawling Attack or a Melee Attack against a target that is Guarding, you may Exhaust this Gift…', '@@REQUIRES: Counter-Tactics\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"brawling or melee attack: guard breaker\"\nWhen you use a Brawling Attack or a Melee Attack against a target that is Guarding, you may Exhaust this Gift and declare a guard breaker.\nYou may claim a bonus 2d12 to hit your target. (There is no bonus against targets who are not Guarding.)\nIf you hit, your damage becomes Weak. (The target rolls their Soak dice twice, to reduce damage from your attack.)', 5, 72, '', NULL, 'guard-breaker', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(206, 1, 206, 'Guard Soak', 0, 0, NULL, 'Passive', '@@REQUIRES: Resolve\n\n@@TRIGGER: failed defense when you are Guarding\nIf you just failed a defense while you are Guarding, you may include your Guarding die as a bonus Soak Die. (For example, if you claimed a d8 Guarding bonus to your defense, then you may also claim a d8 bonus to your Soak', 5, 78, 'failed defense when you are Guarding', 19, 'guard-soak', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(207, 1, 207, 'Gust of Wind', 0, 0, NULL, 'Action; Exhaust; Until the end of the Scene; Action \"ready Gust of Wind\" Exhaust this Gift, then use the ready action to draw forth a \"Gust of Wind\" weapon', '@@SECTION: With a thought, you bring forth a small whirlwind. With a gesture, the mistral arcs from your hand to explode into gale force.\n\n@@REQUIRES: Elemental Apprentice\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Gust of Wind\"\nExhaust this Gift, then use the ready action to draw forth a \"Gust of Wind\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 286, '', 12, 'gust-of-wind', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(208, 1, 208, 'The Way of Purity / Purity Apprentice', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Requires Purity Magic Trappings Literacy: Zho-ngwén Language: Zhonggese Action \"ready Purity weapon\" Exhaust this Gift, then use the ready action to draw…', '@@SECTION: Requires\nPurity Magic Trappings\nLiteracy: Zho-ngwén\nLanguage: Zhonggese\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Purity weapon\"\nExhaust this Gift, then use the ready action to draw forth a Purity spell as a Magic weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\n\n@@SECTION: Purity weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\n點 Call Down the Lightning\n點 Display of Propriety\n點 Righteous Arrow\n\n@@ACTION: Action \"rally a target with improved boons\"\nWhen you rally a target, you may claim the following boons.\n點 Reduce Dying to Injured and Unconscious\n點 Remove On Fire\n點 Remove Hurt', 4, 520, '', 51, 'the-way-of-purity-purity-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(209, 1, 209, 'Purity Magic Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \n點 one Xuanduan (玄端) Robe\n點 one Ruyi (如意) Wand, a small scepter with one round end\n點 one Scholar\'s Rod (the Wenren Zhang, 文人杖), an ornate staff with symbols of authority\n點 one Talisman: the Abacus (Juzu, 算盤), a counting tray with beads on spokes\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 4, 520, '', 25, 'purity-magic-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(210, 1, 210, 'High-Altitude Flyer', 0, 0, NULL, 'Passive', '@@REQUIRES: Flight\n\n@@REQUIRES: Species Trait of d8 or better Speed must be greater than Body\n\n@@REQUIRES: New stunt \"Gain higher Altitude\"\n\n@@REQUIRES: If you were already at Long altitude, you may rise to Very Long Altitude ... but only after moving 36 paces in a straight line. You may have to take multiple Flying Runs to move this many paces.\n\n@@TRIGGER: at Long altitude or higher\n\n@@TRIGGER: at Long altitude or higher\n\n@@ACTION: New action \"recover and refresh Gift of Flight\"\nWhenever you are at Long altitude or higher, you have a new combination action: Recover from Reeling and Refresh your Gift of Flight. You may not claim this combination action when you are Medium altitude or less.', 5, 319, 'at Long altitude or higher', 2, 'high-altitude-flyer', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(211, 1, 211, 'Trappings of Superior Archery', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \n點 Metal Bow\n點 12 barbed arrows\n點 12 regular arrows\n點 Silk Armor\n點 an elaborately-decorated ring (to protect the thumb when drawing back a bow string)\n點 a copy of the book Superior Theory of Archery\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 4, 473, '', 25, 'trappings-of-superior-archery', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(212, 1, 212, 'History', 0, 0, NULL, 'Passive; Bonus d12 to Know the Past When making rolls to know key dates and places; timelines of wars; and myths and lege ds, you may claim a bonus d12', '@@PASSIVE: Bonus d12 to Know the Past\nWhen making rolls to know key dates and places; timelines of wars; and myths and lege ds, you may claim a bonus d12.\nHistory helps with general knowledge - for the true secret history of a particular town or landscape, you\'ll want the Gift of Local Area Knowledge.', 5, 65, '', NULL, 'history', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(213, 1, 213, 'Hoarfrost', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Hoarfrost\" Exhaust this Gift, then use the ready action to draw forth a \"Hoarfrost\" weapon', '@@SECTION: It usually takes a cold, clear night for the white ice called hoarfrost to crystalize. This spell makes it happen in the blink of an eye. The pour souls in the area of effect are quite disoriented, to say the least.\n\n@@REQUIRES: Any two Gifts which have both the \"Water\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Hoarfrost\"\nExhaust this Gift, then use the ready action to draw forth a \"Hoarfrost\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nMark the center of the Hoarfrost effect. Everything within the explosion\'s range of that spot becomes covered with ice, which is bad footing, for the next five minutes. After that, the ice will melt if it\'s hot enough', 5, 296, '', 12, 'hoarfrost', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(214, 1, 214, 'Holy Clout', 1, 0, 2, 'Passive; Exhaust; Exhaust this Gift after casting a spell of the Holy nature to claim a bonus 2d8 with your casting dice', '@@PASSIVE: If you pray hard enough, you can accomplish great things.\n\n@@TRIGGER: Casting a Holy Spell\n\n@@REQUIRES: Mystic: White Magic\n\n@@REQUIRES: Add +1 Mark to Leadership\n\n@@REQUIRES: Add 1 Mark to your Leadership Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: Casting a Holy Spell\nExhaust this Gift after casting a spell of the Holy nature to claim a bonus 2d8 with your casting dice.\nThis gift can only be refreshed by praying once at each office of the day - that\'s eight prayers of 8 minutes each, 3 hours apart, over a total of 24 hours. Refreshing this Gift immediately removes any Lazarus Hearts that are still active.\nMultiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll. In addition, you may only refresh one Holy Clout per 24 hours.', 5, 307, 'Casting a Holy Spell', NULL, 'holy-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(215, 1, 215, 'The Way of Changes', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Your Gift allows you to ready the following magical weapons: 點 Collapsing the Weakest Column 點 Permeation of Wind 點 Quagmire of Doubt 點 The Turmoil of Silence…', '@@SECTION: Requires\nChanges Magic Trappings\nLiteracy: Zho-ngwén\nLanguage: Zhonggese\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Changes weapon\"\nExhaust this Gift, then use the ready action to draw forth a Changes spell as a Magic weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nChanges weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\n點 Collapsing the Weakest Column\n點 Permeation of Wind\n點 Quagmire of Doubt\n點 The Turmoil of Silence\n\n@@STUNT: \"Reason, Scare, Taunt, Trick with d12 bonus and Loud noise\"\nWhenever you attempt a Reason, Scare, Taunt, or Trick, you may invoke one of your many Changes spells to \"break the golden chain to release the dragon\", and you may claim a bonus d12 with your stunt. Using Changes magic to augment a stunt is quite theatrical and over-the-top, and it\'s a Loud noise.', 4, 510, '', 49, 'the-way-of-changes', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(216, 1, 216, 'Changes Magic Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \n點 one Daopao (道袍) Robe\n點 one J-ı nga-ng (金剛) Wand, a small scepter with two rounded ends\n點 one As-One-Wishes Rod (the Ruyi Jingu Bang, 如意金箍棒), a long staff banded with gold\n點 one Talisman: the Counting Beads (Juzu, 数珠), 108 beads on a long string\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 4, 510, '', 25, 'changes-magic-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(217, 1, 217, 'Ice Storm', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Ice Storm\" Exhaust this Gift, then use the ready action to draw forth a \"Ice Storm\" weapon', '@@SECTION: It\'s like the worst blizzard, chilling the flesh and bones, only it appears where you call it forth, covering the earth in frozen rain.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Ice Storm\"\nExhaust this Gift, then use the ready action to draw forth a \"Ice Storm\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nMake a note of where the center of the Ice Storm was. Everything near that point is covered in ice and has now bad footing. In warm weather, the ice will melt in five minutes. In the winter, it\'s just more ice', 5, 294, '', 12, 'ice-storm', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(218, 1, 218, 'Improved Ally', 1, 0, NULL, 'Passive', '@@REQUIRES: Ally\n\n@@REQUIRES: Gifted Ally\n\n@@REQUIRES: Your ally has a Gift. Choose an appropriate Gift for your Ally to have.\n\n@@REQUIRES: Allies may never have Major Gifts, because allies are always minor characters.\n\n@@REQUIRES: Multiple\n\n@@REQUIRES: You may take this Gift multiple times. Each time, your Ally gains another Gift.', 5, 70, '', 6, 'improved-ally', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(219, 1, 219, 'Improved Burrowing', 0, 0, 2, 'Action; (You can use a roll of Mind & Craft vs. a standard difficulty to build supports for long-term burrows.)', '@@REQUIRES: Species Trait of d8 or better Natural Weapon of Claws\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Stunt: Digging\"\nAs a stunt, you can dig at amazing speeds. Declare the terrain feature that you will burrow through.\nRoll your Body & Digging dice vs. a difficulty defined by terrain: 3 for loose dirt, 5 for wood, 7 for solid rock, 9 for solid metal.\nIf you Succeed, you dig a tunnel 1 pace wide and 1 pace deep. For each overwhelming success, you may declare the tunnel one pace deeper.\nThe tunnel might be awfully long, but it may collapse. (You can use a roll of Mind & Craft vs. a standard difficulty to build supports for long-term burrows.)', 5, 319, '', 20, 'improved-burrowing', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(220, 1, 220, 'Improved Spray', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better Spray\n\n@@REQUIRES: Bonus d12 with Spray Attack\n\n@@REQUIRES: When using your Spray Attack, you may claim a bonus d12.', 5, 320, '', 2, 'improved-spray', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(221, 1, 221, 'Improved Strength', 0, 0, NULL, 'Passive', '@@REQUIRES: Strength\n\n@@REQUIRES: Even Stronger Attacks; Carry More Weight\n\n@@REQUIRES: With all Brawling Attacks, Melee Attacks, and Thrown Attacks, you may claim a bonus d12 (instead of the bonus d8 from Strength). There is no benefit for Counter-Attacks or Parries.\n\n@@REQUIRES: You can carry even more weight. See \"Encumbrance\" in the Spot Rules.', 5, 81, '', 5, 'improved-strength', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(222, 1, 222, 'Navigation', 0, 0, NULL, 'Passive; Taken from Tradewinds Navigation', '@@REQUIRES: Literacy\n\n@@REQUIRES: Bonus d12 to Plot Long Sea Voyages\n\n@@REQUIRES: When plotting a navigation course for a sailing vessel, you may claim a bonus d12.\n\n@@PASSIVE: Taken from Tradewinds Navigation.', 1, 915, '', 23, 'navigation', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(223, 1, 223, 'Increased Trait: Career', 1, 0, NULL, 'PASSIVE: Increase Your Career Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\nMultiple\nYou may take this Gift multiple times, increasing a Trait even further, up to d12.\nManifold\nYou may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-career', '2026-03-22 10:39:00', '2026-03-29 08:22:10'),
(224, 1, 224, 'Increased Trait: Species', 1, 0, NULL, 'PASSIVE: Increase Your Species Trait by One Die Size.', '@@PASSIVE: Increase Trait by One Die Size\nPick one Trait: Body, Speed, Mind, Will, Species, or Career. Raise that Trait by one die size, up to d12.\nIf you have multiple Careers, each Career Trait must be increased separately.\nMultiple\nYou may take this Gift multiple times, increasing a Trait even further, up to d12.\nManifold\nYou may take this Gift multiple times to increase different Traits', 5, 65, '', 8, 'increased-trait-species', '2026-03-22 10:39:00', '2026-03-29 08:22:29'),
(225, 1, 225, 'Indomitable Fighter', 0, 0, 1, 'Passive; Exhaust; When you are sent Reeling from a foe\'s successful attack, declare you will Exhaust this Gift', '@@REQUIRES: Strength\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: you are sent Reeling from an Attack\nWhen you are sent Reeling from a foe\'s successful attack, declare you will Exhaust this Gift. Roll your Body Dice, Will Dice, and Strength Dice vs. 3, and count the successes. All foes within Close range of you must resist with their Body Dice. Will Dice, and Strength Dice. If they fail to resist, they are Pushed one pace away for each hit you scored.', 5, 81, 'you are sent Reeling from an Attack', 5, 'indomitable-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(226, 1, 226, 'Inkling', 0, 0, 5, 'Passive; Exhaust; Stunt \"anchor the subconscious\" Exhaust this Gift, then declare a crowd', '@@PASSIVE: Cognoscenti are infamous for being able to find hiddin cabals, cells, and criminals. In truth, the ways of the Green & Purple Magicks teach how to tap into a weak mind and find them later.\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"anchor the subconscious\"\nExhaust this Gift, then declare a crowd. Your attack dice are your Mind & Will vs. a group of target\'s Mind & Will. The lowest-rolling failure now carries your subconscious anchor.\nYou now have synecdoche with the anchored target.\nWhenever you have Focus, you may know the range that the target is away from you (Near, Close, Horizon, beyond the Horizon, etc.)\nIf you Refresh this Gift, you lose the anchor.', 5, 299, '', 12, 'inkling', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(227, 1, 227, 'Inner Might', 0, 0, 2, 'Passive; Before you make a roll that uses Body Dice, declare a bonus d12', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Strength\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: any roll that uses Body Dice\nBefore you make a roll that uses Body Dice, declare a bonus d12. This bonus d12 is just like more Body Dice', 5, 320, 'any roll that uses Body Dice', 20, 'inner-might', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(228, 1, 228, 'Insider with: [Choice]', 1, 0, NULL, 'Passive; Bonus d12 with Insider Crowd You have an \"in\" with a particular crowd - other people who have the same Insider Gift', '@@PASSIVE: Bonus d12 with Insider Crowd\nYou have an \"in\" with a particular crowd - other people who have the same Insider Gift.\nWhen you deceive, gossip, inquire, or negotiate with people who have the same Insider Gift as you, you may claim a bonus d12. This bonus d12 is only to impress your fellow insiders. Insider Gifts with a different crowd grant no bonus. Also, your Insider knowledge only impresses folks who know your specialized jargon and mannerisms - you gain no bonus to impress folks without the same Insider Gift.\nSample Insider Crowds\nBerla Feini (the members of Phelan society)\nThe Blessed (the priestesses and their attendants of the Doloreaux\'s Old Faith)\nThe Chivalrous (anyone who follows the code of conduct as described in the book On Chivalry, such as the Avoirdupois, Rinaldi, and Bisclavret)\nCognoscenti (the semi-anonymous practitioners of Green & Purple Magic)\nInvisible Guild (the brotherhood of criminals along the southwest coast of Calabria)\nPenitence (the abbots, bishops, and other higher- ups in the dominant religious order of Calabria)\nZhongese (the strange bureaucracy of far-off Zhongguo)\nManifold\nYou may take this Gift multiple times. Choose a different social crowd each time.', 5, 58, '', 22, 'insider-with-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(229, 1, 229, 'Instinctive Shot', 0, 0, 1, 'Action; Exhaust; \"ranged attack\" Before making a ranged attack, declare you will exhaust this Gift', '@@REQUIRES: Sharpshooter\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ranged attack\"\nBefore making a ranged attack, declare you will exhaust this Gift. When you play out your attack, negate all of the target\'s bonus defense dice from Cover and Concealment.', 5, 79, '', 5, 'instinctive-shot', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(230, 1, 230, 'Invulnerable Hide', 0, 0, 1, 'Passive; Exhaust; After damage is scored against you, but before you make a Soak Roll, exhaust this Gift', '@@REQUIRES: Species Trait of d8 or better Resolve\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: you suffer Damage\nAfter damage is scored against you, but before you make a Soak Roll, exhaust this Gift.\nThen, Subtract 1 from the Damage. Finally, make your Soak Roll.\nYou can only use Invulnerable Hide once per Damage effect.', 5, 320, 'you suffer Damage', 20, 'invulnerable-hide', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(231, 1, 231, 'Kataw Nature', 0, 0, NULL, 'Passive; Gain a new Species Trait: Kataw d4 (Include with Deceit, Presence, Swimming) You have an extra species trait, the Kataw trait', '@@PASSIVE: Somewhere deep within your blood are the aspects of the kataw, the mysterious amphibians that are scattered throughout the Furanthur Isles. You may have widely-set eyes, webbed fingers or toes, or scaly ridges under your fur.\n\n@@SECTION: Gain a new Species Trait:\n\n@@SECTION: Kataw d4\n\n@@SECTION: (Include with Deceit, Presence, Swimming)\n\n@@FLAVOUR:\nYou have an extra species trait, the Kataw trait.\n\n@@FLAVOUR:\nYou are skilled at moving in water, and you can conceal your strange nature from others.\n\n@@SECTION: This new species trait can be increased normally, with the gift of Increased Trait: Species.\n\n@@FLAVOUR:\nYou can buy Natural Gifts with experience, such as Deep Diver and Fast Swimmer.', 1, 919, '', 2, 'kataw-nature', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(232, 1, 232, 'Knack For: [Choice]', 0, 1, 2, 'Passive; Exhaust; \"+1\" Skill Mark in [Skill of choice] Add one Mark to your Skill of choice', '@@PASSIVE: \"+1\"  Skill Mark in [Skill of choice]\nAdd one Mark to your Skill of choice.\n\n@@REFRESH: X (Respite)\n\n@@SECTION: After any roll that uses dice from your Skill of choice, you may claim the benefit of your Knack. Exhaust this Gift, then re-roll all your dice - Skill Dice, Trait Dice, etc. The second roll stands.\nCharacter Development\nIf you lose this Gift, you also lose the extra Mark you gained from this Gift.\nManifold\nYou may take this Gift more than once. You must choose a different Skill each time.', 5, 65, '', 8, 'knack-for-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(233, 1, 233, 'Knockdown Strike', 0, 0, 1, 'Action; Exhaust; Action \"knockdown attack\" You may use any brawling or melee attack to make a knockdown attack', '@@REQUIRES: Counter-Tactics\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"knockdown attack\"\nYou may use any brawling or melee attack to make a knockdown attack. First, declare your knockdown attack against any foe, and exhaust this Gift. Then, play out your attack. If you succeed, your foe is Knocked Down, in addition to any other effects.', 5, 72, '', 5, 'knockdown-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(234, 1, 234, 'Knowing the True Nature', 0, 0, 2, 'Passive; Exhaust; When using Inquiry, Leadership, or Observation, exhaust this Gift', '@@REQUIRES: Species Trait of d8 or better Keen Nose\n\n@@REFRESH: X (Respite)\n\n@@SECTION:\nWhen using Inquiry, Leadership, or Observation, exhaust this Gift. Instead of rolling, Maximize your dice instead.', 5, 320, '', 20, 'knowing-the-true-nature', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(235, 1, 235, 'Landslide', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Landslide\" Exhaust this Gift, then use the ready action to draw forth a \"Landslide\" weapon', '@@FLAVOUR:\nAn avalanche of dirt and debris falls from nothing, to disappear a a few minutes later. However, the bruises and broken bones remain.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Landslide\"\nExhaust this Gift, then use the ready action to draw forth a \"Landslide\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nMake a note of where the Landslide\'s center point.\nEverything near that point is covered in rubble, and is now bad footing until the end of the Scene (about five minutes).', 5, 288, '', 12, 'landslide', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(236, 1, 236, 'Language', 0, 1, NULL, 'PASSIVE:  You can speak a language', '@@FLAVOUR:\nYou can speak a language\nEvery character starts with one native language. If you don\'t understand a language, you may have penalties to be understood. Gossip and Negotiation are impossible if you don\'t understand the speaker\'s language. Inquiry will only get you so far - you might know if they\'re telling the truth or lying, but you won\'t know what they\'re saying! Presence transcends language barriers.\nReading and writing is covered by Literacy. It\'s quite possible to be able to speak a language but not be able to read it!\nManifold\nYou may take this Gift multiple times. Each time, choose a different language.', 5, 55, '', 14, 'language', '2026-03-22 10:39:00', '2026-03-29 08:30:31'),
(237, 1, 237, 'Law', 0, 0, NULL, 'Passive; Bonus d12 with Legal Matters When rolling to prosecute criminals, to defend yourself in court, and to know the rights that people have under the law, you may…', '@@PASSIVE: Bonus d12 with Legal Matters\nWhen rolling to prosecute criminals, to defend yourself in court, and to know the rights that people have under the law, you may claim a bonus 12.', 5, 58, '', 22, 'law', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(238, 1, 238, 'Lazarus Heart', 0, 0, 5, 'Passive; The Lazarus Heart remains on the target, invisible except to those trained in the Supernatural, who can perceive it as a glowing mark on the target\'s breast,…', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Cleric\'s Trappings (any)\n\n@@REQUIRES: White Magic Apprentice\n\n@@REQUIRES: Mystic: White Magic\n\n@@REQUIRES: Any three \"White Magic Journeyman\" Gifts\n\n@@REQUIRES: Insider: Church of Penitence\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Apply the Lazarus Heart\"\nThe Lazarus Heart is one of the few spells that works on a deceased target ... and it is also one of the most controversial.\nThe Lazarus Heart remains on the target, invisible except to those trained in the Supernatural, who can perceive it as a glowing mark on the target\'s breast, right where their heart is.\nThe Lazarus Heart is triggered when the target becomes Dying, Dead, or Overkilled. If you cast the Lazarus Heart on a target that\'s already Dying, Dead, or Overkilled, the spell triggers immediately.\nWhen activated, roll the target\'s Will and your Mind and Academics. Keep the two sets of dice separate. Your opposed difficulty is d8 if the target is Dying, or d12 if the target is Dead or Overkilled.\nIf you score one success, replace the Dying status with Fatigued.\nIf the target is Dead, you must score one success for each hour (or part thereof) that the target has been dead. If you have enough successes, the target comes back to the world of the living - Sick, but alive.\nIf the target was Overkilled, the target may still survive, as above, but they are also horribly disfigured. This disfigurement may result in the forced re-training of one or more Gifts, at the discretion of the Game Host\nIf you Tie against the difficulty, nothing happens for this round. The Lazarus Heart will try again next round, on the target\'s turn. (If the target is Dying, it may tragically happen that the target will become Dead before the Lazarus Heart tries again.)\nIf you Fail, consult the dice. If it\'s your dice that rolled the lowest, then you (wherever you are) immediately become Afraid and Confused. If it\'s the target\'s dice that rolled lower, then the target becomes Afraid and Confused (if they\'re still alive enough) ... and there is a slight possibility that the target may rise as one of the Undead. Either way, the Lazarus Heart immediately expires.\nThis gift can only be refreshed by praying once at each office of the day - that\'s eight prayers of 8 minutes each, 3 hours apart, over a total of 24 hours. Refreshing this Gift immediately removes any Lazarus Hearts that are still active.', 5, 307, '', 4, 'lazarus-heart', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(239, 1, 239, 'Licensed Fool', 0, 0, 4, 'Passive; Exhaust; Usually, Exhausting this Gift means \"playing dumb\" and getting out of some situation that would embarrass someone with more station than you ... but a subtle…', '@@FLAVOUR:\nYou are a fool ... by law.\n\n@@FLAVOUR:\nYou are a court jester\n\n@@FLAVOUR:\nYou are officially licensed to be a royal fool, either by decree or by law.\n\n@@FLAVOUR:\nYou are expected not just to entertain the court, but you are also expected to say what everyone else is too afraid to say. As a fool, you are expected to insult people, to call out liars and cheats no matter how influential they are, and to point out flaws in plans that the invested can\'t bring themselves to discuss.\n\n@@REFRESH: X (Influence)\n\n@@SECTION: Sway the opinions of others\n\n@@SECTION: You may exhaust this Gift to push influence over other folks ... even after failing a roll! Usually, Exhausting this Gift means \"playing dumb\" and getting out of some situation that would embarrass someone with more station than you ... but a subtle fool can advise, can plant ideas in people\'s heads, and can gain access to places that commoners aren\'t usually allowed.\n\n@@SECTION: Refer to the Influence rules for more details.', 2, 355, '', 10, 'licensed-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(240, 1, 240, 'Lightning Bolt', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@FLAVOUR:\nThe small, sparkling nimbus of your apprentice spell enlarges into a crackling ball of electricity. Targets struck by it dance in agony.\n\n@@REQUIRES: Elemental Apprentice Literacy\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Air to Lightning Bolt\"\nTo use this ability, you must have a \"Create Air\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Create Air\" weapon becomes a \"Lightning Bolt\".', 5, 286, '', NULL, 'lightning-bolt', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(241, 1, 241, 'Line Breaker', 0, 0, NULL, 'Passive', '@@REQUIRES: Strength\n\n@@TRIGGER: moving on the battlefield\nWhen you move on the battlefield, for any reason, you may move through the spaces of any unfriendly, Reeling combatants. Those combatants are pushed 1 pace to the side (your choice of direction). If the combatant can\'t be pushed into an open space for any reason, then the combatant is Knocked Down and you must stop moving at that point.\nThis ability only affects Reeling combatants. Wary, reactive combantants block your path, as normal', 5, 81, 'moving on the battlefield', 5, 'line-breaker', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(242, 1, 242, 'Local Knowledge: [Choice]', 1, 1, NULL, 'PASSIVE: Bonus d12 with a Certain Place You know ', '@@PASSIVE: Bonus d12 with a certain place\nYou know a certain place - a borough of a large city, your home town, the sewer complex underneath the city, etc. - like it was the back of your hand. You can claim an extra d12 on rolls to know where things are, to gossip with the natives of your local knowledge, and to elude pursuit. At the Game Host\'s discretion, you can claim a bonus d12 on other rolls related to your local knowledge, as well.\n\n@@LIMIT: Manifold\nYou can take this Gift multiple times. Each time, you must choose a different landscape for your Local Knowledge.\n\n@@NOTE:\nThis is an excellent Gift for local guides, city officials, and small-time gangs of crooks. The \"home turf advantage\" provided by this Gift will give them an edge against Player-Characters, who usually have better dice in their general abilities but just \"don\'t know the area like these folk do.\"\nEvery Player-Character begins the game with one Local Knowledge Gift. This Gift is often immediately re- trained for more experience. See the Character Development chapter for more details.', 5, 58, '', 22, 'local-knowledge-choice', '2026-03-22 10:39:00', '2026-03-29 08:29:59'),
(243, 1, 243, 'Locating', 0, 0, 5, 'Passive; Exhaust; You may claim the following bonuses: bonus d12 from Geography bonus d12 if the subject is in a landscape covered by your Local Knowledge', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings Thaumaturgy Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"locate a target using synecdoche\" You must have a synecdoche link to the target. Exhaust this Gift.\nRoll your Mind, Academics, and Searching dice vs. 3. You may claim the following bonuses:\nbonus d12 from Geography bonus d12 if the subject is in a landscape covered by your Local Knowledge. (Roll this die separately, in case it\'s in doubt that the target is in the landscape.)\nIf the target has any Supernatural Dice, the Game Host rolls those vs. 5. Each success removes one of yours.\nOne success will tell you the direction to that subject, if they are within Long range. If that subject is within Medium range, the spell tells you the distance, as well.\nTwo successes will tell you the direction, if that subject is within Extreme range.\nThree successes will tell you the direction, if that subject is within the bounds of the Horizon.\nFour successes will tell you the direction regardless of how far away the target is.\nIf your spell successfully points you in the right direction, refresh this Gift immediately. If you fail to score enough successes to find the target, exhaust this Gift.\nYou may refresh this Gift at the next Respite', 5, 309, '', 20, 'locating', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(244, 1, 244, 'Lorica', 0, 0, 5, 'Passive; Exhaust; After you, or an ally within Medium range, makes a Soak Roll, you may declare you will exhaust this Gift', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Cleric\'s Trappings (any)\n\n@@REQUIRES: White Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@TRIGGER: you or ally makes a Soak Roll\nAfter you, or an ally within Medium range, makes a Soak Roll, you may declare you will exhaust this Gift. Your Academics & Supernatural dice may then be claimed as bonus Soak Dice.\nThis gift can only be refreshed by praying for 8 minutes during the Office of Lucernarim (6 pm to 9 pm).', 5, 306, 'you or ally makes a Soak Roll', 12, 'lorica', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(245, 1, 245, 'Luck', 1, 0, 3, 'Passive; In any one contest, you can use your multiple Luck Gifts to re-roll the same die two more times each time you don\'t like the way it comes up, but you cannot…', '@@REFRESH: X (Chapter)\n\n@@TRIGGER: any die roll involving your character\nAfter any die roll, pick up any one die - either one you rolled or one your opposition rolled - and roll it two more times. From the three rolls, keep any one roll that you like. You may only modify one die per contest, and it must be one that involves your character.\nMultiple\nYou can take this Gift multiple times. In any one contest, you can use your multiple Luck Gifts to re-roll the same die two more times each time you don\'t like the way it comes up, but you cannot force a re-roll of any other dice.\nNote\n\"Dice that involve your character\" are subject to review by the Game Host. For example, your Initiative roll personally involves you, but someone else\'s doesn\'t. Likewise, a foe rallying another foe to attack you isn\'t a contest that personally involves you, either. Luck should be good fortune or miracle saves; it should not be a hammer that a character uses to have their way.', 5, 65, 'any die roll involving your character', 8, 'luck', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(246, 1, 246, 'Mad Sprint', 0, 0, 1, 'Passive; Exhaust; Add Body dice to Sprint distance After playing out a Sprint, for any reason, declare you will Exhaust this Gift', '@@REQUIRES: Fast Mover\n\n@@REFRESH: X (Battle)\n\n@@PASSIVE: Add Body dice to Sprint distance\nAfter playing out a Sprint, for any reason, declare you will Exhaust this Gift. Then, roll your body die and add that to your Sprint distance.\nSprints are always in a straight line.', 5, 74, '', 5, 'mad-sprint', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(247, 1, 247, 'Maelstrom', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Maelstrom\" Exhaust this Gift, then use the ready action to draw forth a \"Maelstrom\" weapon', '@@SECTION: People subjected to this spell describe it as being im whirlpool, swirling about and unable to think. While t a moment, the bewilderment lingers on.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Maelstrom\"\nExhaust this Gift, then use the ready action to draw forth a \"Maelstrom\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 295, '', 12, 'maelstrom', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(248, 1, 248, 'Mage Seal', 0, 0, 5, 'Action; You may refresh this gift as a Refresh action', '@@SECTION: Thaumaturges know how to bind doors fast.\n\n@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings Thaumaturgy Apprentice\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"magically seal\"\nYou stare at a door, window, portal, or other receptacle with Medium range. That portal immediately slams shut and becomes magically sealed. Anyone other than you who attempts to open it, smash it, pick the lock, listen to what\'s on the other side, or otherwise interact with the portal suffers a penalty of your Supernatural Dice.\nYou may refresh this gift as a Refresh action. When you do, the Mage Seal expires.', 5, 309, '', NULL, 'mage-seal', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(249, 1, 249, 'Magic Replay', 0, 0, 3, 'Passive; Exhaust; If, after rolling your dice to use magic, to defend against magic, or to resist magic of any kind, you are unhappy with the result, you may Exhaust this Gift', '@@PASSIVE: Thaumaturges don\'t make simple mistakes.\n\n@@TRIGGER: any die roll involving magic\n\n@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings Thaumaturgy Apprentice Mystic: Thaumaturgy Reflection\n\n@@REQUIRES: Reprisal\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: any die roll involving magic\nIf, after rolling your dice to use magic, to defend against magic, or to resist magic of any kind, you are unhappy with the result, you may Exhaust this Gift. Both you and your opposition must now re-roll all their dice. The second result stands, for better or worse.', 5, 311, 'any die roll involving magic', NULL, 'magic-replay', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(250, 1, 250, 'Magic Save', 0, 0, 3, 'Passive; Exhaust; Exhaust this Gift after you are hit by a Magic Attack. Negate any and all results that Magic Attack just inflicted against yourself', '@@REQUIRES: Mystic (any)\n\n@@REQUIRES: +1 Mark in Supernatural\n\n@@REQUIRES: You may claim +1 Mark in Supernatural Skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: hit by magic effect\nExhaust this Gift after you are hit by a Magic Attack. Negate any and all results that Magic Attack just inflicted against yourself.\nAfter negating the Magic Attack, you immediately become Reeling, Injured, and Confused.', 5, 64, 'hit by magic effect', 21, 'magic-save', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(251, 1, 251, 'Mantle of Fire', 0, 0, 2, 'Passive; Declare an attack, rolling your Body, Strength, and Brawling vs. their defense - Damage +0 Weak, On Fire', '@@FLAVOUR:\nThis spell has been retired from popular use, because of its association with the Heliodromes, a heretic cult bent on destruction of all churches and states. The Dunwasser elementalists no longer teach it.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Frenzy\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Insider with either the Dunwasser Academy or the Heliodromes\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@SECTION: At any time during combat, you may declare that you will wear the Mantle of Fire. Your head and shoulders burst into flame.\nWhile the Mantle of Fire is upon you, you are On Fire, but you are also immune to being On Fire. (Other fire spells affect you normally.)\nYou may attempt to set others on fire as if your hands were torches. Declare an attack, rolling your Body, Strength, and Brawling vs. their defense - Damage +0 Weak, On Fire.\nWhile the Mantle of Fire is lit, you now have an extra off-hand, but only for holding spells with the Fire descriptor.\nThe Mantle lasts for the next five minutes.', 5, 293, '', 12, 'mantle-of-fire', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(252, 1, 252, 'Marching Teeth', 0, 0, 2, 'Passive; The over-educated foreigners like to label this regeneration as \"polyphyodontry.\" X: respite +2 bite damage, but you lose the ability to bite until your next…', '@@FLAVOUR:\nA lot of critters in the far Tradewinds can regrow their teeth. Many of them have new teeth constantly growing behind their old ones. Sharks and the like may have two or more rows of teeth. The over-educated foreigners like to label this regeneration as \"polyphyodontry.\"\n\n@@SECTION: X: respite\n\n@@SECTION: +2 bite damage, but you lose the ability to bite until your next respite\n\n@@SECTION:\nAfter hitting a target with your bite attack - but before the target soaks the damage - tap this gift. Your bite does +2 damage, and the target escapes from your grapple. A significant amount of your teeth break or fall out. (Many of them are now embedded in your target\'s flesh!). You cannot use your bite again until this gift is recharged.\n\n@@FLAVOUR:\nYou can recharge this gift after a good respite, when enough of your teeth will grow back so that you can bite again.', 1, 920, '', 2, 'marching-teeth', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(253, 1, 253, 'Mark of Nine', 0, 0, 2, 'Action; Action \"Attack: Brand one of a Crowd with the Mark of Nine\" Declare a Crowd of people, and roll your Will, Deceit, & 3d6', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Necromancer\'s Trappings Apprentice Necromancy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Attack: Brand one of a Crowd with the Mark of Nine\"\nDeclare a Crowd of people, and roll your Will, Deceit, & 3d6. Everyone in the Crowd rolls their Mind, Will, Deceit, and Supernatural. The lowest roller who fails to resist is branded with the Mark of Nine.\nThe Mark of Nine is invisible on the target. It can only be found with a thorough search and a successful roll of Supernatural vs. 5.\nIf you Refresh this Gift, your Mark of Nine disappears from the target.\nFocus \"Find the Mark of Nine\"\nWhenever you have Focus, you know the direction you must face to find the target of your Mark of Nine. You also know the Range band the target is in (\"Close\", \"Near\", \"Short\", \"Horizon\", or \"beyond Horizon\", etc.)\nIf you have line of sight, then you may strike out against the target with no penalties for concealment. The Mark of Nine counts as a synecdoche link to the target.', 5, 314, '', 12, 'mark-of-nine', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(254, 1, 254, 'Marking of Territory', 0, 0, 2, 'Action; Action \"stunt: mark territory\" As a stunt, you can make a territorial mark, using natural means such as by scratching something with your claws, digging the…', '@@REQUIRES: Species Trait of d8 or better Keen Nose\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"stunt: mark territory\"\nAs a stunt, you can make a territorial mark, using natural means such as by scratching something with your claws, digging the ground to make a form, or by applying special spoors.\nIf you make your mark inside your Species\' Habitat, it lasts for a month and anyone within Medium Range of your mark with a Species Trait less than yours suffers a penalty equal to your Species Trait on all rolls.\nIf you make your mark outside of your Species Habitat, it lasts for a week and anyone within Short Range of your mark with a Species Trait less than yours suffers a penalty equal to your Species Trait on all rolls.\nThis penalty lasts until the target is Rallied or until they leave range of your mark. (Note that anyone who would Rally the target might suffer the penalty from your mark!) A single mark can only affect a target once.\nWhen you make the mark, you may also add on an extra simple message with the mark, such as \"A great evil happened here\", \"I will come by this place again\", \"Next time, send better warriors\", etc. The message should be very simple, something an animal could communicate - the Game Host should use their discretion. Anyone with the Gift of Keen Nose and the same Species Habitat as you will discer your mark within Medium range, and they will understand your message', 5, 320, '', 20, 'marking-of-territory', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(255, 1, 255, 'Mass Agony', 0, 0, 2, 'Passive', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Necromancer\'s Trappings Apprentice Necromancy\n\n@@PASSIVE: X (Respite) Action \"Aim to upgrade Torment to Mass Agony\"\nTo use this ability, you must have a \"Torment\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Torment\" weapon becomes a \"Mass Agony\".', 5, 314, '', 12, 'mass-agony', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(256, 1, 256, 'Mass Animation', 0, 0, 2, 'Passive', '@@TRAPPINGS: Mystic: Necromancy Necromancer\'s Trappings Animation\n\n@@REQUIRES: Curse\n\n@@PASSIVE: X (Respite) Action \"Rally a Group of corpses into Marionettes\"\nDeclare a Group of dead bodies within Medium range of you. The body must not have been Overkilled.\nRoll your Will, Leadership, & 3d6. Each corpse resists with 3d6. If you are successful, the corpse becomes a Hurt, Injured Marionette under your control. If the body is still fresh, treat it as a Typical Zombie; if the body is nothing but bones, treat it as a Typical Skeleton.\nThe normal rolls for Groups apply - you may only animate a number of bodies equal to your highest showing die.\nFor the next five minutes, you must take the Rally action to order the animated corpses to do your bidding. Roll your Will & Leadership as normal; the highest showing die is the number of corpses you may control. (You may also use your ability to unleash undead to turn the animated corpses into Berserk monsters - in which case, you no longer control them.)\nAfter five minutes, the bodies return to lifelessness.', 5, 315, '', 12, 'mass-animation', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(257, 1, 257, 'Mass Blindness', 0, 0, 2, 'Action; Exhaust; Action \"attack a group with Blindness\" Exhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets', '@@REQUIRES: Green & Purple Apprentice Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic Blindness\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"attack a group with Blindness\"\nExhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets.\nRoll your Mind & Will dice. All targets roll their Body & Mind dice. Any who Fail to beat your dice are Blinded.', 5, 302, '', 12, 'mass-blindness', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(258, 1, 258, 'Mass Marionette', 0, 0, 2, 'Action; Exhaust; Action \"Magic attack: Marionette\" Exhaust this Gift, then declare an attack on a group: your Mind & Will vs. the target\'s Body, Mind, and Will', '@@REQUIRES: Green & Purple Apprentice Insider with the Cognoscenti Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic Paralysis\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Magic attack: Marionette\"\nExhaust this Gift, then declare an attack on a group: your Mind & Will vs. the target\'s Body, Mind, and Will.\nEach target that Fails becomes your Marionette', 5, 302, '', 12, 'mass-marionette', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(259, 1, 259, 'Mass Mesmerisism', 0, 0, 3, 'Action; Exhaust; Action \"attack a group with Mesmerism\" Exhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets', '@@REQUIRES: Green & Purple Apprentice Insider with the Cognoscenti Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic Mesmerism\n\n@@REQUIRES: Oratory\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Action \"attack a group with Mesmerism\"\nExhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets.\nRoll your Mind & Will dice. All targets roll their Mind & Will dice. Any who Fail to beat your dice are Mesmerized.', 5, 302, '', 12, 'mass-mesmerisism', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(260, 1, 260, 'Mass Paralysis', 0, 0, 2, 'Action; Exhaust; Action \"attack a group with Paralysis\" Exhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets', '@@REQUIRES: Green & Purple Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REQUIRES: Paralysis\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"attack a group with Paralysis\"\nExhaust this Gift, then use the Attack action to launch a Magic Attack against a Group of targets.\nRoll your Mind & Will dice. All targets roll their Body & Will dice. Any who Fail to beat your dice are Immobilized.', 5, 299, '', 12, 'mass-paralysis', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(261, 1, 261, 'Meator Swarm', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Find the attacker\'s highest- showing die, and drop that many small fires in the area of the explosion', '@@SECTION: Resembling a swarm of insects more than anything else, when you toss this spell, red-hot balls of fire fly in all directions, exploding with loud crackles. Use of this spell within city limits is punishable by death.\n\n@@REQUIRES: Any two Gifts which have both the \"Fire\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Meteor Swarm\"\nExhaust this Gift, then use the ready action to draw forth a \"Meteor Swarm\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nAt the discretion of the Game Host, the Meteor Swarm may start fires. Find the attacker\'s highest- showing die, and drop that many small fires in the area of the explosion. For example, if the attacker rolled 11, 7, 3, then drop eleven small fires in the area of effect.', 5, 293, '', 12, 'meator-swarm', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(262, 1, 262, 'Melee Fervor', 0, 0, NULL, 'Passive; Will and Melee Combat With a Melee Weapon, you can use Will and Melee Combat Dice (instead of Body and Melee Combat)', '@@PASSIVE: Will and Melee Combat\nWith a Melee Weapon, you can use Will and Melee Combat Dice (instead of Body and Melee Combat).\nWith a Brawling Attack, you can use Will and Brawling Dice (instead of Body and Brawling Dice).\n\n@@NOTE:\nYou can only use Melee Fervor with Brawling Skill if you have the Gift of Brawling Fighter', 5, 55, '', 14, 'melee-fervor', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(263, 1, 263, 'Melee Finesse', 0, 0, NULL, 'Passive; Speed & Melee Combat With a Melee Weapon, you can use Speed and Weapon Melee Combat Dice (instead of Body and Melee Combat Skill) when Attacking,…', '@@PASSIVE: Speed & Melee Combat\nWith a Melee Weapon, you can use Speed and Weapon Melee Combat Dice (instead of Body and Melee Combat Skill) when Attacking, Counter-Attacking, and Parrying ... however, your dice will be limited by your Encumbrance.\n\n@@NOTE:\nYou can only use Melee Finesse with Brawling Skill if you have the Gift of Brawling Fighter.', 5, 52, '', 16, 'melee-finesse', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(264, 1, 264, 'Melee Guile', 0, 0, NULL, 'Passive; Mind and Melee Combat With a Melee Weapon, you can use Mind and Melee Combat Dice (instead of Body and Melee Combat)', '@@PASSIVE: Mind and Melee Combat\nWith a Melee Weapon, you can use Mind and Melee Combat Dice (instead of Body and Melee Combat).\nWith a Brawling Attack, you can use Mind and Brawling Dice (instead of Body and Brawling Dice).\n\n@@NOTE:\nYou can only use Melee Guile with Brawling Skill if you have the Gift of Brawling Fighter.', 5, 55, '', 14, 'melee-guile', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(265, 1, 265, 'Mesmerism', 0, 0, 2, 'Action; Exhaust; Exhaust this Gift', '@@FLAVOUR:\nThe signature spell of the Cognoscenti, this spell pu s the target in a hypnagogic state, where they will respond to simple questions in a monotone, and they are highly prone to suggestion.\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Aim to upgrade Perplex to Mesmerism\"\nTo use this ability, you must have a \"Perplex\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Perplex\" weapon becomes a \"Mesmerism\".', 5, 299, '', 12, 'mesmerism', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(266, 1, 266, 'Meta Clout', 1, 0, 3, 'Passive; Exhaust; Add +1 Mark to Supernatural Add 1 Mark to your Academics Skill. Exhaust this Gift after casting any spell to claim a bonus d12 with your casting dice', '@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Mystic: Thaumaturgy\n\n@@REQUIRES: Mystic: White Magic\n\n@@PASSIVE: Add +1 Mark to Supernatural\nAdd 1 Mark to your Academics Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: Casting any Spell\nExhaust this Gift after casting any spell to claim a bonus d12 with your casting dice.', 5, 311, 'Casting any Spell', 4, 'meta-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(267, 1, 267, 'Meta Mnemonic', 0, 0, 3, 'Passive; Extra action: \"refresh any one Magic Gift: Battle, Respite, or Chapter\" On your turn, you may Refresh any one gift that has the \"Magic\" descriptor, that is…', '@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Mystic: Thaumaturgy\n\n@@REQUIRES: Mystic: White Magic\n\n@@REQUIRES: Add +1 Mark to Supernatural\n\n@@REQUIRES: Add 1 Mark to your Supernatural Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh any one Magic Gift: Battle, Respite, or Chapter\"\nOn your turn, you may Refresh any one gift that has the \"Magic\" descriptor, that is either a Battle Gift, Respite Gift, or Chapter Gift.', 5, 311, '', 4, 'meta-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(268, 1, 268, 'Mighty Grip', 0, 0, NULL, 'Passive', '@@REQUIRES: Strength\n\n@@REQUIRES: Use Melee Weapons Without Awkwardness\n\n@@REQUIRES: You may use Awkward weapons as if they were typical, easy weapons. (Characters without this Gift are sent Reeling when they use an Awkward weapon to attack or to counter-attack.)', 5, 81, '', 5, 'mighty-grip', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(269, 1, 269, 'Mighty Strike', 0, 0, 1, 'Action; Exhaust; Action \"melee attack: mighty strike\" Exhaust this Gift, then declare a melee attack against a target', '@@REQUIRES: Strength\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"melee attack: mighty strike\"\nExhaust this Gift, then declare a melee attack against a target. If your attack hits, your attack causes +1 Damage, above and beyond all other damage, and you may add the \"Push 1\" effect.', 5, 81, '', 5, 'mighty-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(270, 1, 270, 'Militia Leader', 0, 0, NULL, 'Passive', '@@REQUIRES: True Leader\n\n@@ACTION: Action \"rally a target with Local Knowledge\"\nWhen you Rally a target that has Local Knowledge, and when the target is in the landscape of their Local Knowledge, you may claim a bonus d12 with your Leadership dice', 5, 82, '', 5, 'militia-leader', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(271, 1, 271, 'Mob Fighter', 0, 0, 1, 'Passive', '@@REQUIRES: Counter-Tactics\n\n@@TRIGGER: melee attack incapacitates target\nWhen your melee attack inflicts a Dying, Dead, Overkill, Asleep, or Unconscious result on a target, you may immediately sweep to strike a new target.\nYou may still sweep even if the target negates your result by using a Saving Gift.\nYou may only claim the sweep attack on your turn.\nMob Fighter does not help with counter-attacks.', 5, 72, 'melee attack incapacitates target', 5, 'mob-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(272, 1, 272, 'Mounted Fighter', 0, 0, NULL, 'Passive; Mount includes your Riding Dice with defenses Whenever you are riding a mount, your mount may include all of your Riding Dice with its Counter-Attacks,…', '@@PASSIVE: Mount includes your Riding Dice with defenses\nWhenever you are riding a mount, your mount may include all of your Riding Dice with its Counter-Attacks, Parries, and Dodges. See \"Mounted Combat\" in the Spot Rules for more details.', 5, 52, '', 16, 'mounted-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(273, 1, 273, 'Mystic of: [Choice]', 0, 0, NULL, 'Passive; Bonus d12 with a Particular Way of Magic You have a keen understanding of the unknown', '@@PASSIVE: Bonus d12 with a Particular Way of Magic\nYou have a keen understanding of the unknown.\nWhen doing academic research into the history of your specialty, when inquiring about incidents related to your specialty, or when attempting to detect supernatural traces of your specialty, you may claim a bonus d12.\nSample Specialties include:\nElementalism (Air, Earth, Fire, Water, Star) Black Magic (Unholy)\nWhite Magic (Holy)\nGreen & Purple Magic (Psychic)\nBlessed Magic (Blessed)\nDruid Magic (Druid)\nThaumaturgy (Theurgic)', 5, 55, '', 14, 'mystic-of-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(274, 1, 274, 'Obnoxious Fool', 0, 0, NULL, 'Passive; Enraged/Berserk foes have d12 penalty to attack targets that aren\'t you If a hostile combatant is Enraged or Berserk, and they can trace line of sight to you,…', '@@PASSIVE: There\'s something about you that people hate just so much.\n\n@@SECTION: Enraged/Berserk foes have d12 penalty to attack targets that aren\'t you\n\n@@SECTION:\nIf a hostile combatant is Enraged or Berserk, and they can trace line of sight to you, then they have a d12 penalty to all their attacks that do not include you as a target.', 2, 356, '', 10, 'obnoxious-fool', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(275, 1, 275, 'Overconfidence', 0, 0, NULL, 'Passive; Gain a Bonus by Making Anything Harder There\'s no simple task that you can\'t find some way to make more dramatic', '@@PASSIVE: Gain a Bonus by Making Anything Harder\nThere\'s no simple task that you can\'t find some way to make more dramatic. Before rolling dice, declare an offer of a bonus d12 to your opposition.\nIf your opposition accepts the d12, you may also claim a bonus d12. You may only gain a single bonus d12 from this ability.\nIn a skill contest (such as an Attack vs. Defense), the other character makes the choice to accept or not.\nAgainst a fixed difficulty number, the Game Host makes the choice to accept.\nNote\nRemember, the other side has to claim the d12 before you can claim the bonus d12. In some cases, the Game Host may rule that the extra dice are inappropriate.\nIf you are Overconfident, and an Overconfident character offers you the d12, then you may not refuse - you must always accept. However, the maximum overconfidence bonus to any one character is a single d12.', 5, 55, '', 14, 'overconfidence', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(276, 1, 276, 'Pacifist', 0, 0, 5, 'Passive; Exhaust; If you ever Attack or Counter-Attack, exhaust this Gift. As long as this Gift is not exhausted, you may claim an extra d12 with all defenses', '@@REFRESH: X (Special)\n\n@@FLAVOUR:\nYour personal commitment to avoiding violence has honed your sense of danger.\nIf you ever Attack or Counter-Attack, exhaust this Gift. If you ever cause anyone to be Hurt, Injured, Dying, Sick, or Dead, for any reason, exhaust this Gift. You may not refresh this Gift until 24 hours after the exhausting incident.\nAs long as this Gift is not exhausted, you may claim an extra d12 with all defenses.', 5, 52, '', 16, 'pacifist', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(277, 1, 277, 'Pack Mind', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better Team Player\n\n@@ACTION: Action \"combination recover and rally other\"\nWhenever you take the recover action, you may also rally another ally. As long as the ally is aware of you - sight, sound, smell, or any other means - you may attempt the rally.\nWith this ability, you don\'t actually have to speak out loud - you have a mystical command of body language, curt cries and barks, secret spoors, and other primal methods. The Pack Mind ability is much more subtle than a typical rally.\nThis action counts as both a recover and rally. You cannot take another rally action in the same round.', 5, 321, '', 2, 'pack-mind', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(278, 1, 278, 'Pack Tactics', 0, 0, NULL, 'Passive; d8 Tactics bonus if your ally has this Gift... You may claim a d12 Tactics bonus for each threatening, Guarding ally that also has the Gift of Pack Tactics', '@@PASSIVE: d8 Tactics bonus if your ally has this Gift...\nIf you Attack a target that is threatened by an ally who also has the Gift of Pack Tactics, you may claim a bonus d8 to your Tactics dice.\nYou may claim a d8 Tactics bonus for each threatening ally that also has the Gift of Pack Tactics.\n... or a d12 Tactics bonus if that ally is Guarding!\nIf you Attack a target that is threatened by an ally who also has the Gift of Pack Tactics, and your ally is Guarding, you may claim a bonus d12 to your Tactics dice (instead of the d8 bonus). Your ally is assumed to be harrying the target with feints, jabs, goads, and other distractions.\nYou may claim a d12 Tactics bonus for each threatening, Guarding ally that also has the Gift of Pack Tactics.', 5, 56, '', 14, 'pack-tactics', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(279, 1, 279, 'Panic', 0, 0, 5, 'Action; Action \"magic attack vs', '@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"magic attack vs. Group\"\nDeclare an attack: your Mind & Will vs. a Group\'s Mind & Will.\nIf you Succeed or better, the target becomes Afraid.\nThe lowest-rolling failure becomes Terrified.\nYou may only refresh this gift after all the targets of this spell haven\'t seen you for at least 24 hours.', 5, 299, '', 12, 'panic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(280, 1, 280, 'Paralysis', 0, 0, 1, 'Action; Exhaust; With refinement, a spell that causes shakes and shivers can be bolstered to freeze the muscles entirely', '@@SECTION: With refinement, a spell that causes shakes and shivers can be bolstered to freeze the muscles entirely.\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Ataxia to Paralysis\"\nTo use this ability, you must have an \"Perplex\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Ataxia\" weapon becomes a \"Paralysis\".', 5, 299, '', 12, 'paralysis', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(281, 1, 281, 'Parkour', 0, 0, NULL, 'Passive', '@@REQUIRES: Fast Climber\n\n@@ACTION: Action \"stunt: free running up\"\nAs a stunt, you may run up a wall ... either to the top or some platform way up there.\nFirst, declare a straight line to a high spot that you will move to, and the wall that you will scale. Then, roll your Sprint die. Move that many paces towards the wall - if you fail to reach it, stop moving.\nIf you do reach the wall, you may start to run up the wall. For every pace of ground that you covered before you got to the wall, you may move one pace vertically, up the wall.\nIf you fall short of your target, you have two choices: you may either fall back down the wall (which results in falling damage) or you may attempt a last-ditch grab - see \"Falling\" in the Spot Rules.\nNo matter the outcome, you are always Reeling after this stunt.\n\n@@ACTION: Action \"stunt: free running down\"\nAs a stunt, you may run down a wall.\nFirst, declare a straight line to a low spot that you will move to, and the wall you\'re going to run down. Then, roll your Sprint die. Your Sprint score is both your lateral movement (across) and your descending movement (down). For example, if you score a 7, then you move 7 paces forward and 7 paces down.\nIf you fail to reach the ground, you\'re in trouble.\nFollowing the previous example, if you scored a 7, but you needed to descend 8 paces, then you didn\'t make it. If you fall short, you have two choices: you may either fall back down the wall (which results in falling damage) or you may attempt a last-ditch grab - see \"Falling\" in the Spot Rules.\nNo matter the outcome, you are always Reeling after this stunt.\n\n@@ACTION: Action \"stunt: free running sideways\"\nAs a stunt, you may run along a wall ... possibly to a platform on the other side of a gap.\nFirst, declare a straight line to a spot that you will move to, and the wall that you will run across. The wall must be within your Stride distance.\nThen, roll your Sprint die. Move that many paces along the wall. You must run in a straight line - if the wall is curved, you won\'t be able to run. The wall must also be smooth - if the wall would be bad footing, then you can\'t run across it. (Yes, the Gift of Sure-Footed would negate bad footing penalties.)\nAt the end of your movement, you must then move your Stride in any horizontal direction. If you end up on good footing, your movement ends and you are sent Reeling. If you end up on no footing - then you fall!\nSee \"Falling\" in the Spot Rules.\nNo matter the outcome, you are always Reeling after this stunt.', 5, 52, '', 16, 'parkour', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(282, 1, 282, 'Pawang Apprentice', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Stunt \"reason with supernatural being\" You may speak with any supernatural being, by taking the \"Reason\" action', '@@STUNT: \"reason with supernatural being\"\n\n@@SECTION: You may speak with any supernatural being, by taking the \"Reason\" action. You cannot force an elemental to manifest, but you can talk to one that is still dormant. If you roll well with your Gossip or Negotiation skills, the being might deign to speak with you. (The supernatural are notoriously emotional.)\n\n@@SECTION: While people without this Gift may talk to supernatural beings, their words may not be understood, and they might not understand the replies.\n\n@@STUNT: \"minor elemental effect\"\n\n@@SECTION: Your knowledge of petty elemental magicks allows you to perform minor little feats of wizardry to manipulate the physical world. You can call forth a misty fog, spark a candle or a gun, lift ¼ stone or less of unattended physical materials and move them around within Near range, freeze or boil one liter worth of liquid, or any other petty feat of magic involving the physical world. The Game Host is the final arbiter of what is petty elemental magic and what isn\'t.\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready magic weapon\"\n\n@@SECTION: Exhaust this Gift, then use the Ready action to draw forth an Elemental weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\n\n@@SECTION: Elemental weapons are Magic Attacks. Your Gift allows you to ready the following magical weapons:\nJengges\nNaruga', 1, 920, '', 12, 'pawang-apprentice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(283, 1, 283, 'Penitence', 0, 0, 5, 'Passive; Exhaust; Exhaust this Gift', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Cleric\'s Trappings (any) White Magic Apprentice\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Prayer for Penitence\"\nDeclare a crowd of targets, and a task they must perform, or a practice that they must refrain from doing. Inform the crowd using an inspirational speech. Exhaust this Gift.\nRoll your Mind & Will vs. the crowd\'s Will. The lowest-rolling failure in the crowd is the one who actually has the penitence cast upon them - you will recognize this person on sight as the penitent.\nThe rest of the crowd won\'t know if it\'s on them or not ... and it\'s not common knowledge that this spell only works on one person, so this spell is very good at keeping a whole crowd in line.\nIf the penitent target breaks the promise you specify, the spell ends and you instantly know. If the promise has a duration (e.g. \"Abstain from all alcohol for a year and a day\"), the spell also expires when the duration is up.\nThe promise is broken when the target believes they broke the rule.\nThis gift can only be refreshed by praying for 8 minutes during the Office of Nones (3 pm to 6 pm). As soon as this gift is refreshed, the penitence expires.', 5, 306, '', 12, 'penitence', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(284, 1, 284, 'Personality of: [Choice]', 0, 0, 2, 'PASSIVE:  You may claim a bonus d12 - if the roll is somehow relevant to your Personality.', '@@PASSIVE: Character Creation\nEvery Major Character starts with one Personality Gift. A Personality is a one-word description of a major personality trait of the character.\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: any roll you make\nYou have a strong personality - so strong, in fact, that it helps you to get stuff done.\nAfter any die roll that you make, you may exhaust this gift to claim a bonus d12 - if the roll is somehow relevant to your Personality. For example, if your Personality is Envious, you might claim a bonus to steal something away from someone. If your Personality is Wrathful, you might claim a bonus to strike someone in combat\nThe Game Host is the final judge over whether a roll is relevant to your character\'s personality. The Host is encouraged to be generous about letting a character use a Personality Gift in a defensive manner. (For example, the Game Host is encouraged to allow a Player to use their Personality Bonus die as an extra Soak die if it might prevent the character\'s death).\nCharacter Development\nDuring the character development phase, you may change one Personality choice to a different choice, at no cost. For example, you may change \"Envious\" to \"Wrathful\". As usual, the Game Host must approve any character developments.', 5, 66, 'any roll you make', 8, 'personality-of-choice', '2026-03-22 10:39:00', '2026-03-29 08:32:36'),
(285, 1, 285, 'Piety of: [Choice]', 0, 0, NULL, 'Passive; Bonus d12 for your Faith You have extreme devotion to a religious cause', '@@PASSIVE: Bonus d12 for your Faith\nYou have extreme devotion to a religious cause.\nWhen negotiating with religious leaders, inquiring about matters divine, or gossiping with fellow devotees of your religion, you may claim a bonus d12.\nYou must choose a particular religion. Popular choices include:\nPenitence, the most influential religion in all of Calabria\nLutarism, The Old Faith of the Doloreaux\nAthanasia, a sect of s\'Allumer devoted to understanding the universe\nHyperdulia, a sect of s\'Allumer devoted to honoring saints of the past\nAsk your Game Host for permission to choose another religion. In some places, choosing a particular religion may be against the law!', 5, 56, '', 14, 'piety-of-choice', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(286, 1, 286, 'Pilum of Fire', 0, 0, 1, 'Action; Exhaust; Action \"Aim to upgrade Ignite Fire to Pilum of Fire\" Add +1 Mark to Presence Add 1 Mark to your Presence Skill', '@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Ignite Fire to Pilum of Fire\"\n\n@@SECTION: Add +1 Mark to Presence\nAdd 1 Mark to your Presence Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Red Robe Extra action \"Refresh Fire Magic Gift\"\nWhile wearing a Red Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Fire\" descriptors. These gifts include Elemental Apprentice and Pilum of Fire.\n\n@@SECTION: To use this ability, you must have a \"Ignite Fire\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Ignite Fire\" weapon becomes a \"Pilum of Fire\".', 5, 292, 'While wearing a Red Robe Extra action \"Refresh Fire Magic Gift\"', 12, 'pilum-of-fire', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(287, 1, 287, 'Prudence', 0, 0, NULL, 'PASSIVE: At the start of battle, you are automatically Guarding (bonus d8 to all defenses), if you are able to Guard. ', '@@REQUIRES: Danger Sense\n\n@@START: of Battle\nAt the start of battle, you are automatically Guarding (bonus d8 to all defenses), if you are able to Guard. If you are not able to Guard - for example, if you are helpless, or if you Botched your initiative roll and were sent Reeling - this Gift has no effect', 5, 73, '', 5, 'prudence', '2026-03-22 10:39:00', '2026-03-29 08:50:12'),
(288, 1, 288, 'Psychic Clout', 0, 0, NULL, 'PASSIVE: Add +1 Mark to Negotiation; ACTION: Cast a spell of the Psychic nature and claim a bonus 2d8.', '@@REQUIRES: Mystic: Cognoscente Magic\n\n@@PASSIVE: Add +1 Mark to Negotiation\nAdd 1 Mark to your Negotiation Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting a Psychic Spell\nExhaust this Gift after casting a spell of the Psychic nature to claim a bonus 2d8 with your casting dice.\nMultiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 302, 'Casting a Psychic Spell', 12, 'psychic-clout', '2026-03-22 10:39:00', '2026-03-29 08:51:45'),
(289, 1, 289, 'Quake', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Your victims can feel the shudder in their very souls', '@@SECTION: It\'s not just the ground that shakes. Your victims can feel the shudder in their very souls.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Quake\"\nExhaust this Gift, then use the ready action to draw forth a \"Quake\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 289, '', 12, 'quake', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(290, 1, 290, 'Quick Sheathe', 0, 0, NULL, 'Passive; Requires Quick Draw Extra action \"Put away\" You may take one extra \"put away\" action every round', '@@PASSIVE: Requires\nQuick Draw\n\n@@ACTION: Extra action \"Put away\"\nYou may take one extra \"put away\" action every round.', 5, 77, '', 18, 'quick-sheathe', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(291, 1, 291, 'Quick-Draw', 0, 0, NULL, 'Passive; Extra action: \"draw weapon\" You can take an extra action on your turn: a \"ready\" action, but only to draw a weapon', '@@ACTION: Extra action \"draw weapon\"\nYou can take an extra action on your turn: a \"ready\" action, but only to draw a weapon. The standard rules apply: you can\'t take the same action more than once, during your turn.\nQuick-Draw only works with physical weapons, not with magical weapons or anything else beyond the mundane.', 5, 77, '', 5, 'quick-draw', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(292, 1, 292, 'Rapid Aim', 0, 0, 1, 'Passive; Exhaust; Extra action \"aim\" Exhaust this Gift to take an extra action on your turn: \"aim', '@@REQUIRES: Veteran\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Extra action \"aim\"\nExhaust this Gift to take an extra action on your turn: \"aim', 5, 83, '', 26, 'rapid-aim', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(293, 1, 293, 'Rapid Dash', 0, 0, 1, 'Passive; Exhaust; Extra action \"dash\" Exhaust this Gift to take an extra action on your turn: \"dash\"', '@@REQUIRES: Fast Mover\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Extra action \"dash\"\nExhaust this Gift to take an extra action on your turn: \"dash\".', 5, 74, '', 5, 'rapid-dash', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(294, 1, 294, 'Rapid Guard', 0, 0, 1, 'Passive; Exhaust; Extra action \"guard\" Exhaust this Gift to take an extra action on your turn: \"guard\"', '@@REQUIRES: Veteran\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Extra action \"guard\"\nExhaust this Gift to take an extra action on your turn: \"guard\".', 5, 83, '', 5, 'rapid-guard', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(295, 1, 295, 'Rapid Sprint', 0, 0, 1, 'Passive; Exhaust; Extra action \"sprint\" Exhaust this Gift to take an extra action on your turn: \"sprint\"', '@@REQUIRES: Fast Mover\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Extra action \"sprint\"\nExhaust this Gift to take an extra action on your turn: \"sprint\".', 5, 74, '', 5, 'rapid-sprint', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(296, 1, 296, 'Rapier Lunge', 0, 0, NULL, 'Passive', '@@REQUIRES: Fencing\n\n@@ACTION: Action \"melee attack with rapier\"\nWhen executing a Melee Attack with a rapier, you may declare a rapier lunge - You may attack foes at Reach range. (Characters without this Gift can only attack with rapiers at Close Range.)\nNote\nYou may still only Counter with a rapier at Close Range.', 5, 75, '', 5, 'rapier-lunge', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(297, 1, 297, 'Reflection', 0, 0, 1, 'Passive; Exhaust; Instead of using your regular defense against a magic spell, you may declare you will use Reflection', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings\n\n@@REQUIRES: Thaumaturgy Apprentice\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: you are targeted by a Magic attack\nInstead of using your regular defense against a magic spell, you may declare you will use Reflection. You must declare Reflection as soon as the spell is launched and you\'re a target.\nExhaust this Gift. Roll your Mind & Supernatural as your defense.\nIf you succeed in defeating the Magic attack, the original spell-caster suffers a brutal Counter-Attack - identical to the spell they just used! Substitute your dice for the attacker\'s roll.\nIf the attack was a Group, Crowd, or Explosion, then everyone is saved, as the spell goes right back to the attacker. Regardless of the reflected spell\'s original scope, only the attacker is hit by the Reflection. Use your successes to determine damage, if any.\nIf you tie on your Reflection roll, then you (and everyone else) are still targeted as normal ... but the spell also reflects back to strike the attacker (alone). Again, use your successes to determine damage to your attacker.\nIf you fail on your Reflection roll, you (and everyone else) are attacked, as normal.\n\n@@NOTE:\nThe Reflection spell may reflect any spell that you are aware of. Since the Reflection spell may reflect a Synecdoche spell, it has the \"Synecdoche\" descriptor; since it automatically finds your attacker, it has the \"Locating\" descriptor.', 5, 309, 'you are targeted by a Magic attack', 12, 'reflection', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(298, 1, 298, 'Relentlessness', 0, 0, 1, 'Passive; Exhaust; If you are hit by an attack, and that attack sends you Reeling, you may exhaust this Gift to negate the Reeling', '@@REQUIRES: Resolve\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: You are hit by an attack.\nIf you are hit by an attack, and that attack sends you Reeling, you may exhaust this Gift to negate the Reeling', 5, 78, 'You are hit by an attack.', 5, 'relentlessness', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(299, 1, 299, 'Replay for Destiny', 0, 0, 3, 'Passive; If you fail an attack, counter-attack or defense, before you roll your Soak & Armor, you may declare a replay', '@@REQUIRES: Body of d8 or better\n\n@@REQUIRES: Speed of d8 or better\n\n@@REQUIRES: Mind of d8 or better\n\n@@REQUIRES: Will of d8 or better\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: failed Counter or Defense\nIf you fail an attack, counter-attack or defense, before you roll your Soak & Armor, you may declare a replay.\nFirst, your character\'s life briefly flashes before their eyes, and in this tiniest of moment, they contemplate the transitory nature of life, as to whether it is their destiny to die this day.\nThen, replay the last attack vs. defense exchange.\nPick up all the dice, both attacker\'s and defender\'s, and re-roll them. The new result stands', 5, 64, 'failed Counter or Defense', 21, 'replay-for-destiny', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(300, 1, 300, 'Reprisal', 0, 0, 2, 'Passive; Exhaust; The spell-caster may claim a bonus d12 to their defenses if your Reprisal comes more than one round after they cast their spell (but is still within the last…', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings Thaumaturgy Apprentice\n\n@@REFRESH: X (Respite)\n\n@@TRIGGER: casting a spell vs. spell-caster\nDeclare a target. This target must have cast a spell that either affected you, or that affected an object or ally within Close range of you, in the last five minutes. The caster need not be present; distance does not matter.\nExhaust this Gift, then cast any spell. That spell targets the spell-caster, no matter where they are, or what state they are in. The spell-caster defends normally, only Cover and Range are completely negated. The spell-caster may claim a bonus d12 to their defenses if your Reprisal comes more than one round after they cast their spell (but is still within the last five minutes).\nYou will know the results of your spell - what results it inflicted on the target - and that\'s all. You\'ll have to use other methods of intelligence to find out who the spell-caster was, where they are, and if they survived your reprisal', 5, 310, 'casting a spell vs. spell-caster', 20, 'reprisal', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(301, 1, 301, 'Reserves of Vitality', 0, 0, 2, 'Action; Exhaust; Action \"recover and call upon the reserves of strength\" When you take the Recover action, you may call upon your body\'s primal energy to overcome failings of…', '@@REQUIRES: Species Trait of d8 or better Resolve\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"recover and call upon the reserves of strength\"\nWhen you take the Recover action, you may call upon your body\'s primal energy to overcome failings of the flesh. Exhaust this Gift to negate any and all Reeling, Hurt, Afraid, Half-Buried, Slowed, Terrified, Controlled, Marionette, and Paralyzed conditions on yourself', 5, 321, '', 20, 'reserves-of-vitality', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(302, 1, 302, 'Retreating Save', 0, 0, 3, 'Passive; Exhaust; After you fail a defense, after you roll your Soak, if and only if you claim a Retreat, you may exhaust this Gift to negate all Unconscious, Dying, Dead, and…', '@@REQUIRES: Speed d8 or better\n\n@@REQUIRES: +1 Mark in Jumping\n\n@@REQUIRES: You may claim +1 Mark in Jumping skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: Retreat with failed defense\nAfter you fail a defense, after you roll your Soak, if and only if you claim a Retreat, you may exhaust this Gift to negate all Unconscious, Dying, Dead, and Overkilled results inflicted on you, from the attack that you just Retreated from.\nIf you don\'t Retreat, you cannot use this ability.', 5, 64, 'Retreat with failed defense', 21, 'retreating-save', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(303, 1, 303, 'Retribution', 0, 0, 1, 'Action; Action \"Attack vs', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Necromancer\'s Trappings\n\n@@REQUIRES: Apprentice Necromancy\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Attack vs. Group\"\nDeclare any poor status currently affecting your own character (such as Hurt, Injured, Sick, On Fire, etc.) Then declare a Group of targets. Roll your Will, Deceit, & 3d6. Targets resist with their Will, Inquiry, and Supernatural. Each target that fails to resist becomes Reeling and now suffers the same poor status that you have.', 5, 314, '', 12, 'retribution', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(304, 1, 304, 'Riot', 0, 0, 5, 'Action; Action \"magic attack vs. crowd\" Attack: your Mind & Will vs. a crowd\'s Mind & Will', '@@REQUIRES: Green & Purple Apprentice Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic Panic\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"magic attack vs. crowd\"\nAttack: your Mind & Will vs. a crowd\'s Mind & Will.\nIf you Succeed or better, the target becomes Enraged.\nThe lowest-rolling failure becomes Berserk.\nYou refresh this gift after all the targets of this spell haven\'t seen you for at least 24 hours.', 5, 302, '', 12, 'riot', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(305, 1, 305, 'Sabotage', 0, 0, NULL, 'Passive', '@@REQUIRES: Streetwise\n\n@@REQUIRES: Bonus d12 to defeat locks and traps\n\n@@REQUIRES: When making rolls to disable machines and to bypass traps, you may claim a bonus d12. This bonus applies, but is not limited to, academic knowledge about locks and traps, using craft to bypass or to disable locks and traps, and climbing or sneaking around alarms.', 5, 80, '', 23, 'sabotage', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(306, 1, 306, 'Salmon Leap', 0, 0, 1, 'Action; Exhaust; You may sacrifice 2 paces of salmon leap to gain 1 pace of altitude', '@@REQUIRES: Species Trait of d8 or better Fast Jumper\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"stunt: salmon leap\"\nJust as salmon can swim up a waterfall, you can leap great distances.\nAs a stunt, declare a point that you will leap to. This point cannot be further than Medium range (36 paces) away. Next, exhaust this Gift.\nThird, move up to your Dash in a straight line. You must move at least 1 pace, in the direction of your landing point. Fourth, roll your Body and Jumping dice, and note the score.\nLast, roll your Sprint Dice, and add that score to the roll you just made. This total is your salmon leap.\nThe salmon leap is the distance you move along the ground. Just like its namesake, the salmon leap is a jump through the air, so you do not touch the ground beneath you.\nYou may sacrifice 2 paces of salmon leap to gain 1 pace of altitude. Your salmon leap can take you very high up.\nYou may sacrifice 1 pace of salmon leap to lower your height by one pace. Your salmon leap can take you very far down.\nIf your salmon leap overshoots your target, you must sacrifice forward movement for altitude. If you smack into a ceiling or other barrier, your movement stops at the point where you hit the barrier, and you fall to the ground, Knocked Down.\nIf your landing spot is below you, and your salmon leap distance can reach it, you do not take falling damage. (If your salmon leap isn\'t long enough to reach the low ground, however, you will take falling damage.)', 5, 321, '', 3, 'salmon-leap', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(307, 1, 307, 'Sand Blast', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Sand Blast\" Exhaust this Gift, then use the ready action to draw forth a \"Sand Blast\" weapon', '@@SECTION: Dust and gypsum glitter inside this spell. By your will, a gout of sand flies violently forth, ripping any exposed flesh it touches.\n\n@@REQUIRES: Any two Gifts which have both the \"Earth\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Sand Blast\"\nExhaust this Gift, then use the ready action to draw forth a \"Sand Blast\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 290, '', NULL, 'sand-blast', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(308, 1, 308, 'Sand Geyser', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Earth to Sand Geyser\"\n\n@@SECTION: To use this ability, you must have a \"Create Earth\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\n\n@@SECTION: Exhaust this Gift. Your \"Create Earth\" weapon becomes a \"Sand Geyser\", a fuming spray of dust and sand that you can then hurl at your targets.', 3, 748, '', 12, 'sand-geyser', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(309, 1, 309, 'Scary Fighter', 0, 0, 1, 'Action; Afraid or Terrified Target\" When you make an attack against an Afraid or Terrified target, you may claim a bonus d12', '@@REQUIRES: Resolve\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"attack vs. Afraid or Terrified Target\"\nWhen you make an attack against an Afraid or Terrified target, you may claim a bonus d12.', 5, 78, '', 19, 'scary-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(310, 1, 310, 'Scathefire', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Ignite Fire to Scathefire\"\n\n@@SECTION: To use this ability, you must have a \"Create Air\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\n\n@@SECTION: Exhaust this Gift. Your \"Ignite Fire\" weapon becomes a \"Scathefire\", a glowing ball of sparks that will spread into a long, blazing arc.', 3, 748, '', 12, 'scathefire', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(311, 1, 311, 'Second Throw', 0, 0, 1, 'Passive; Exhaust; After resolving a thrown attack, you may immediately exhaust this Gift to follow with a second throwing attack', '@@REQUIRES: Quick-Draw\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: throwing attack\nAfter resolving a thrown attack, you may immediately exhaust this Gift to follow with a second throwing attack. You quickly draw another weapon and throw it at a target - either the same target, or a different one.', 5, 77, 'throwing attack', 5, 'second-throw', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(312, 1, 312, 'Secrets of Air Magic', 0, 0, NULL, 'Passive; You have learned how to replenish your reserves of Air Magic faster, but only if you style yourself in the appropriate manner', '@@FLAVOUR:\nYou have learned how to replenish your reserves of Air Magic faster, but only if you style yourself in the appropriate manner.\n\n@@TRAPPINGS: Elementalist\'s Trappings: Yellow\n\n@@REQUIRES: Add +1 Mark to Weather Sense\n\n@@REQUIRES: Add 1 Mark to your Weather Sense Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Yellow Robe Extra action \"Refresh Air Magic Gift\"\nWhile wearing a Yellow Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Air\" descriptors. These Gifts include Elemental Apprentice and Lightning Bolt.', 5, 286, 'While wearing a Yellow Robe Extra action \"Refresh Air Magic Gift\"', 12, 'secrets-of-air-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(313, 1, 313, 'Secrets of Antiñgero Magic', 0, 0, NULL, 'Passive; Add +1 Mark to Supernatural Add 1 Mark to your Supernatural Skill', '@@PASSIVE: When wearing the mystical patterns of the Pedalaman Robe, the power flows through you more easily. You\'ll get an extra \"refresh\" action every turn to untap your Antiñgero Apprentice gift.\n\nAdd +1 Mark to Supernatural\nAdd 1 Mark to your Supernatural Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Pedalaman Robe Extra action \"Refresh Antiñgero Apprentice Gift\"\n\n@@SECTION: While wearing a Pedalaman Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all the \"Battle\", \"Magic\", and \"Antiñgero\" descriptors. These Gifts include Antiñgero Apprentice.', 1, 920, 'While wearing a Pedalaman Robe Extra action \"Refresh Antiñgero Apprentice Gift\"', 12, 'secrets-of-antigero-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(314, 1, 314, 'Secrets of Dukun Magic', 0, 0, 1, 'Passive; Add +1 Mark to Presence Add 1 Mark to your Presence Skill', '@@FLAVOUR: When wearing the mystical patterns of the Pesisir Robe, the power flows through you more easily. You\'ll get an extra \"refresh\" action every turn to untap your Dukun Apprentice gift.\n\n@@REQUIRES: Dukun Trappings\n\n@@PASSIVE: Add +1 Mark to Presence\nAdd 1 Mark to your Presence Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Pesisir Robe\n\n@@ACTION: Extra action \"Refresh Dukun Apprentice Gift\" While wearing a Pesisir Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all the \"Battle\", \"Magic\", and \"Dukun\" descriptors.', 1, 921, 'While wearing a Pesisir Robe', 12, 'secrets-of-dukun-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(315, 1, 315, 'Secrets of Earth magic', 0, 0, NULL, 'Passive; You have learned how to replenish your reserves of Earth Magic faster, but only if you style yourself in the appropriate manner', '@@FLAVOUR:\nYou have learned how to replenish your reserves of Earth Magic faster, but only if you style yourself in the appropriate manner.\n\n@@TRAPPINGS: Elemetalist\'s Trappings: Amber\n\n@@REQUIRES: Add +1 Mark to Digging\n\n@@REQUIRES: Add 1 Mark to your Digging Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Amber Robe\n\n@@TRIGGER: While wearing a Amber Robe\n\n@@ACTION: Extra action \"Refresh Air Magic Gift\"\nWhile wearing a Amber Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Earth\" descriptors. These Gifts include Elemental Apprentice and Stone Hurlant.', 5, 289, 'While wearing a Amber Robe', 12, 'secrets-of-earth-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(316, 1, 316, 'Secrets of Fire Magic', 0, 0, NULL, 'Passive; You have learned how to replenish your reserves of Fire Magic faster, but only if you style yourself in the appropriate manner', '@@FLAVOUR:\nYou have learned how to replenish your reserves of Fire Magic faster, but only if you style yourself in the appropriate manner.\n\n@@TRAPPINGS: Elementalist\'s Trappings: Red\n\n@@REQUIRES: Add +1 Mark to Presence\n\n@@REQUIRES: Add 1 Mark to your Presence Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Red Robe Extra action \"Refresh Fire Magic Gift\"\nWhile wearing a Red Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Fire\" descriptors. These gifts include Elemental Apprentice and Pilum of Fire.', 5, 292, 'While wearing a Red Robe Extra action \"Refresh Fire Magic Gift\"', 12, 'secrets-of-fire-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(317, 1, 317, 'Secrets of Foolery', 0, 0, NULL, 'Passive; Each round; You cannot be wearing any Armor', '@@PASSIVE: Any fool could do this ... but you\'r not just any fool.\n\n@@TRIGGER: Dressed like a fool\n\n@@ACTION: Extra action \"Refresh any Foolish Battle Gift\"\n\n@@SECTION: To use this ability, you must be dressed like a fool.\n\n@@SECTION: You cannot be wearing any Armor. The more impractical your clothes are, the better.\n\n@@SECTION: You may take an extra action each round: the Refresh action, but only to refresh a gift that has both the \"Battle\" and the \"Foolish\" descriptor.\n\n@@FLAVOUR:\nThe standard rule that you can\'t perform the same action twice in the same round applies.', 2, 356, 'Dressed like a fool', 10, 'secrets-of-foolery', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(318, 1, 318, 'Secrets of Pawang Magic', 0, 0, 1, 'Passive; Add +1 Mark to Academics Add 1 Mark to your Academics Skill', '@@SECTION:\nWhen wearing the mystical patterns of the Cirebon Robe, the power flows through you more easily. You\'ll get an extra \"refresh\" action every turn to untap your Pawang Apprentice gift.\n\n@@PASSIVE: Add +1 Mark to Academics\nAdd 1 Mark to your Academics Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Cirebon Robe\n\n@@ACTION: Extra action \"Refresh Pawang Apprentice Gift\"\n\n@@SECTION: While wearing a Cirebon Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all the \"Battle\", \"Magic\", and \"Pawang\" descriptors.\n\n@@SECTION: These Gifts include Pawang Apprentice.', 1, 921, 'While wearing a Cirebon Robe', 12, 'secrets-of-pawang-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(319, 1, 319, 'Secrets of Star Magic', 0, 0, NULL, 'Passive; Add +1 Mark to Academics Add 1 Mark to your Academics skill', '@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Elementalist\'s Trappings: Star\n\n@@PASSIVE: Add +1 Mark to Academics\nAdd 1 Mark to your Academics skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Starry Robe\n\n@@ACTION: Extra action \"Refresh Air, Earth, Fire, or Water Magic Gift\"\nWhile wearing a Star Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has both the \"Battle\" and \"Magic\" descriptors, and has at least one of the following descriptors: \"Air\", \"Earth\", \"Fire\", \"Water\", or \"Star\". These gifts include Elemental Apprentice, Freeze Arrow, Pilum of Fire, and Stone Hurlant,', 5, 297, 'While wearing a Starry Robe', 12, 'secrets-of-star-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(320, 1, 320, 'Secrets of Thaumaturgy', 0, 0, NULL, 'Passive', '@@REQUIRES: Cleric\'s Trappings: Left-Hand Path\n\n@@PASSIVE: Add +1 Mark to Leadership\n\nAdd 1 Mark to your Leadership Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"\n\n@@SECTION: While wearing a White Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Holy\" descriptors. These Gifts include Thaumaturgy Apprentice and Reflection.', 5, 310, 'While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"', 12, 'secrets-of-thaumaturgy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(321, 1, 321, 'Secrets of the Green School', 0, 0, NULL, 'Passive', '@@REQUIRES: Cognoscente\'s Trappings: Green School\n\n@@PASSIVE: Add +1 Mark to Gossip\n\nAdd 1 Mark to your Gossip Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Green Robe Extra action \"Refresh Psychic Magic Gift\"\n\n@@SECTION: While wearing a Green Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Psychic\" descriptors. These gifts include Green & Purple Apprentice, Blindness and Paralysis.', 5, 300, 'While wearing a Green Robe Extra action \"Refresh Psychic Magic Gift\"', 12, 'secrets-of-the-green-school', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(322, 1, 322, 'Secrets of the Left-Hand Path', 0, 0, NULL, 'Passive', '@@REQUIRES: Cleric\'s Trappings: Left-Hand Path\n\n@@PASSIVE: Add +1 Mark to Leadership\n\nAdd 1 Mark to your Leadership Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"\n\n@@SECTION: While wearing a White Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Holy\" descriptors. These Gifts include White Magic Apprentice, Flesh Ward, and Fulguration', 5, 307, 'While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"', 12, 'secrets-of-the-left-hand-path', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(323, 1, 323, 'Secrets of the Purple School', 0, 0, NULL, 'Passive', '@@REQUIRES: Cognoscente\'s Trappings: Purple School\n\n@@PASSIVE: Add +1 Mark to Negotiation\n\nAdd 1 Mark to your Negotiation Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Purple Robe\n\n@@ACTION: Extra action \"Refresh Psychic Magic Gift\"\n\nWhile wearing a Purple Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Psychic\" descriptors. These gifts include Green & Purple Apprentice, Blindness and Paralysis.', 5, 300, 'While wearing a Purple Robe', 12, 'secrets-of-the-purple-school', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(324, 1, 324, 'Secrets of the Right_hand Path', 0, 0, NULL, 'Passive', '@@REQUIRES: Cleric\'s Trappings: Right-Hand Path\n\n@@PASSIVE: Add +1 Mark to Melee Combat\n\nAdd 1 Mark to your Melee Combat Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"\n\n@@SECTION: While wearing a White Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Holy\" descriptors. These Gifts include White Magic Apprentice, Flesh Ward, and Fulguration.', 5, 307, 'While wearing a White Robe Extra action \"Refresh Holy Magic Gift\"', 12, 'secrets-of-the-right-hand-path', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(325, 1, 325, 'Secrets of the Wilding Way', 0, 0, 5, 'Passive; Exhaust; Extra Action \"Refresh Wilding Gift\" As long as this Gift is unexhausted, you may take an extra action every round: an extra \"Refresh\" action, but only to…', '@@REQUIRES: Species Trait of d8 or better\n\n@@REQUIRES: Species Trait must be higher than your Mind Trait\n\n@@REQUIRES: Not Confused, But Berserk\n\n@@REQUIRES: You cannot become Confused. Whenever you would become Confused, you become Berserk for the duration, instead.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Extra Action \"Refresh Wilding Gift\"\nAs long as this Gift is unexhausted, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has the \"Wilding\" descriptor.\nIf you wear robes, armor, or any clothes more than the minimum to remain decent in polite society, exhaust this Gift. You cannot refresh this Gift for another 24 hours', 5, 322, '', 2, 'secrets-of-the-wilding-way', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(326, 1, 326, 'Secrets of Unholy Magic', 0, 0, NULL, 'Passive', '@@TRAPPINGS: Necromancer\'s Trappings\n\n@@PASSIVE: Add +1 Mark to Deceit\nAdd 1 Mark to your Deceit\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Black Robe Extra action \"Refresh Unholy Magic Gift\"\n\n@@ACTION: While wearing a Black Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Unholy\" descriptors.', 5, 314, 'While wearing a Black Robe Extra action \"Refresh Unholy Magic Gift\"', 12, 'secrets-of-unholy-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(327, 1, 327, 'Secrets of Water Magic', 0, 0, NULL, 'Passive', '@@REQUIRES: Elementalist\'s Trappings: Water\n\n@@PASSIVE: Add +1 Mark to Swimming\n\nAdd 1 Mark to your Swimming\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: While wearing a Blue Robe Extra action \"Refresh Water Magic Gift\"\n\n@@SECTION: While wearing a Blue Robe, you may take an extra action every round: an extra \"Refresh\" action, but only to refresh a gift that has all of the \"Battle\", \"Magic\", and \"Water\" descriptors. These Gifts include Elemental Apprentice and Freeze Arrow', 5, 295, 'While wearing a Blue Robe Extra action \"Refresh Water Magic Gift\"', 12, 'secrets-of-water-magic', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(328, 1, 328, 'Severance', 0, 0, 2, 'Passive; Exhaust; The target resists with an extra d12 for each Influence Gift they have', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Thaumaturge\'s Trappings Thaumaturgy Apprentice\n\n@@REFRESH: X (Respite)\n\n@@STUNT: \"Severance\"\nDeclare a target, then exhaust this Gift. Roll your Mind, Searching, and Supernatural vs. the target\'s Body, Will, and Presence. The target resists with an extra d12 for each Influence Gift they have.\nIf you succeed, any and all magical effects on the target instantly end. In addition, any synecdoche links in the rest of the world are also severed', 5, 310, '', 20, 'severance', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(329, 1, 329, 'Shape-Craft', 0, 0, NULL, 'Passive; Against inanimate, unattended objects, your \"Move Earth\" now causes Critical damage', '@@FLAVOUR:\nYour knowledge of material items allows you to sculpt without tools\n\n@@REQUIRES: Any two Gifts which have both the \"Earth\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@TRIGGER: Using a \"Move Earth\" spell\nYour advanced command over moving earth allows you to move things in strange shapes. The following rules apply to you.\n\n@@ACTION: Against inanimate, unattended objects, your \"Move Earth\" now causes Critical damage. (Normally, inanimate objects are immune to Critical effects.) In addition, you may claim your Craft dice as bonus dice.\n\n@@ACTION: When using a \"Move Earth\" against a target, you may choose instead to shape an object around a target\'s foot, arm, etc. Roll your Body & Craft (instead of your Body & Digging.) Your damage becomes Weak, but you may claim your Craft dice as bonus dice, and you may add the \"Grapple\" effect. If the target wants to break free, they must use a \"Break Free\" attack against your Body & Craft.', 5, 291, 'Using a \"Move Earth\" spell', 12, 'shape-craft', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(330, 1, 330, 'Sharpshooter', 0, 0, NULL, 'Action; \"ranged attack with reduced Range penalty dice\" When you make a ranged attack, your penalty Range Dice are better than those attackers who don\'t have…', '@@ACTION: Action \"ranged attack with reduced Range penalty dice\"\nWhen you make a ranged attack, your penalty Range Dice are better than those attackers who don\'t have this Gift.\nYou suffer no penalty up to Short Range; at Medium Range, you suffer d8; at Long Range, you suffer d12; at Very Long Range, you suffer 2d12. See the Combat Rules chapter for more details', 5, 79, '', 64, 'sharpshooter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(331, 1, 331, 'Shield Fighter', 0, 0, NULL, 'Passive', '@@REQUIRES: Veteran\n\n@@REQUIRES: Increased Armor Dice\n\n@@REQUIRES: When you fight with a Shield that has a Cover Die of d8, you may improve that cover to d12. Only Shields are improved, not bucklers or cloaks.', 5, 83, '', 5, 'shield-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(332, 1, 332, 'Shield Save', 0, 0, 3, 'Passive; You may use this ability after failing any defense that claimed a Cover bonus from your shield, after you have rolled your Soak dice', '@@REQUIRES: Resolve\n\n@@REQUIRES: Veteran\n\n@@REQUIRES: +1 Mark in Dodge\n\n@@REQUIRES: You may claim +1 Mark in Dodge Skill.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: failed Counter or Parry with Shield, or failed Dodge with Cover Dice from Shield\nYou may use this ability after failing any defense that claimed a Cover bonus from your shield, after you have rolled your Soak dice. (Also, you may use this abilty with a buckler, the shield that can counter.)\nNegate all Unconscious, Dying, Dead, and Overkilled results just inflicted on you from the attack that just hit you.\nIf you are using a wooden shield, the shield smashes into splinters and is instantly destroyed. If you are using a metal shield, the shield is still useable.\nIf you have no shield, you cannot use this abilit', 5, 64, 'failed Counter or Parry with Shield, or failed Dodge with Cover Dice from Shield', 21, 'shield-save', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(333, 1, 333, 'Shield Soak', 0, 0, NULL, 'Passive', '@@REQUIRES: Resolve\n\n@@TRIGGER: failed defense that used Shield\'s Cover\nIf you just failed a defense that used Cover Dice from a shield (such as a Parry or a Dodge), your Soak is improved. You may claim the shield\'s Cover Dice as extra Soak Dice.', 5, 78, 'failed defense that used Shield\'s Cover', 19, 'shield-soak', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(334, 1, 334, 'Signature Item: [Choice]', 0, 0, 5, 'Action; Once exhausted, you cannot recover this Gift until the next game session', '@@REQUIRES: Specific permission from the Game Host.\n\n@@REQUIRES: Belongings\n\n@@REQUIRES: You begin the game with a signature item. Perhaps it is a sword inherited from a famous ancestor. Or perhaps it\'s a gun you were lucky enough to pick up from someone who saved your life. You may even have some special transportation, such as a coach with two coursers to pull it, or a small ship.\n\n@@REQUIRES: The signature item should be something singularly associated with your character. It should have a name and a distinctive appearance.\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"replace your missing trappings\"\nIf you are parted from your signature item, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session.', 5, 62, '', NULL, 'signature-item-choice', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
(335, 1, 335, 'Sirocco Blast', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Air to Sirocco Blast\"\n\n@@SECTION: To use this ability, you must have a \"Create Air\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\n\n@@SECTION: Exhaust this Gift. Your \"Create Air\" weapon becomes a \"Sirocco Blast\", a whirling ball of air that you unleash onto several targets.', 3, 479, '', 12, 'sirocco-blast', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(336, 1, 336, 'Sixth Sense', 0, 0, NULL, 'Passive', '@@REQUIRES: Danger Sense\n\n@@TRIGGER: someone attacks with concealment bonus\nYou have an uncanny sense of danger. Whenever anyone attacks you and claims a concealment bonus, you may claim a bonus d12 with any Parry or Dodge. (Note: the bonus to hit against a Reeling target is a concealment bonus.)\nYou may not claim this bonus against attacks that do not claim concealment bonuses. You may not claim this bonus if you are helpless, nor with Counter-Attacks.', 5, 73, 'someone attacks with concealment bonus', 7, 'sixth-sense', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(337, 1, 337, 'Skulking', 0, 0, 1, 'Passive; Exhaust; Negate Reeling When Hiding and Sneaking After declaring a \"hide\" or a \"sneak\" stunt, Exhaust this Gift to negate the Reeling effect', '@@REQUIRES: Streetwise\n\n@@REFRESH: X (Battle)\n\n@@PASSIVE: Negate Reeling When Hiding and Sneaking\nAfter declaring a \"hide\" or a \"sneak\" stunt, Exhaust this Gift to negate the Reeling effect. The stunt still ends your turn, as usual, but at least you\'re not Reeling.\nCharacters without this Gift are sent Reeling after a \"hide\" or \"sneak\" stunt. See the Spot Rules for more details.', 5, 80, '', 5, 'skulking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(338, 1, 338, 'Sneaky Fighter', 0, 0, NULL, 'Passive', '@@REQUIRES: Streetwise\n\n@@REQUIRES: Attack with Concealable Weapon\n\n@@REQUIRES: Whenever you attack with a weapon that has the Concealable descriptor, you may claim a bonus 2d8 with your attack dice. There is no bonus for Counters or Parries', 5, 80, '', 24, 'sneaky-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(339, 1, 339, 'Speak with Dead', 0, 0, 2, 'Passive; Stunt \"Reason with the Dead\" You may take the Reason action to talk with a corpse', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Necromancer\'s Trappings Apprentice Necromancy\n\n@@REFRESH: X (Respite)\n\n@@STUNT: \"Reason with the Dead\"\nYou may take the Reason action to talk with a corpse. Roll your Will, Negotiation, & 2d6 vs. 3d6. The soul of the corpse must not have passed on to its final reward, and the body must not have been consecrated. To hear you, the head must have an intact ear; to answer you, the head must have an intact mouth.\nEverything else isn\'t really necessary.\nIf you are successful, the restless spirit inhabits the corpse. The eyes open and the mouth speaks.\nSpirits of bodies that met violent deaths might be disoriented or in denial about what has happened to them.\nThe corpse can speak with anyone present. (It\'s best to take the body somewhere private.) Being beyond earthly concerns, it may be difficult to motivate the spirit to talk, so some serious negotiations may be in order.\nAfter five minutes, the spell ends. You may speak with the corpse at a later time, if the soul doesn\'t pass on.', 5, 314, '', 12, 'speak-with-dead', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(340, 1, 340, 'Sperlunking', 0, 0, NULL, 'Passive; Bonus d12 for Caves When making rolls to navigate through a cave\'s twisty passages, or to travel long distances underground, you may claim a bonus d12', '@@PASSIVE: Bonus d12 for Caves\nWhen making rolls to navigate through a cave\'s twisty passages, or to travel long distances underground, you may claim a bonus d12.', 5, 56, '', 14, 'sperlunking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(341, 1, 341, 'Star Clout', 1, 0, 3, 'Passive; The greatest wizards can increase the power of a spell, even after it has been cast', '@@FLAVOUR:\nThe greatest wizards can increase the power of a spell, even after it has been cast.\n\n@@TRAPPINGS: Elementalist Trappings: Star\n\n@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Add +1 Mark to Academics\n\n@@REQUIRES: Add 1 Mark to your Academics Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting a Air, Earth, Fire, or Water Spell\nExhaust this Gift after casting a spell of the Air, Earth, Fire, Water, or Star nature to claim a bonus 2d8 with your casting dice.\nMultiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 297, 'Casting a Air, Earth, Fire, or Water Spell', 12, 'star-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(342, 1, 342, 'Star Mnemonic', 0, 0, 3, 'Passive; Add +1 Mark to Academics Add 1 Mark to your Academics Skill', '@@FLAVOUR:\nYour meditative training allows you to call upon reserves of power.\n\n@@REQUIRES: Any eight Gifts which have both the \"Magic\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Insider with the Dunwasser Academy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@TRAPPINGS: Elementalist\'s Trappings: Star\n\n@@PASSIVE: Add +1 Mark to Academics\nAdd 1 Mark to your Academics Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh all Magic Battle Gifts and Magic Respite Gifts\"\nOn your turn, as an extra action, you may put your off-hand upon your magical talisman, and in a loud voice, you declare your command over all that is under the Stars. By doing so, you immediately refresh all exhausted gifts that have both the \"Magic\" descriptor and either the \"Battle\" or the \"Respite\" descriptor.\nOther Gifts are not refreshed.\nYes, you can use this Gift to refresh any Magic Gift, even ones that aren\'t part of Elementalism.', 5, 298, '', NULL, 'star-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(343, 1, 343, 'Stare-Down', 0, 0, 5, 'Action; Exhaust; Resolve the stare-down as an attack', '@@REQUIRES: Species Trait of d8 or better Counter-Tactics\n\n@@REQUIRES: Resolve\n\n@@REFRESH: X (Special)\n\n@@ACTION: Action \"stunt: stare down\"\nYou may stare someone down. First, Exhaust this gift. Then, declare a foe within Medium Range. You must be able to see the foe\'s eyes, and they must be able to see yours.\nResolve the stare-down as an attack. You roll your Body, Will, & Species dice. The target defends with Body, Will, & Species, plus double any concealment dice.\nIf you succeed, the target is sent Reeling & Afraid, and you may immediately refresh this Gift. If you overwhelm, your target becomes Reeling and Terrified, and you may immediately refresh this Gift.\nYou may also refresh this Gift at your next Respite.', 5, 322, '', 20, 'stare-down', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(344, 1, 344, 'Starlight', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Action \"ready Stardust\" Exhaust this Gift, then use the ready action to draw forth a \"Stardust\" weapon', '@@FLAVOUR:\nYou call forth a dazzling radiance that clings to you, a soft glow that inspires awe in all who see it. At your behest, a single ray of light beams into a target.\n\n@@REQUIRES: Elemental Apprentice\n\n@@TRAPPINGS: Elementalist\'s Trappings: Star\n\n@@REQUIRES: Insider: Dunwasser Academy Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: One Gift with both \"Air\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Earth\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Fire\" & \"Journeyman\" descriptors\n\n@@REQUIRES: One Gift with both \"Water\" & \"Journeyman\" descriptors\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Stardust\"\nExhaust this Gift, then use the ready action to draw forth a \"Stardust\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\n\n@@NOTE:\n: people and things Overkilled by the Starlight are completely disintergrated, their elements destroyed, their possessions lost forever', 5, 298, '', 12, 'starlight', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(345, 1, 345, 'Stitch in Time', 0, 0, 3, 'Passive; Exhaust; You have an amazing ability to recover just before someone attacks', '@@REQUIRES: Danger Sense\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: you are attacked\nYou have an amazing ability to recover just before someone attacks. When you are attacked, but before any attack dice are rolled, declare you will exhaust this Gift for the following benefits:\nNegate all Reeling, Asleep, and/or Unconsciousness status on yourself.\nReplace any Dying condition with Sick and Afraid.\nAdd the Guarding status', 5, 73, 'you are attacked', 7, 'stitch-in-time', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(346, 1, 346, 'Stone Hurtlant', 0, 0, 1, 'Action; Exhaust; Exhaust this Gift', '@@SECTION: With an amber glow, the spell you hold in your hand becomes a giant boulder, levitating at your beck and call. At your command, the stone is hurled towards your foe with such force that it explodes on impact\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"Aim to upgrade Create Earth to Stone Hurlant\"\nTo use this ability, you must have a \"Create Earth\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Create Earth\" weapon becomes a \"Stone Hurlant\".', 5, 289, '', 13, 'stone-hurtlant', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(347, 1, 347, 'Sudden Draw', 0, 0, 1, 'Passive; Exhaust; Requires Quick Draw Interrupt: Draw a weapon Interrupt someone else\'s turn to declare you will exhaust this Gift to draw a weapon', '@@PASSIVE: Requires\nQuick Draw\n\n@@REFRESH: X (Battle)\n\n@@SECTION: Interrupt: Draw a weapon\nInterrupt someone else\'s turn to declare you will exhaust this Gift to draw a weapon. You may immediately defend yourself with the weapon you have just drawn.\nYou may not interrupt your own turn with this ability.\nYou must wait until your turn is over before using the Sudden Draw.', 5, 77, '', 18, 'sudden-draw', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(348, 1, 348, 'Summon Monster', 0, 0, 5, 'Passive; For one scene; Add +1 Mark to Supernatural Add 1 Mark to your Supernatural Skill', '@@FLAVOUR:\nYou can summon various supernatural creatures of the islands to help you. Note that these creatures will demand a price for their favors.\n\n@@PASSIVE: Add +1 Mark to Supernatural\nAdd 1 Mark to your Supernatural Skill.\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@SECTION: Summon a monster to help you\n\n@@SECTION: As a special \"summon\" action, tap this gift, and then roll your Will, Supernatural, and bonus d12 from Mystic: Tawas. Each 4 or better that you roll is one success.\nYou can then choose one and only one result from the table below, one that you have enough successes to obtain. (If you scored 2 successes, you can choose any 2, 1, or none result... and not any result of 3 or higher.)\n\n@@SECTION: How soon you can recharge the gift depends on the outcome of your summoning.\n\n@@SECTION:\nIf you failed to summon anything, you can recharge at the start of the next scene. (That means, not until after this combat is over!)\n\n@@SECTION:\nIf you summoned a monster to answer questions, you may recharge at the next respite.\n\n@@SECTION:\nIf you summoned a monster to help you in a non-violent manner (move things, deal with environmental hazards, etc.), you may recharge at your next respite.\n\n@@SECTION:\nIf you summoned a monster to help you for violence, the outcome varies on the result. If your taniwha didn\'t suffer anything worse than Hurt or Afraid, you may recharge at the start of the next chapter. If your monster was Injured or worse, you will need to make some sort of sacrifice. The worse the monster suffered, and the greater its power was, the greater the sacrifice will be\n\n@@SECTION:\nIf you summoned an aswang, kuntilanak or other powerful creature, you cannot recharge before the next chapter starts ... and you may have to pay a greater cost for the return of your power. This cost might be a sacrifice of your own possessions, life force, loved ones, etc. Or the creature may refuse to leave (and to let you recharge) until it has committed an atrocity or two, to sate its lust for blood.\n\n@@FLAVOUR:\nThe summoned monster appears Near you (within 4m), in an appropriate space. Whenever you recharge this gift, for any reason, your summoned taniwha will go away.\nMonsters are not puppets - they are living, willful creatures with their own agendas, always cruel, often evil. They will serve to the best of their ability, but abuse of this magic may eventually result in the supernatural world closing their ears to the call, making this gift useless.\n\n@@SECTION: Will, Supernatural, Mystic\'s d12 ≥4  Chooseone result\nNo successes  No effect, but your gift of \"Summon Spirit\" will recharge at the start of the next scene.\n1 success or more Summon a Hantu Raya and ask it three questions, which it will answer to the best of its ability. Recharge at the next respite.\n2 successes or more   Summon a Hantu Raya which will help you: you can ask it to fight for one scene, or to impersonate you for a day. See below for how to recharge.\n3 successes or more   Summon an Aswang to perform a task or to fight a battle for you. See below for how to recharge.\n4 successes or more   Summon a Kuntilanak to perform a task or to fight a battle for you. See below for how to recharge.\n5 successes or more   Summon a Spellcasting Aswang to perform a task or to fight a battle for you. See below for how to recharge.\n6 successes or more   Summon a Kuntilanak Merat to perform a task or to fight a battle for you. See below for how to recharge.\n7 successes or more   Summon a Masamang Aswang to perform a task or to fight a battle for you.\nYou cannot recharge this gift until you have sacrificed at least 4 lives to the dread creature.', 1, 921, '', 12, 'summon-monster', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(349, 1, 349, 'Summon Taniwha', 0, 0, 5, 'Passive; For one scene; Add +1 Mark to Supernatural Add 1 Mark to your Supernatural Skill', '@@PASSIVE: Recognizing the convenant of natural and the supernatural, you can communicate with the elemental demiurges of the islands to help you.\n\n@@PASSIVE: Add +1 Mark to Supernatural\nAdd 1 Mark to your Supernatural Skill.\n\n@@SECTION:\nIf you re-train this Gift, you also lose the extra Mark.\n\n@@SECTION: Summon Taniwha\n\n@@FLAVOUR:\nYou can summon a spirit to help you.\n\n@@SECTION: As a special \"summon\" action, tap this gift, and then roll your Will, Supernatural, and bonus d12 from Mystic: Tawas. Each 4 or better that you roll is one success.\nYou can then choose one and only one result from the table below, one that you have enough successes to obtain. (If you scored 2 successes, you can choose any 2, 1, or none result... and not any result of 3 or higher.)\n\n@@SECTION: How soon you can recharge the gift depends on the outcome of your summoning.\nIf you failed to summon anything, you can recharge at the start of the next scene (about five minutes).\nIf you summoned a taniwha to answer questions, you may recharge at the next respite.\nIf you summoned a taniwha to help you in a non-violent manner (move things, deal with environmental hazards, etc.), you may recharge at the start of the next chapter.\nIf you summoned a taniwha to help you for violence, the outcome varies on the result. If your taniwha didn\'t suffer anything worse than Hurt or Afraid, you may recharge at the start of the next chapter. If your taniwha was Injured or worse, you will need to make some sort of sacrifice. The worse the taniwha suffered, and the greater its power was, the greater the sacrifice will be. If the taniwha was destroyed, you may not be able to make a large enough sacrifice to recharge this gift.\n\n@@FLAVOUR:\nThe summoned taniwha appears Near you (within 4m), in an appropriate space. Whenever you recharge this gift, for any reason, your summoned taniwha will go away.\n\n@@SECTION: Taniwhas are not puppets - they are living, willful creatures with their own agendas. They will serve to the best of their ability, but abuse of this magic may eventually result in the supernatural world closing their ears to the call, making this gift useless.\n\n@@SECTION: Will, Supernatural, Mystic\'s d12 ≥4  Choose one result\nNo successes  No effect, but your gift of \"Summon Taniwha\" will recharge at the start of the next scene.\n1 success or more Summon a random taniwha and ask it three questions, which it will answer to the best of its ability.\n2 successes or more   Summon a taniwha of random type (Te Ahi, Te Hau, Te Wai, Te Whenua) which will help you and will fight for you, for one scene. If the taniwha is unharmed, you can recharge at the next respite (see below).\n3 successes or more   Summon a taniwha of a type that you choose (Te Ahi, Te Hau, Te Wai, Te Whenua) which will help you and will fight for you, for one scene. See below for how to recharge.\n4 successes or more   Summon a taniwha Pontianak of random type (Te Ahi, Te Hau, Te Wai, Te Whenua) which will fight for you (and that\'s all it will do) for one scene. See below for how to recharge.\n5 successes or more   Summon a taniwha spellcaster of a type that you choose (Te Ahi, Te Hau, Te Wai, Te Whenua) which will help you and will fight for you for one scene. See below for how to recharge.\n6 successes or more   Summon a taniwha Mangō of random type (Te Ahi, Te Hau, Te Wai, Te Whenua) which will fight for you (and that\'s all it will do) for one scene. See below for how to recharge.\n7 successes or more   Summon a taniwha Tuakana of random type (Te Ahi, Te Hau, Te Wai, Te Whenua) which will give you audience and possibly defend you. See below for how to recharge.', 1, 922, '', 12, 'summon-taniwha', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(350, 1, 350, 'Sunburst', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Action \"ready Sunburst\" Exhaust this Gift, then use the ready action to draw forth a \"Sunburst\" weapon', '@@FLAVOUR:\nA white-hot glow, this spell is a very brief explosion, impossible to describe, since to see it is to be blinded by it.\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Sunburst\"\nExhaust this Gift, then use the ready action to draw forth a \"Sunburst\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 292, '', 12, 'sunburst', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(351, 1, 351, 'Swerven', 0, 0, 5, 'Passive; Exhaust; The Cognoscenti may be separated by distance, but they can communicate to each other by meeting in their dreams', '@@FLAVOUR:\nThe Cognoscenti may be separated by distance, but they can communicate to each other by meeting in their dreams.\n\n@@TRAPPINGS: Cognoscente\'s Trappings: Any Green & Purple Apprentice\n\n@@REQUIRES: Inkling\n\n@@REQUIRES: Insider with the Cognoscenti\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Thought Reading\n\n@@REFRESH: X (Special)\n\n@@STUNT: \"Invade someone\'s dream\"\nYou must have a synecdoche link to the target, and the target must be asleep. If neither of these things are true, then you exhaust the spell and nothing happens, except that you are sent Reeling.\nIf the spell does work, then you fall Unconscious. Your consciousness invades the target\'s dreams.\nThe dream-scape is a strange place, where you may be attacked by all sorts of shades. In the dream, you appear with all of your Cognoscente\'s Trappings, and that\'s all.\nThe dream lasts for a few hours - even though people sleep all night, they drift in and out of dream-sleep. If you are rendered Dying or Dead in the dream, then you wake up, Afraid, and you cannot refresh this Gift until the next Respite. If you are Overkilled, then you become Terrified (until cured), and you cannot Refresh this Gift until the next Chapter. Otherwise, the Gift refreshes when the dream ends.', 5, 303, '', NULL, 'swerven', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(352, 1, 352, 'Tandem Replay', 0, 0, 1, 'Passive; If your attack, counter-attack, or parry fails, but you have two weapons ready, you may try again with your second weapon', '@@REQUIRES: Ambidexterity\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: your attack, counter-attack or parry fails, while you carry two weapons\nIf your attack, counter-attack, or parry fails, but you have two weapons ready, you may try again with your second weapon. Declare your second weapon to be used; then both combatants re-roll their attack vs. defense. The second result stands.\nIf you win the second contest, remember that you\'re using your second weapon, not the first.', 5, 71, 'your attack, counter-attack or parry fails, while you carry two weapons', 1, 'tandem-replay', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(353, 1, 353, 'Tandem Strike', 0, 0, 1, 'Action; Exhaust; \"melee attack: tandem strike\" You may make two melee attacks: first with one weapon, then the other', '@@REQUIRES: Ambidexterity\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"melee attack: tandem strike\"\nYou may make two melee attacks: first with one weapon, then the other.\nFirst, exhaust this Gift. Then declare a target for your first weapon, and play out that attack normally. Then declare a target for your second weapon, and play out that attack. (Yes, you could choose the same target both times.) Note that the target defends normally - if the target can still Counter-Attack, they may Counter-Attack.\nIf you attack the same target twice, the target uses one defense roll against both of your attacks. If you attack the same target twice, and even one of your attacks fails to beat the target\'s Counter dice, then you were hit with a Counter-Attack.\nIf you attack two different targets, each target defends normally. Yes, attacking two targets could put you at risk for two counter-attacks.\nBoth attacks happen simultaneously. Even if the first attack sends you Reeling, Unconscious, or worse, both attacks are played out. Likewise, even if your first attack sends the target Reeling, a second attack doesn\'t take advantage - it\'s happening at the same time as the first attack.', 5, 71, '', 5, 'tandem-strike', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(354, 1, 354, 'The Band Plays On', 0, 0, NULL, 'Passive; The best Anatolian hospitals frequently hire musicians to help with the healing or therapeutic processes for exactly this reason', '@@PASSIVE: Play, play, play the soundtrack of the universe. The best Anatolian hospitals frequently hire musicians to help with the healing or therapeutic processes for exactly this reason.\n\n@@SECTION: Inspirational Music\n\n@@FLAVOUR:\nYou can help someone just by playing music appropriate to their actions. Playing music is a stunt, every turn, and it\'s a very loud noise.\n\n@@SECTION: While playing the music, all friends within Medium range enjoy the following advantages:\n\n@@SECTION: All friends who hear your music gain a d8 assist bonus to an appropriate task.\n\n@@SECTION: All allies in combat are flanking their opponents (and may claim their tactics bonus).', 3, 747, '', 22, 'the-band-plays-on', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(355, 1, 355, 'The Cry of a Hundred Souls', 0, 0, 2, 'Action; Action \"attack: cry of a hundred souls\" As an Action, you can howl a loud noise that terrifies lesser beings', '@@REQUIRES: Species Trait of d8 or better Howling\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"attack: cry of a hundred souls\"\nAs an Action, you can howl a loud noise that terrifies lesser beings. Roll your Species & Presence dice, and a bonus d12 (from the Howling Gift).\nAll within Short Range of you must test their Species & Presence vs. your roll or become Afraid.\nAll within Medium Range of you must test their Species & Presence with a bonus d12 vs. your roll or become Afraid.', 5, 318, '', 20, 'the-cry-of-a-hundred-souls', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(356, 1, 356, 'The Dark Bargain', 0, 0, 1, 'Passive', '@@REQUIRES: Any two Gifts which have both the \"Unholy\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Necromancy\n\n@@TRAPPINGS: Necromancer\'s Trappings\n\n@@PASSIVE: X (Battle) Trigger: using any Magic Battle Gift or Respite Gift\nDeclare you will invoke the Dark Bargain and Exhaust this Gift. Then declare any other Magical Battle Gift or Magical Respite Gift. Follow the rules for the appropriate Gift.\nAfter using the Magical Gift, roll 6d6 vs. 5. If you are successful, the Gift that you declared is not Exhausted.', 5, 315, '', 12, 'the-dark-bargain', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(357, 1, 357, 'The Rage Within', 0, 0, NULL, 'Passive', '@@REQUIRES: Species Trait of d8 or better Frenzy\n\n@@TRIGGER: lose an attack vs. defense contest\nWhenever you lose an attack vs. defense contest, immediately refresh your \"Frenzy\" Gift.', 5, 321, 'lose an attack vs. defense contest', 9, 'the-rage-within', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(358, 1, 358, 'The Tempest', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; This spell is forbidden in populated areas, as it has been known to level buildings with its hurricane force', '@@FLAVOUR:\nThis spell is forbidden in populated areas, as it has been known to level buildings with its hurricane force.\n\n@@REQUIRES: Any two Gifts which have both the \"Air\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready The Tempest\"\nExhaust this Gift, then use the ready action to draw forth a \"The Tempest\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 288, '', 12, 'the-tempest', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(359, 1, 359, 'Theurgic Clout', 1, 0, 3, 'Passive; Exhaust; The greatest wizards can increase the power of a spell, even after it has been cast', '@@FLAVOUR:\nThe greatest wizards can increase the power of a spell, even after it has been cast.\n\n@@TRIGGER: Casting a Theurgic Spell\n\n@@REQUIRES: Mystic: Thaumaturgy\n\n@@REQUIRES: Add +1 Mark to Supernatural\n\n@@REQUIRES: Add 1 Mark to your Supernatural Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@TRIGGER: Casting a Theurgic Spell\nExhaust this Gift after casting a spell of the Theurgic nature to claim a bonus 2d8 with your casting dice.\nMultiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 311, 'Casting a Theurgic Spell', NULL, 'theurgic-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(360, 1, 360, 'Thought Reading', 0, 0, 2, 'Passive; Until the end of the Scene; If you Succeed, you may read the mind of the lowest-rolling failure in the group', '@@REQUIRES: Green & Purple Apprentice\n\n@@REFRESH: X (Respite)\n\n@@STUNT: \"Read a group of minds\"\nYour attack dice are your Mind & Inquiry vs. a group\'s Mind, Deceit, and Presence.\nIf you Succeed, you may read the mind of the lowest-rolling failure in the group. How much you read depends on how many successes you get.\nOne success will get you surface thought - you know what the target is thinking, if they mean you harm or help, and if they are lying to you. This effect lasts until the end of the Scene (that is, for no more than five minutes).\nTwo successes will let you read memories. You know the truthfulness of anything the target says for the next five minutes, and you have a deep understanding of who the target is and where they came from. The game host will tell you all Influence Gifts, all Personality Gifts, and all Careers that the target possesses. In a single moment, you gain an hour\'s worth of truthful interrogation from the target. The Game Host may choose to move the game along for now, but should you have more questions, the Host will let you know what your character learned.\nThree successes will let you find deep, buried secrets. In addition to the information above, you will also learn of any Major Gifts the target has. Anything the target knows or experienced is available to you.\nIf any of your targets Overwhelmingly Succeed against your Thought-Reading dice, those targets are aware of your direction and distance, whether they have any Supernatural skill or not.', 5, 300, '', 12, 'thought-reading', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(361, 1, 361, 'Threatening Fighter', 0, 0, 1, 'Passive; Exhaust; If a combatant that you threaten declares an Attack action against someone who is not you, you may declare that you will interrupt that fighter', '@@REQUIRES: Counter-Tactics\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: threatened foe attacks a different target\nIf a combatant that you threaten declares an Attack action against someone who is not you, you may declare that you will interrupt that fighter. Exhaust this Gift, then play out an attack with your threatening weapon.\nSee the \"Combat\" chapter for more details on interrupting and threatening.', 5, 72, 'threatened foe attacks a different target', NULL, 'threatening-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(362, 1, 362, 'Thunderclap', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; You call upon the elemental forces of nature to manifest a sound made solid, a strobing light that will explode at your command Action \"ready Thunderclap\"…', '@@FLAVOUR:\nYou call upon the elemental forces of nature to manifest a sound made solid, a strobing light that will explode at your command\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Thunderclap\"\nExhaust this Gift, then use the ready action to draw forth a \"Thunderclap\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 286, '', 12, 'thunderclap', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(363, 1, 363, 'Toughness', 1, 0, 2, 'Passive; After being hit with an attack and rolling your Soak, you may declare the damage to be Weak - roll your Soak dice again, and each success reduces the damage…', '@@REFRESH: X (Respite)\n\n@@TRIGGER: suffering Damage\nAfter being hit with an attack and rolling your Soak, you may declare the damage to be Weak - roll your Soak dice again, and each success reduces the damage further. If the damage was already Weak, there is no effect.\nMultiple\nYou can buy this Gift multiple times. However, you can only use Toughness once per damage effect, as each effect can only become Weak once.', 5, 64, 'suffering Damage', 21, 'toughness', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(364, 1, 364, 'Tradewinds Navigation', 0, 0, NULL, 'Passive', '@@REQUIRES: Literacy\n\n@@REQUIRES: Bonus d12 to Plot Long Sea Voyages\n\n@@REQUIRES: When plotting a navigation course for a sailing vessel, you may claim a bonus d12.', 5, 76, '', 23, 'tradewinds-navigation', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(365, 1, 365, 'Troop Leader', 0, 0, NULL, 'Passive', '@@REQUIRES: True Leader\n\n@@ACTION: Action \"rally a Group of targets to negate Afraid\"\nYou may rally a mass of troops at once! ... But only to remove the Afraid condition.\nFirst, , declare a Group of targets. Then, you roll your Will & Leadership, just like any rally.\nEach ally resists with a 3 ... plus any dice for Range (d8 for Short, d12 for Medium, etc.) The Gift of Commanding Leader may reduce this range.\nTies do not count, only successful overcoming of the target\'s resistance will result in a successful rally.\nIf you succeed against an ally, you may negate the Afraid condition on that ally.\nThe maximum number of targets in your Group is your score. For example, if your highest die came up 7, you may only rally 7 targets in your Group. Closer targets rally first, but otherwise you may choose.\nNote that unlike a regular rally, a troop rally can only remove the Afraid condition. A troop rally cannot remove Reeling, nor can it benefit from other rally- boosting Gifts, such as \"True Leader\".\nThe Troop Leader Gift is excellent insurance against the mass fear caused by an \"Overkill\" effect', 5, 82, '', 5, 'troop-leader', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(366, 1, 366, 'Unholy Clout', 1, 0, NULL, 'Passive', '@@REQUIRES: Mystic: Necromancy\n\n@@REQUIRES: Add +1 Mark to Deceit\n\n@@REQUIRES: Add 1 Mark to your Deceit Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting an Unholy Spell\nExhaust this Gift after casting a spell of the Unholy nature to claim a bonus d12 & d6 with your casting dice.', 5, 315, 'Casting an Unholy Spell', NULL, 'unholy-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(367, 1, 367, 'Unmaking', 0, 0, 2, 'Action; Exhaust; Declare a Ranged Attack against a target within Medium Range', '@@REQUIRES: Literacy\n\n@@TRAPPINGS: Necromancer\'s Trappings\n\n@@REQUIRES: Apprentice Necromancy\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"Aim to upgrade Horror to Unmaking\"\nTo use this ability, you must have a \"Horror\" Magic weapon at the ready, and you must take the \"Aim\" action at a target.\nExhaust this Gift. Your \"Horror\" weapon becomes a \"Unmaking\".\nDeclare a Ranged Attack against a target within Medium Range. Roll your Will, Supernatural & 3d6. The target resists with Body, Speed, Mind, Will, & Species.\nIf the target resists or defends, nothing happens.\nIf you succeed, note which die of the target rolled the lowest:\nIf Body rolled the lowest, the target falls Asleep.   If Speed rolled the lowest, the target become\nImmobilized.\nIf Mind rolled the lowest, the target becomes Confused.\nIf Will rolled the lowest, the target becomes Afraid.   If Species rolled the lowest, the target becomes\nBerserk.\nIf two dice tied for lowest, the target suffers both effects.', 5, 315, '', 12, 'unmaking', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(368, 1, 368, 'Unshakable Fighter', 0, 0, NULL, 'Passive; Immune to Overkill\'s fear You are immune to the fear effect caused by Overkill', '@@PASSIVE: Immune to Overkill\'s fear\nYou are immune to the fear effect caused by Overkill. (Combatants without this Gift become Afraid when a nearby ally is Overkilled.)', 5, 56, '', 14, 'unshakable-fighter', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(369, 1, 369, 'Upheaval', 0, 0, 2, 'Action; Exhaust; Until the end of the Scene; Foes grappled by the spell must break free, using a \"Break Free\" attack against your Body & Digging dice ... even if you are incapacitated', '@@SECTION: After you toss this amber glow to the center point, there is a pause\n... just before the earth rips open and your hapless victims fall inside. Sadly, the pit is only a dozen hands deep.\n\n@@REQUIRES: Any two Gifts which have both the \"Earth\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Elemental Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Action \"ready Upheaval\"\nExhaust this Gift, then use the ready action to draw forth a \"Upheaval\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).\nMake a note of where the center of the Upheaval landed, and what its Explosion range was. Everything within that range is now bad footing.\nFoes grappled by the spell must break free, using a \"Break Free\" attack against your Body & Digging dice\n... even if you are incapacitated. (Your dice represent how trapped they became.)', 5, 291, '', 12, 'upheaval', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(370, 1, 370, 'Vermin of the State', 0, 0, 3, 'Passive; Exhaust; Re-roll with bonus 3d6 You may call upon infernal powers to grant you bonuses to one roll', '@@PASSIVE: Not all of the Five Vermin have this Gift... but the ones that do have some infernal advantage.\n\n@@SECTION: Unholy Aura\n\n@@FLAVOUR:\nYou are always Unholy. You may not use Holy effects. You take Slaying Damage from Holy attacks.\n\n@@REFRESH: X (Chapter)\n\n@@SECTION: Re-roll with bonus 3d6\n\n@@SECTION: You may call upon infernal powers to grant you bonuses to one roll. After rolling, declare you will exhaust this Gift to re-roll your dice; you must claim a bonus 3d6, and your roll becomes Unholy (with all risks). The second result stands, even if it\'s worse.', 4, 438, '', 15, 'vermin-of-the-state', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(371, 1, 371, 'Vessel of Unlife', 0, 0, 3, 'Passive', '@@REQUIRES: Mystic: Necromancy\n\n@@TRAPPINGS: Necromancer\'s Trappings\n\n@@REQUIRES: Animation\n\n@@REQUIRES: Mark of Nine\n\n@@REQUIRES: Speak with Dead\n\n@@PASSIVE: X (Chapter) Stunt \"Create Restless Dead\"\nYou must have a dead body, that must not have been Overkilled. Roll 6d6 vs. 5. If you are successful, the corpse becomes an undead monster.\nIf the corpse is fresh, Body is the same that the character had in lfe. If it\'s a skeleton, drop the Body one die size (to a minimum of d4) but raise the Speed die (to a maximum of d12).\nThe body has the same Mind & Will that it had in life. The Species Trait is gone. Replace it with an Undead\nTrait, which applies to Brawling, Observation, and Supernatural.\nSome Gifts may stay, others may have to be re- trained. For example, being dead may make a corpse lose many social gifts such as Nobility and Insider.\nThe Undead spends its first action to stand up. Then, immediately roll its Body, its Speed, and 3d6 vs. your Mind & Will. If it wins, it becomes angry - give it the Berserk status. Otherwise, it becomes restless.\nCharacter Development\nYou cannot retrain this Gift until the Vessel of Unlife you created with it has been destroy', 5, 316, '', 12, 'vessel-of-unlife', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(372, 1, 372, 'Watchful Leader', 0, 0, 1, 'Passive; Exhaust; If anyone attacks that ally before your next turn, you may interrupt to launch an Attack', '@@REQUIRES: True Leader\n\n@@REQUIRES: +1 Mark with Observation\n\n@@REQUIRES: You have an extra Mark with Observation skill. If you retrain this Gift, you lose this extra Mark.\n\n@@REFRESH: X (Battle)\n\n@@TRIGGER: successful Rally\nAfter any successful Rally, exhaust this Gift, then declare a target you just Rallied. If anyone attacks that ally before your next turn, you may interrupt to launch an Attack.\nYou may use any attack that you have ready - Melee Attack, Ranged Attack, Thrown Attack, Special Attack, etc. - as long as the attacker of your declared target is within range.\nYou must be able to interrupt with an attack. You cannot be Reeling, Afraid, Confused, Enraged, or be suffering from any other condition that makes you lose competence or confidence.\nWhen your turn comes back, your watch ends. You will have to refresh this Gift, then successfully Rally a target, to use it again.', 5, 82, 'successful Rally', NULL, 'watchful-leader', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(373, 1, 373, 'Water Clout', 1, 0, NULL, 'Passive', '@@REQUIRES: Mystic: Elementalism\n\n@@REQUIRES: Add +1 Mark to Swimming\n\n@@REQUIRES: Add 1 Mark to your Swimming Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@TRIGGER: Casting a Water Spell\nExhaust this Gift after casting a spell of the Water nature to claim a bonus 2d8 with your casting dice.\nMultiple\nYou may buy this Gift multiple times. Each new Gift gives you +1 Mark and a new Exhaustion, but you may only use one Clout per roll.', 5, 296, 'Casting a Water Spell', 12, 'water-clout', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(374, 1, 374, 'Water Mnemonic', 0, 0, 3, 'Passive; Extra action: \"refresh all Water Battle Gifts and Water Respite Gifts\" On your turn, as an extra action, you may put your off-hand upon your magical talisman,…', '@@FLAVOUR:\nYour meditative training allows you to call upon reserves of power.\n\n@@REQUIRES: Any two Gifts which have both the \"Water\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@TRAPPINGS: Any magical Talisman from any Trappings Gift\n\n@@REQUIRES: Add +1 Mark to Swimming\n\n@@REQUIRES: Add 1 Mark to your Swimming Skill.\n\n@@REQUIRES: If you re-train this Gift, you also lose the extra Mark.\n\n@@REFRESH: X (Chapter)\n\n@@ACTION: Extra action \"refresh all Water Battle Gifts and Water Respite Gifts\"\nOn your turn, as an extra action, you may put your off-hand upon your magical talisman, and in a loud voice, you declare your command over all Water. By doing so, you immediately refresh all exhausted gifts that have both the \"Water\" descriptor and either the \"Battle\" or the \"Respite\" descriptor. Other Gifts are not refreshed.\nIf you do not have a magical talisman to brandish forth, you cannot use this ability.', 5, 296, '', 12, 'water-mnemonic', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(375, 1, 375, 'Wealth', 1, 0, 4, 'Passive; You may invoke your wealthy status for special favors ... even after failing a roll!', '@@REQUIRES: An appropriate background and career.\n\n@@REQUIRES: Better Money and Material Possessions\n\n@@REQUIRES: You begin the game with two Expensive items.\n\n@@REQUIRES: You are rich. When gossiping about the upper class, when negotiating for favors often granted to the wealthy, or when asserting your affluent presence, you may claim a bonus d12.\n\n@@REFRESH: X (Influence)\n\n@@FLAVOUR:\nYou may invoke your wealthy status for special favors ... even after failing a roll! Refer to the Influence rules for more details.\nMultiple\nSubject to the discretion of the Game Host, you can take this Gift multiple times, to represent more fabulous wealth.', 5, 60, '', 22, 'wealth', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(376, 1, 376, 'Whips of Flame', 0, 0, 1, 'Action; Exhaust; Until the end of the Scene; Action \"ready Whips of Flame\" Exhaust this Gift, then use the ready action to draw forth a \"Whips of Flame\" weapon', '@@FLAVOUR:\nA flexing trail of fire hangs from your fingertips. At your comand the whip extends several paces and smites your enemies.\n\n@@REQUIRES: Any two Gifts which have both the \"Fire\" and \"Journeyman\" descriptors\n\n@@REQUIRES: Mystic: Elementalism\n\n@@REFRESH: X (Battle)\n\n@@ACTION: Action \"ready Whips of Flame\"\nExhaust this Gift, then use the ready action to draw forth a \"Whips of Flame\" weapon. The spell remains in your hand, your rod, or your wand until you cast it forth (with the Attack action), until you drop it (as a free action), or until the end of the Scene (five minutes).', 5, 294, '', 12, 'whips-of-flame', '2026-03-22 10:39:00', '2026-03-22 10:39:00');
INSERT INTO `DcVnchxg4_customtables_table_gifts` (`id`, `published`, `ct_id`, `ct_gifts_name`, `ct_gifts_allows_multiple`, `ct_gifts_manifold`, `ct_gifts_refresh`, `ct_gifts_effect`, `ct_gifts_effect_description`, `ct_book_id`, `ct_pg_no`, `ct_gift_trigger`, `ct_gift_class`, `ct_slug`, `created_at`, `updated_at`) VALUES
(377, 1, 377, 'Wilding Camouflage', 0, 0, NULL, 'Passive; You get a d12 to conceal yourself from sight in natural surroundings or against any surface where your color change would allow you to blend in', '@@FLAVOUR:\nYou can change the pigmentation and texture of your skin.\n\n@@STUNT: change your pelt\n\n@@SECTION: As a stunt, you can change the surface texture and color of your skin. Even complex patterns are possible, as long as the pattern is somewhat regular-most things less complicated than paisley. You get a d12 to conceal yourself from sight in natural surroundings or against any surface where your color change would allow you to blend in.', 3, 750, '', 2, 'wilding-camouflage', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(378, 1, 378, 'Wrestling with Angels', 0, 0, 5, 'Passive; Exhaust; You can inflict Weak damage to them with melee or ranged weapons, and full damage with unarmed attacks and natural weapons', '@@FLAVOUR:\nThe Light\'s clarity in your form and essence forces spirits to take notice of you.\n\n@@REFRESH: X (Special)\n\n@@TRIGGER: benefiting from magic\n\n@@SECTION:\nIf you receive any direct personal benefit from magic, exhaust this Gift for 24 hours. If your friend heals you with White Magic, it counts; if your friend lightning- bolts the bad guy who was about to kick your ass, it doesn\'t. You probably don\'t want your enemies to find out about this gift.\n\n@@SECTION:\nWhen unexhausted, benefits to deal with the immaterial\n\n@@FLAVOUR:\nYou can speak to, and understand the speech of, spirits such as elementals and shades. You can inflict Weak damage to them with melee or ranged weapons, and full damage with unarmed attacks and natural weapons.', 3, 749, 'benefiting from magic', 12, 'wrestling-with-angels', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(379, 1, 379, 'Xenomancy', 0, 0, 2, 'Passive; Exhaust; You can\'t recover it until the next Respite.', '@@PASSIVE: How can you know how someone else thinks if you can\'t see what they see? This spell allows a Green & Purple Wizard to inhabit the perceptions of someone else.\n\n@@REQUIRES: Green & Purple Apprentice\n\n@@REQUIRES: Literacy\n\n@@REQUIRES: Mystic: Cognoscente Magic\n\n@@REQUIRES: Inkling\n\n@@REFRESH: X (Respite)\n\n@@ACTION: Long action \"stunt: labor of remote viewing\"\nThis spell requires that you have synecdoche with the target.\nRoll your Mind & Will vs. the target\'s Mind & Will. This is a synecdoche spell, so distance and line of sight don\'t matter.\nIf you Tie or better, you can perceive what the target perceives. The duration is based on how well you rolled: for a Tie, about six seconds (one r und); for Success, about five minutes (one scene); for Overwhelming Success, indefinitely (but see below).\nThe spell also ends if you stop laboring to continue it, or if the target falls asleep.\nYou sense everything that the target does - sight, sound, smell, taste, temperature, pain, etc.\nIf you Fail, your spell doesn\'t work, and you must Exhaust this Gift. You can\'t recover it until the next Respite.. If you Overwhelmingly Fail or worse, not only must you Exhaust the Gift, but the target becomes aware of what you perceive for the next minute.', 5, 303, '', 12, 'xenomancy', '2026-03-22 10:39:00', '2026-03-22 10:39:00'),
(380, 1, 380, 'Archer\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS:  \na composite bow \nsix spare bow strings\n12 barbed arrows\n24 standard arrows \na quiver \narchery gloves \na shortsword\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 5, 60, '', 25, 'archers-trappings', '2026-03-22 10:39:00', '2026-03-29 09:13:22'),
(381, 1, 381, 'Dukun\'s Trappings', 0, 0, 5, 'TRAPPINGS: Start the Game with a List of Special Equipment.', '@@SECTION: Belongings\nYou begin the game with:\n\n@@TRAPPINGS: \none Pesisir Robe \none Cassia Rod \none Greenstone Wand \none Talisman: an Alum Pendant\n\n@@REFRESH: X (Special)\n\n@@SECTION: Action \"replace your missing trappings\"\nIf you are parted from your items, ask the Game Host for a plot twist to return or to replace them.\nOnce exhausted, you cannot recover this Gift until the next game session', 1, 918, '', 25, 'dukuns-trappings', '2026-03-22 10:39:00', '2026-03-29 10:39:04'),
